// ---------------------------------------------------------------------------
{
  const ok = { result: 'ok', nodeId: 'n1' };
  const out = decorateOperatorHint(ok);
  assert(out.operator_hint === undefined, 'T-445-B: success envelope must NOT gain operator_hint');
}

