// ---------------------------------------------------------------------------
// T-446-E: --summary mode — subprocess test (real CLI invocation in $TMPDIR)
//   Runs adaptive-node.js orient --project nonexistent-zyx --json --summary
//   via a temp project dir in $TMPDIR. Asserts:
//     (a) stdout is exactly ONE line starting with "summary: "
//     (b) .cache/orient-envelope.json is written (full envelope cache)
// ---------------------------------------------------------------------------
{
  const { execFileSync } = require('child_process');
  const ADAPTIVE_NODE = path.join(__dirname, 'kaola-workflow-adaptive-node.js');

  // Stand up a minimal git repo + project dir in TMPDIR.
  const tmpRoot446e = fs.mkdtempSync(path.join(os.tmpdir(), 'kw-summary-'));
  try {
    const g = (args) => {
      try {
        execFileSync('git', ['-C', tmpRoot446e, ...args], { encoding: 'utf8', stdio: ['ignore', 'ignore', 'ignore'] });
      } catch (_) {}
    };
    g(['init']);
    g(['config', 'user.email', 'kw@test']);
    g(['config', 'user.name', 'kw']);
    g(['config', 'commit.gpgsign', 'false']);
    // No project dir → orient will refuse with plan_missing.

    let stdout446e = '';
    try {
      stdout446e = execFileSync(process.execPath, [
        ADAPTIVE_NODE, 'orient', '--project', 'nonexistent-zyx', '--json', '--summary',
      ], { cwd: tmpRoot446e, encoding: 'utf8' });
    } catch (err) {
      stdout446e = String(err.stdout || '');
    }

    const lines446e = stdout446e.split('\n').filter(l => l.length > 0);
    assert(lines446e.length === 1, 'T-446-E: --summary produces exactly 1 output line, got ' + lines446e.length + ': ' + JSON.stringify(lines446e));
    assert(lines446e[0].startsWith('summary: '), 'T-446-E: the single line starts with "summary: ", got: ' + lines446e[0]);

    // .cache/ for the project: cacheDir = <root>/kaola-workflow/nonexistent-zyx/.cache
    const projCacheDir446e = path.join(tmpRoot446e, 'kaola-workflow', 'nonexistent-zyx', '.cache');
    const envelopePath446e = path.join(projCacheDir446e, 'orient-envelope.json');
    assert(fs.existsSync(envelopePath446e), 'T-446-E: orient-envelope.json must be written to .cache/');
    if (fs.existsSync(envelopePath446e)) {
      let env446e = {};
      try { env446e = JSON.parse(fs.readFileSync(envelopePath446e, 'utf8')); } catch (_) {}
      assert(typeof env446e.result === 'string', 'T-446-E: cached envelope has result field');
    }
  } finally {
    try { fs.rmSync(tmpRoot446e, { recursive: true, force: true }); } catch (_) {}
  }
}

// ---------------------------------------------------------------------------
// T-446-F: route-findings subprocess — recognized subcommand (real CLI) (#446)
//   Runs adaptive-node.js route-findings --project test-project --node-id review --json
//   against a TMPDIR project. With an evidence file present, it should return ok
//   with the findings array. With no evidence file, it refuses evidence_absent
//   (NOT unknown subcommand — proving route-findings is a recognized subcommand).
// ---------------------------------------------------------------------------
{
  const { execFileSync } = require('child_process');
  const ADAPTIVE_NODE = path.join(__dirname, 'kaola-workflow-adaptive-node.js');

  const tmpRoot446f = fs.mkdtempSync(path.join(os.tmpdir(), 'kw-route-'));
  try {
    const g = (args) => {
      try {
        execFileSync('git', ['-C', tmpRoot446f, ...args], { encoding: 'utf8', stdio: ['ignore', 'ignore', 'ignore'] });
      } catch (_) {}
    };
    g(['init']);
    g(['config', 'user.email', 'kw@test']);
    g(['config', 'user.name', 'kw']);
    g(['config', 'commit.gpgsign', 'false']);

    // Create a minimal project structure.
    const projDir446f = path.join(tmpRoot446f, 'kaola-workflow', 'test-project-446f');
    const cacheDir446f = path.join(projDir446f, '.cache');
    fs.mkdirSync(cacheDir446f, { recursive: true });

    // Write a minimal plan.
    fs.writeFileSync(path.join(projDir446f, 'workflow-plan.md'), makePlan([
      '| impl | in_progress | |',
      '| review | pending | |',
      '| finalize | pending | |',
    ]));
    fs.writeFileSync(path.join(projDir446f, 'workflow-state.md'), makeState());

    // Write evidence for the review node.
    fs.writeFileSync(path.join(cacheDir446f, 'review.md'), [
      'evidence-binding: review abc456',
      '',
      'finding: F1 — scripts/other.js — wrong logic',
      '',
      'verdict: pass',
      'findings_blocking: 0',
    ].join('\n') + '\n');

    let out446f = '';
    try {
      out446f = execFileSync(process.execPath, [
        ADAPTIVE_NODE, 'route-findings', '--project', 'test-project-446f', '--node-id', 'review', '--json',
      ], { cwd: tmpRoot446f, encoding: 'utf8' });
    } catch (err) {
      out446f = String(err.stdout || '');
    }

    let parsed446f = {};
    try { parsed446f = JSON.parse(out446f.trim().split('\n').pop()); } catch (_) {}

    // Key assertion: must NOT be "unknown subcommand".
    assert(
      !(parsed446f.errors && parsed446f.errors.join('').includes('unknown subcommand')),
      'T-446-F: route-findings is a recognized subcommand (must not return unknown subcommand)'
    );
    // It found the evidence → ok with findings array.
    assert(parsed446f.result === 'ok', 'T-446-F: ok result when evidence present, got ' + parsed446f.result);
    assert(Array.isArray(parsed446f.findings), 'T-446-F: findings array returned');
    assert(parsed446f.count === 1, 'T-446-F: 1 finding parsed, got ' + parsed446f.count);

    // findings-route.json must be written.
    const routePath446f = path.join(cacheDir446f, 'findings-route.json');
    assert(fs.existsSync(routePath446f), 'T-446-F: .cache/findings-route.json written by route-findings');

  } finally {
    try { fs.rmSync(tmpRoot446f, { recursive: true, force: true }); } catch (_) {}
  }
}

// ---------------------------------------------------------------------------
// D451-DISPATCH-EFFORT: buildDispatch includes agent_type and dispatchEffort fields
// ---------------------------------------------------------------------------
{
  // Case 1: opus model → xhigh effort
  const opusNode = { id: 'n1-planner', role: 'code-reviewer', model: 'opus', declared_write_set: 'scripts/foo.js' };
  const opusCtx = {
    nonce: 'abc123def456',
    evidence_file: '.cache/n1-planner.md',
    required_tokens: ['evidence-binding', 'RED', 'GREEN'],
    working_dir: '/fake/worktree',
    forge_rider: null,
  };
  const dOpus = buildDispatch(opusNode, opusCtx);
  assert(dOpus.agent_type === 'code-reviewer', 'D451-DISPATCH-EFFORT: opus agent_type equals base role');
  assert(dOpus.codex_model === 'gpt-5.6-sol', 'D451-DISPATCH-EFFORT: opus codex_model is gpt-5.6-sol');
  assert(dOpus.codex_model_source === 'planner_model', 'D451-DISPATCH-EFFORT: opus codex_model_source is planner_model');
  assert(dOpus.codex_reasoning_effort === 'xhigh', 'D451-DISPATCH-EFFORT: opus codex_reasoning_effort is xhigh');
  assert(dOpus.codex_reasoning_effort_source === 'planner_model', 'D451-DISPATCH-EFFORT: opus codex_reasoning_effort_source is planner_model');
  assert(dOpus.codex_profile_mode === 'pinned' && dOpus.codex_profile_tier === 'reasoning'
    && dOpus.codex_profile_compatible === true,
    'D451-DISPATCH-EFFORT: reasoning reviewer uses the standalone pinned profile pair');
  assert(dOpus.codex_task_name === 'n1_planner_code_reviewer', 'D451-DISPATCH-EFFORT: opus dispatch carries task-name identity for per-spawn calls');

  // Case 2: sonnet model → profile-pinned Sol/medium
  const sonnetNode = { id: 'n2-impl', role: 'implementer', model: 'sonnet', declared_write_set: 'scripts/bar.js' };
  const sonnetCtx = {
    nonce: 'def456abc123',
    evidence_file: '.cache/n2-impl.md',
    required_tokens: ['evidence-binding'],
    working_dir: '/fake/worktree',
    forge_rider: null,
  };
  const dSonnet = buildDispatch(sonnetNode, sonnetCtx);
  assert(dSonnet.agent_type === 'implementer', 'D451-DISPATCH-EFFORT: sonnet agent_type equals base role');
  assert(dSonnet.codex_model === 'gpt-5.6-sol', 'D451-DISPATCH-EFFORT: sonnet codex_model is gpt-5.6-sol');
  assert(dSonnet.codex_model_source === 'planner_model', 'D451-DISPATCH-EFFORT: sonnet codex_model_source is planner_model');
  assert(dSonnet.codex_reasoning_effort === 'medium', 'D451-DISPATCH-EFFORT: sonnet codex_reasoning_effort is medium');
  assert(dSonnet.codex_reasoning_effort_source === 'planner_model', 'D451-DISPATCH-EFFORT: sonnet codex_reasoning_effort_source is planner_model');
  assert(dSonnet.codex_profile_mode === 'pinned' && dSonnet.codex_profile_tier === 'standard'
    && dSonnet.codex_profile_compatible === true,
    'D451-DISPATCH-EFFORT: standard implementer uses the pinned role profile');

  // Case 2b: a plan tier that conflicts with the role profile is surfaced fail-closed on the card.
  const dMismatch = buildDispatch({ ...sonnetNode, role: 'code-reviewer' }, sonnetCtx);
  assert(dMismatch.codex_profile_mode === 'pinned' && dMismatch.codex_profile_tier === 'reasoning'
    && dMismatch.codex_profile_compatible === false,
    'D451-DISPATCH-EFFORT: standard reviewer conflicts with its pinned reasoning profile');

  // Case 3: null helper input → unresolved role_default sentinel (plan-run refuses before spawn)
  const nullModelNode = { id: 'n3-review', role: 'code-reviewer', model: null, declared_write_set: '—' };
  const nullCtx = {
    nonce: 'xyz789',
    evidence_file: '.cache/n3-review.md',
    required_tokens: ['evidence-binding'],
    working_dir: '/fake/worktree',
    forge_rider: null,
  };
  const dNull = buildDispatch(nullModelNode, nullCtx);
  assert(dNull.agent_type === 'code-reviewer', 'D451-DISPATCH-EFFORT: null-model agent_type equals base role');
  assert(dNull.codex_model === null, 'D451-DISPATCH-EFFORT: null-model codex_model is null');
  assert(dNull.codex_model_source === 'role_default', 'D451-DISPATCH-EFFORT: null-model codex_model_source is role_default');
  assert(dNull.codex_reasoning_effort === null, 'D451-DISPATCH-EFFORT: null-model codex_reasoning_effort is null');
  assert(dNull.codex_reasoning_effort_source === 'role_default', 'D451-DISPATCH-EFFORT: null-model codex_reasoning_effort_source is role_default');
  assert(dNull.codex_profile_mode === 'pinned' && dNull.codex_profile_tier === 'reasoning'
    && dNull.codex_profile_compatible === false,
    'D451-DISPATCH-EFFORT: unresolved direct helper input is not profile-compatible');

  // #382-opencode: the opencode effort twin (dispatchEffortOpencode). No provider in ctx →
  // role_default (the agent's configured variant wins), so the cases above all carry null.
  assert(dOpus.opencode_variant === null && dOpus.opencode_variant_source === 'role_default',
    'D451-DISPATCH-EFFORT: opus (no provider) opencode_variant is null/role_default');
  assert(dSonnet.opencode_variant === null && dSonnet.opencode_variant_source === 'role_default',
    'D451-DISPATCH-EFFORT: sonnet (no provider) opencode_variant is null/role_default');
  // Case 4: opus + opencode provider → the provider's TOP effort variant (mapTier).
  const dOc = buildDispatch(opusNode, Object.assign({}, opusCtx, { opencode_provider: 'zhipuai-coding-plan' }));
  assert(dOc.opencode_variant === 'max' && dOc.opencode_variant_source === 'planner_model',
    'D451-DISPATCH-EFFORT: opus + zhipu provider → opencode_variant max (top), got ' + JSON.stringify(dOc.opencode_variant));
  // Case 5: sonnet + opencode provider → the provider's SECOND effort variant.
  const dOai = buildDispatch(sonnetNode, Object.assign({}, sonnetCtx, { opencode_provider: 'openai' }));
  assert(dOai.opencode_variant === 'high' && dOai.opencode_variant_source === 'planner_model',
    'D451-DISPATCH-EFFORT: sonnet + openai provider → opencode_variant high (second), got ' + JSON.stringify(dOai.opencode_variant));

  // #537 Surface 2: the runtime buildDispatch call is dispatchEffortOpencode(model, ctx.opencode_provider)
  // and NO caller ever populates ctx.opencode_provider — so a declared tier silently resolved to
  // role_default. The schema now PURE-resolves the active provider from KAOLA_OPENCODE_INHERIT_MODEL
  // (the established opencode inherited-model env, "provider/model" form) when no provider is passed,
  // so a declared tier reaches a CONCRETE effort variant. Backward-compat: env UNSET + no provider
  // stays null/role_default (cases 1-3 above remain valid; claude/codex are behavior-inert).

  // Case 6 (direct, opus): env-resolved provider → concrete TOP variant, source reflects resolution.
  const rOpusEnv = dispatchEffortOpencode('opus', null, { KAOLA_OPENCODE_INHERIT_MODEL: 'zhipuai-coding-plan/glm-5.2' });
  assert(rOpusEnv.opencode_variant === 'max',
    'D451-DISPATCH-EFFORT: opus + env-resolved zhipu provider → opencode_variant max, got ' + JSON.stringify(rOpusEnv.opencode_variant));
  assert(rOpusEnv.opencode_variant_source !== 'role_default',
    'D451-DISPATCH-EFFORT: opus + env-resolved provider source is NOT role_default, got ' + JSON.stringify(rOpusEnv.opencode_variant_source));

  // Case 7 (direct, sonnet): env-resolved provider → concrete SECOND variant.
  const rSonnetEnv = dispatchEffortOpencode('sonnet', null, { KAOLA_OPENCODE_INHERIT_MODEL: 'openai/gpt-5' });
  assert(rSonnetEnv.opencode_variant === 'high',
    'D451-DISPATCH-EFFORT: sonnet + env-resolved openai provider → opencode_variant high, got ' + JSON.stringify(rSonnetEnv.opencode_variant));
  assert(rSonnetEnv.opencode_variant_source !== 'role_default',
    'D451-DISPATCH-EFFORT: sonnet + env-resolved provider source is NOT role_default, got ' + JSON.stringify(rSonnetEnv.opencode_variant_source));

  // Case 8 (backward-compat): env UNSET + no provider → unchanged null/role_default.
  const rNone = dispatchEffortOpencode('opus', null, {});
  assert(rNone.opencode_variant === null && rNone.opencode_variant_source === 'role_default',
    'D451-DISPATCH-EFFORT: opus + unset env + no provider → null/role_default (backward-compat), got ' + JSON.stringify(rNone));

  // Case 9 (dispatch SURFACE): the runtime 2-arg buildDispatch call picks up the env-resolved
  // provider, so a declared tier surfaces a concrete variant in the dispatch envelope. Drives the
  // real process.env (the runtime read path) — saved/restored so the suite stays hermetic.
  const ENV_KEY = 'KAOLA_OPENCODE_INHERIT_MODEL';
  const savedEnv = process.env[ENV_KEY];
  try {
    process.env[ENV_KEY] = 'zhipuai-coding-plan/glm-5.2';
    const dEnv = buildDispatch(opusNode, opusCtx); // no opencode_provider in ctx — the real runtime shape
    assert(dEnv.opencode_variant === 'max',
      'D451-DISPATCH-EFFORT: buildDispatch opus (no ctx provider) + env-resolved zhipu → opencode_variant max, got ' + JSON.stringify(dEnv.opencode_variant));
    assert(dEnv.opencode_variant_source !== 'role_default',
      'D451-DISPATCH-EFFORT: buildDispatch opus env-resolved source is NOT role_default, got ' + JSON.stringify(dEnv.opencode_variant_source));
  } finally {
    if (savedEnv === undefined) delete process.env[ENV_KEY]; else process.env[ENV_KEY] = savedEnv;
  }
}

// ---------------------------------------------------------------------------
// TIER-RENAME (#610) + ENVELOPE-DISPLAY (#609): buildDispatch carries a runtime-native
// model_display alongside the raw tier, NEUTRAL tokens dispatch identically to their legacy
// aliases (back-compat), and an untiered node omits the display while carrying null Codex overrides.
// ---------------------------------------------------------------------------
{
  const ctx = { nonce: 'n', evidence_file: '.cache/x.md', required_tokens: ['evidence-binding'], working_dir: '/w', forge_rider: null };
  const mk = model => buildDispatch({ id: 'nX', role: 'code-reviewer', model, declared_write_set: 'scripts/x.js' }, ctx);

  // NEUTRAL reasoning tier: same effort as legacy opus + a native display object.
  const dR = mk('reasoning');
  assert(dR.codex_model === 'gpt-5.6-sol', 'TIER-RENAME: reasoning → gpt-5.6-sol model');
  assert(dR.codex_reasoning_effort === 'xhigh', 'TIER-RENAME: reasoning → xhigh effort');
  assert(dR.model === 'reasoning', 'TIER-RENAME: raw tier stays in the dispatch card');
  assert(dR.model_display && dR.model_display.claude === 'opus'
    && dR.model_display.codex === 'gpt-5.6-sol (xhigh reasoning effort)'
    && dR.model_display.opencode === 'top effort variant',
    'ENVELOPE-DISPLAY: reasoning model_display is runtime-native, got ' + JSON.stringify(dR.model_display));

  // NEUTRAL standard tier: same effort as legacy sonnet + a native display object.
  const dS = mk('standard');
  assert(dS.codex_model === 'gpt-5.6-sol', 'TIER-RENAME: standard → gpt-5.6-sol model');
  assert(dS.codex_reasoning_effort === 'medium', 'TIER-RENAME: standard → medium effort');
  assert(dS.model_display && dS.model_display.claude === 'sonnet'
    && dS.model_display.codex === 'gpt-5.6-sol (medium reasoning effort)'
    && dS.model_display.opencode === 'second effort variant',
    'ENVELOPE-DISPLAY: standard model_display is runtime-native, got ' + JSON.stringify(dS.model_display));
  assert(dR.codex_profile_compatible === true && dS.codex_profile_compatible === false,
    'CODEX-PROFILE: code-reviewer accepts reasoning and refuses a standard tier mismatch');

  // BACK-COMPAT: a legacy opus/sonnet cell (frozen plan) dispatches with the SAME effort AND the
  // SAME display as its neutral token — a resumed legacy plan is behavior-identical.
  const dLegacyOpus = mk('opus'), dLegacySonnet = mk('sonnet');
  assert(dLegacyOpus.codex_model === dR.codex_model
    && dLegacyOpus.codex_reasoning_effort === dR.codex_reasoning_effort,
    'BACK-COMPAT: legacy opus model+effort == reasoning model+effort');
  assert(JSON.stringify(dLegacyOpus.model_display) === JSON.stringify(dR.model_display),
    'BACK-COMPAT: legacy opus display == reasoning display');
  assert(dLegacySonnet.codex_model === dS.codex_model
    && dLegacySonnet.codex_reasoning_effort === dS.codex_reasoning_effort
    && JSON.stringify(dLegacySonnet.model_display) === JSON.stringify(dS.model_display),
    'BACK-COMPAT: legacy sonnet effort+display == standard');

  // UNTIERED (no tier): NO model_display key; both Codex overrides remain unresolved null sentinels.
  const dNone = mk(null);
  assert(!('model_display' in dNone), 'ENVELOPE-DISPLAY: untiered node carries no model_display key');
  assert(dNone.codex_model === null, 'TIER-RENAME: untiered node keeps the unresolved role_default model sentinel');
  assert(dNone.codex_reasoning_effort === null, 'TIER-RENAME: untiered node still role_default effort');
}

// ===========================================================================
// #466 — worktree-authority split guard. The adaptive lifecycle resolves the
// project folder (plan / ledger / .cache / baselines) cwd-relative via getRoot().
// When a linked worktree is recorded for the project but a MUTATING lifecycle
// command is invoked from the MAIN repo root (cwd === main, NOT the worktree),
// the ledger/evidence/baselines would diverge from where the role agents write —
// silent until finalize. The guard refuses loud (zero mutation) and points the
// operator into the worktree. Read-only (orient, record-evidence --verify) and
// the legitimately main-root copy (mirror-project) are EXEMPT. Native posture
// (no worktree_path recorded) is UNGUARDED. Driven as REAL subprocesses in a
// REAL git repo (the guard reads git + fs — a direct-call test would be a
// false-green per the #292 io-shim trap).
// ===========================================================================
{
  const { execFileSync } = require('child_process');
  const NODE_CLI_466 = path.join(__dirname, 'kaola-workflow-adaptive-node.js');
  const VALIDATOR_466 = path.join(__dirname, 'kaola-workflow-plan-validator.js');

  function make466Repo(stateExtra) {
    const repoRoot = fs.mkdtempSync(path.join(os.tmpdir(), 'kw-466-'));
    const project = 'issue-466';
    const projDir = path.join(repoRoot, 'kaola-workflow', project);
    const cacheDir = path.join(projDir, '.cache');
    fs.mkdirSync(cacheDir, { recursive: true });
    const planPath = path.join(projDir, 'workflow-plan.md');
    const plan = [
      '# Workflow Plan — issue-466', '',
      '## Meta', 'labels: area:scripts', 'sink: CHANGELOG.md', '',
      '## Nodes', '',
      '| id | role | depends_on | declared_write_set | cardinality | shape |',
      '| --- | --- | --- | --- | --- | --- |',
      '| seed     | code-explorer | —     | —     | 1 | sequence |',
      '| A        | tdd-guide     | seed  | ax.js | 1 | sequence |',
      '| review   | code-reviewer | A     | —     | 1 | sequence |',
      '| finalize | finalize      | review| —     | 1 | sequence |', '',
      '## Node Ledger', '',
      '| id | status |', '| --- | --- |',
      '| seed | complete |',
      '| A | pending |',
      '| review | pending |',
      '| finalize | pending |', '',
    ].join('\n') + '\n';
    fs.writeFileSync(planPath, plan);
    fs.writeFileSync(path.join(projDir, 'workflow-state.md'), '# State\n' + (stateExtra || ''));
    const g = (a) => execFileSync('git', ['-C', repoRoot, ...a], { encoding: 'utf8', stdio: ['ignore', 'ignore', 'ignore'] });
    g(['init']);
    g(['config', 'user.email', 'kw@test']);
    g(['config', 'user.name', 'kw']);
    g(['config', 'commit.gpgsign', 'false']);
    // Freeze in place so plan_hash exists (mutating subcommands run an integrity --resume-check; we
    // want the ONLY refusal under test to be the #466 split guard, which precedes the dispatch).
    try { execFileSync('node', [VALIDATOR_466, planPath, '--freeze', '--repair', '--json'], { cwd: repoRoot, encoding: 'utf8' }); } catch (_) {}
    fs.writeFileSync(path.join(repoRoot, '.gitignore'), '.kw/\n');
    g(['add', '-A']);
    g(['commit', '-m', 'init']);
    return { repoRoot, project, projDir, cacheDir, planPath, g };
  }
  function run466(cwd, subArgs) {
    try {
      const stdout = execFileSync('node', [NODE_CLI_466, ...subArgs], { cwd, encoding: 'utf8' });
      let parsed = {}; try { parsed = JSON.parse(stdout.trim().split('\n').pop()); } catch (_) {}
      return { exitCode: 0, ...parsed };
    } catch (err) {
      const status = (err.status == null) ? 1 : err.status;
      let parsed = {}; try { parsed = JSON.parse(String(err.stdout || '').trim().split('\n').pop()); } catch (_) {}
      return { exitCode: status, ...parsed };
    }
  }
  function rm466(p) { try { fs.rmSync(p, { recursive: true, force: true }); } catch (_) {} }

  // T466-1: open-ready (MUTATING) from MAIN root with a recorded+existing worktree → refuse split.
  {
    const wt = fs.mkdtempSync(path.join(os.tmpdir(), 'kw-466-wt-'));
    const { repoRoot, planPath, projDir } = make466Repo('worktree_path: ' + wt + '\n');
    const r = run466(repoRoot, ['open-ready', '--project', 'issue-466', '--json']);
    assert(r.result === 'refuse' && r.reason === 'worktree_authority_split',
      'T466-1: open-ready from main root with a recorded worktree refuses worktree_authority_split, got ' + JSON.stringify(r));
    assert(r.exitCode === 1, 'T466-1: the split refusal exits non-zero');
    assert(r.worktreePath === wt, 'T466-1: refusal carries the recorded worktreePath, got ' + JSON.stringify(r.worktreePath));
    assert(typeof r.operator_hint === 'string' && /worktree/i.test(r.operator_hint),
      'T466-1: operator_hint points into the worktree, got ' + JSON.stringify(r.operator_hint));
    // ZERO-MUTATION: the refused open-ready wrote nothing to the main-root project folder — the
    // ## Node Ledger still shows A pending and no task-mirror was created (the RED run flipped A to
    // in_progress AND wrote workflow-tasks.json, so this locks the early-return invariant).
    const ledgerAfter = fs.readFileSync(planPath, 'utf8');
    const ledgerBody = ledgerAfter.slice(ledgerAfter.indexOf('## Node Ledger'));
    assert(/\|\s*A\s*\|\s*pending\s*\|/.test(ledgerBody), 'T466-1: ledger A still pending after refuse (zero mutation)');
    assert(!fs.existsSync(path.join(projDir, 'workflow-tasks.json')), 'T466-1: no task-mirror written on refuse');
    rm466(repoRoot); rm466(wt);
  }

  // T466-2: open-next (MUTATING) from main root with a recorded worktree → also refuses.
  {
    const wt = fs.mkdtempSync(path.join(os.tmpdir(), 'kw-466-wt-'));
    const { repoRoot } = make466Repo('worktree_path: ' + wt + '\n');
    const r = run466(repoRoot, ['open-next', '--project', 'issue-466', '--json']);
    assert(r.reason === 'worktree_authority_split',
      'T466-2: open-next from main root with a recorded worktree refuses split, got ' + JSON.stringify(r));
    rm466(repoRoot); rm466(wt);
  }

  // T466-3: record-evidence --stdin (MUTATING) from main root with a recorded worktree → refuses.
  {
    const wt = fs.mkdtempSync(path.join(os.tmpdir(), 'kw-466-wt-'));
    const { repoRoot } = make466Repo('worktree_path: ' + wt + '\n');
    let r;
    try {
      const stdout = execFileSync('node', [NODE_CLI_466, 'record-evidence', '--node-id', 'A', '--stdin', '--project', 'issue-466', '--json'],
        { cwd: repoRoot, encoding: 'utf8', input: 'evidence-binding: A 000000000000\n' });
      r = JSON.parse(stdout.trim().split('\n').pop());
    } catch (err) {
      try { r = JSON.parse(String(err.stdout || '').trim().split('\n').pop()); } catch (_) { r = {}; }
    }
    assert(r.reason === 'worktree_authority_split',
      'T466-3: record-evidence --stdin from main root with a recorded worktree refuses split, got ' + JSON.stringify(r));
    rm466(repoRoot); rm466(wt);
  }

  // T466-4: NATIVE posture (no worktree_path recorded) → guard NEVER fires (open-ready proceeds).
  {
    const { repoRoot } = make466Repo('');
    const r = run466(repoRoot, ['open-ready', '--project', 'issue-466', '--json']);
    assert(r.reason !== 'worktree_authority_split',
      'T466-4: native posture (no worktree_path) is NOT split-guarded, got ' + JSON.stringify(r));
    rm466(repoRoot);
  }

  // T466-5: EXEMPT read-only orient — recorded worktree at main root does NOT trip the split guard.
  {
    const wt = fs.mkdtempSync(path.join(os.tmpdir(), 'kw-466-wt-'));
    const { repoRoot } = make466Repo('worktree_path: ' + wt + '\n');
    const r = run466(repoRoot, ['orient', '--project', 'issue-466', '--json']);
    assert(r.reason !== 'worktree_authority_split', 'T466-5: orient (read-only) is exempt, got ' + JSON.stringify(r));
    rm466(repoRoot); rm466(wt);
  }

  // T466-6: EXEMPT mirror-project — legitimately runs from the main root (it IS the main→worktree copy).
  {
    const wt = fs.mkdtempSync(path.join(os.tmpdir(), 'kw-466-wt-'));
    const { repoRoot } = make466Repo('worktree_path: ' + wt + '\n');
    const r = run466(repoRoot, ['mirror-project', '--project', 'issue-466', '--json']);
    assert(r.reason !== 'worktree_authority_split', 'T466-6: mirror-project is exempt, got ' + JSON.stringify(r));
    rm466(repoRoot); rm466(wt);
  }

  // T466-7: EXEMPT record-evidence --verify (read-only) — not split-guarded.
  {
    const wt = fs.mkdtempSync(path.join(os.tmpdir(), 'kw-466-wt-'));
    const { repoRoot } = make466Repo('worktree_path: ' + wt + '\n');
    const r = run466(repoRoot, ['record-evidence', '--node-id', 'A', '--verify', '--project', 'issue-466', '--json']);
    assert(r.reason !== 'worktree_authority_split', 'T466-7: record-evidence --verify is exempt, got ' + JSON.stringify(r));
    rm466(repoRoot); rm466(wt);
  }

  // T466-8: recorded worktree_path that does NOT exist on disk → guard does NOT fire (cannot be authoritative).
  {
    const { repoRoot } = make466Repo('worktree_path: /nonexistent/kw-466-ghost-dir\n');
    const r = run466(repoRoot, ['open-ready', '--project', 'issue-466', '--json']);
    assert(r.reason !== 'worktree_authority_split',
      'T466-8: a recorded-but-missing worktree dir does not trip the guard, got ' + JSON.stringify(r));
    rm466(repoRoot);
  }

  // T466-9: real linked-worktree posture — a lifecycle command RUN FROM the worktree is NOT guarded,
  // EVEN WITH worktree_path recorded in the MAIN state. This is the load-bearing exemption branch: the
  // guard short-circuits on `realRepoRoot === mainRoot`, so a worktree run must proceed. Recording
  // worktree_path in main state ensures the `if (recordedWorktree)` check is NOT what makes it pass —
  // a regression that broke the cwd discriminator (always-true) WOULD fire here and be caught.
  {
    const { repoRoot, projDir, g } = make466Repo('');
    const wt = fs.mkdtempSync(path.join(os.tmpdir(), 'kw-466-realwt-'));
    rm466(wt); // `git worktree add` requires a non-existent path
    let added = true;
    try { g(['worktree', 'add', wt, '-b', 'kw466wt']); } catch (_) { added = false; }
    if (added) {
      // Record the real worktree in the MAIN state (the file the guard reads via mainRoot).
      fs.writeFileSync(path.join(projDir, 'workflow-state.md'), '# State\nworktree_path: ' + wt + '\n');
      const r = run466(wt, ['open-ready', '--project', 'issue-466', '--json']);
      assert(r.reason !== 'worktree_authority_split',
        'T466-9: a lifecycle command run FROM the worktree (worktree_path recorded) is not split-guarded, got ' + JSON.stringify(r));
      assert(r.result === 'ok',
        'T466-9: in-worktree open-ready actually PROCEEDS (not refused for any reason), got ' + JSON.stringify(r));
      try { g(['worktree', 'remove', '--force', wt]); } catch (_) { rm466(wt); }
    } else {
      assert(true, 'T466-9: skipped (git worktree add unavailable in this environment)');
    }
    rm466(repoRoot);
  }
}

// ===========================================================================
// #439 (D-419 Part 4) — speculative-READ kernel runtime. open-ready --speculative-consent opens a
// read node behind an OPEN gate (marked speculative:true); open-next refuses gate_not_complete;
// discard-speculative rolls it back; a gate closing verdict:fail surfaces speculative_review_required.
// Driven as REAL subprocesses in a REAL git repo (the lifecycle reads git + fs).
// ===========================================================================
{
  const { execFileSync } = require('child_process');
  const NODE_CLI_439 = path.join(__dirname, 'kaola-workflow-adaptive-node.js');
  const VALIDATOR_439 = path.join(__dirname, 'kaola-workflow-plan-validator.js');

  // impl(tdd-guide,a.js) → gate(code-reviewer) → docs(doc-updater, read) → sink(finalize). impl complete.
  function make439Repo(policy) {
    const repoRoot = fs.mkdtempSync(path.join(os.tmpdir(), 'kw-439-'));
    const project = 'issue-439';
    const projDir = path.join(repoRoot, 'kaola-workflow', project);
    const cacheDir = path.join(projDir, '.cache');
    fs.mkdirSync(cacheDir, { recursive: true });
    const planPath = path.join(projDir, 'workflow-plan.md');
    const meta = ['## Meta', 'labels: area:scripts', 'sink: CHANGELOG.md'];
    if (policy) meta.push('speculative_open_policy: ' + policy);
    const plan = [
      '# Workflow Plan — issue-439', '',
      ...meta, '',
      '## Nodes', '',
      '| id | role | depends_on | declared_write_set | cardinality | shape |',
      '| --- | --- | --- | --- | --- | --- |',
      '| impl | tdd-guide     | —    | a.js         | 1 | sequence |',
      '| gate | code-reviewer | impl | —            | 1 | sequence |',
      '| docs | doc-updater   | gate | —            | 1 | sequence |',
      '| sink | finalize      | docs | CHANGELOG.md | 1 | sequence |', '',
      '## Node Ledger', '',
      '| id | status |', '| --- | --- |',
      '| impl | complete |', '| gate | pending |', '| docs | pending |', '| sink | pending |', '',
    ].join('\n') + '\n';
    fs.writeFileSync(planPath, plan);
    fs.writeFileSync(path.join(projDir, 'workflow-state.md'), '# State\n');
    fs.writeFileSync(path.join(repoRoot, 'a.js'), '// impl\n');
    const g = (a) => execFileSync('git', ['-C', repoRoot, ...a], { encoding: 'utf8', stdio: ['ignore', 'ignore', 'ignore'] });
    g(['init']); g(['config', 'user.email', 'kw@test']); g(['config', 'user.name', 'kw']); g(['config', 'commit.gpgsign', 'false']);
    try { execFileSync('node', [VALIDATOR_439, planPath, '--freeze', '--repair', '--json'], { cwd: repoRoot, encoding: 'utf8' }); } catch (_) {}
    fs.writeFileSync(path.join(repoRoot, '.gitignore'), '.kw/\n');
    g(['add', '-A']); g(['commit', '-m', 'init']);
    execFileSync('node', [VALIDATOR_439, planPath, '--record-base', '--node-id', 'impl', '--json'],
      { cwd: repoRoot, encoding: 'utf8' });
    return { repoRoot, project, projDir, cacheDir, planPath, g };
  }
  function run439(repoRoot, subArgs) {
    try {
      const stdout = execFileSync('node', [NODE_CLI_439, ...subArgs], { cwd: repoRoot, encoding: 'utf8' });
      let p = {}; try { p = JSON.parse(stdout.trim().split('\n').pop()); } catch (_) {}
      return { exitCode: 0, ...p };
    } catch (err) {
      const status = (err.status == null) ? 1 : err.status;
      let p = {}; try { p = JSON.parse(String(err.stdout || '').trim().split('\n').pop()); } catch (_) {}
      return { exitCode: status, ...p };
    }
  }
  function readRS439(cacheDir) { try { return JSON.parse(fs.readFileSync(path.join(cacheDir, 'running-set.json'), 'utf8')); } catch (_) { return null; } }
  function ledgerStatus439(planPath, id) {
    const txt = fs.readFileSync(planPath, 'utf8');
    const body = txt.slice(txt.indexOf('## Node Ledger'));
    const m = body.match(new RegExp('^\\|\\s*' + id + '\\s*\\|\\s*(\\S+)\\s*\\|', 'm'));
    return m ? m[1] : null;
  }
  // Open the gate via the REAL scheduler so it has a recorded baseline, then return the gate's nonce.
  function openGate439(repoRoot, cacheDir) {
    const r = run439(repoRoot, ['open-ready', '--project', 'issue-439', '--json']);  // opens gate (ready)
    const gateEntry = (r.opened || []).find(n => n.id === 'gate');
    return gateEntry ? gateEntry.nonce : null;
  }
  function rm439(p) { try { fs.rmSync(p, { recursive: true, force: true }); } catch (_) {} }

  // T439-1: open-ready --speculative-consent opens docs speculatively (policy:consent, gate open).
  {
    const { repoRoot, cacheDir } = make439Repo('consent');
    openGate439(repoRoot, cacheDir);
    const r = run439(repoRoot, ['open-ready', '--project', 'issue-439', '--speculative-consent', '--json']);
    assert(r.result === 'ok' && (r.opened || []).some(n => n.id === 'docs'),
      'T439-1: open-ready --speculative-consent opens docs, got ' + JSON.stringify((r.opened || []).map(n => n.id)));
    const rs = readRS439(cacheDir);
    const docsEntry = rs && (rs.nodes || []).find(n => n.id === 'docs');
    assert(docsEntry && docsEntry.speculative === true, 'T439-1: docs running-set entry is marked speculative:true');
    rm439(repoRoot);
  }

  // T439-2: open-ready WITHOUT --speculative-consent opens nothing speculative (consent is per-run).
  {
    const { repoRoot, cacheDir } = make439Repo('consent');
    openGate439(repoRoot, cacheDir);
    const r = run439(repoRoot, ['open-ready', '--project', 'issue-439', '--json']);
    assert((r.opened || []).every(n => n.id !== 'docs'), 'T439-2: no speculative open without the consent flag, got ' + JSON.stringify((r.opened || []).map(n => n.id)));
    rm439(repoRoot);
  }

  // T439-3: policy:off (default) + consent flag → NO speculative open (the plan must authorize too).
  {
    const { repoRoot, cacheDir } = make439Repo(null);  // no speculative_open_policy ⇒ default off
    openGate439(repoRoot, cacheDir);
    const r = run439(repoRoot, ['open-ready', '--project', 'issue-439', '--speculative-consent', '--json']);
    assert((r.opened || []).every(n => n.id !== 'docs'), 'T439-3: policy:off refuses speculative open even with the consent flag');
    rm439(repoRoot);
  }

  // T439-4: with the gate open SERIALLY (no running-set), open-next of the gate-blocked read node
  // refuses gate_not_complete (evaluated after the scheduler/batch guard passes — no running-set is
  // live on the serial path). When the gate is instead live in the running-set, open-next refuses
  // scheduler_active first; the speculative open then goes through open-ready --speculative-consent.
  {
    const { repoRoot } = make439Repo('consent');
    run439(repoRoot, ['open-next', '--project', 'issue-439', '--json']);  // serially opens the gate (no running-set)
    const r = run439(repoRoot, ['open-next', '--project', 'issue-439', '--node-id', 'docs', '--json']);
    assert(r.result === 'refuse' && r.reason === 'gate_not_complete',
      'T439-4: open-next of a gate-blocked read node refuses gate_not_complete, got ' + JSON.stringify(r));
    assert(r.speculativeGate === 'gate', 'T439-4: gate_not_complete names the open gate');
    rm439(repoRoot);
  }

  // T439-5: discard-speculative docs → ledger pending + removed from running-set.
  {
    const { repoRoot, cacheDir, planPath } = make439Repo('consent');
    openGate439(repoRoot, cacheDir);
    run439(repoRoot, ['open-ready', '--project', 'issue-439', '--speculative-consent', '--json']);
    assert(ledgerStatus439(planPath, 'docs') === 'in_progress', 'T439-5: docs is in_progress after speculative open');
    const r = run439(repoRoot, ['discard-speculative', '--project', 'issue-439', '--node-id', 'docs', '--json']);
    assert(r.result === 'ok' && r.ledgerReset === 'pending', 'T439-5: discard-speculative ok + ledger reset to pending, got ' + JSON.stringify(r));
    assert(ledgerStatus439(planPath, 'docs') === 'pending', 'T439-5: docs ledger is pending after discard');
    const rs = readRS439(cacheDir);
    assert(rs && (rs.nodes || []).every(n => n.id !== 'docs'), 'T439-5: docs removed from running-set after discard');
    rm439(repoRoot);
  }

  // T439-6: discard-speculative on a NON-speculative member (the gate) → not_speculative refuse.
  {
    const { repoRoot, cacheDir } = make439Repo('consent');
    openGate439(repoRoot, cacheDir);
    const r = run439(repoRoot, ['discard-speculative', '--project', 'issue-439', '--node-id', 'gate', '--json']);
    assert(r.result === 'refuse' && r.reason === 'not_speculative',
      'T439-6: discard-speculative on a non-speculative node refuses not_speculative, got ' + JSON.stringify(r));
    rm439(repoRoot);
  }

  // T439-7: close gate with verdict:FAIL → speculative_review_required names docs.
  {
    const { repoRoot, cacheDir, projDir } = make439Repo('consent');
    const gateNonce = openGate439(repoRoot, cacheDir);
    run439(repoRoot, ['open-ready', '--project', 'issue-439', '--speculative-consent', '--json']);
    fs.writeFileSync(path.join(cacheDir, 'gate.md'),
      'evidence-binding: gate ' + (gateNonce || '') + '\nverdict: fail\nfindings_blocking: 1\nfinding: id=x scope=in-scope severity=high status=open desc=bad\n');
    const r = run439(repoRoot, ['close-node', '--project', 'issue-439', '--node-id', 'gate', '--json']);
    assert(r.result === 'review_failed' && r.lifecycle_settled === true,
      'T439-7: gate failure settles one review attempt and returns the gate pending, got ' + JSON.stringify(r));
    assert(r.attempt_id === 'gate:1', 'T439-7: failure names the exact durable attempt id');
    const journal = JSON.parse(fs.readFileSync(path.join(cacheDir, 'review-attempts.json'), 'utf8'));
    assert(journal.attempts.length === 1 && journal.attempts[0].outcome === 'fail'
      && journal.attempts[0].lifecycle_settled === true && journal.attempts[0].consumed_by === null,
      'REV-SEQ-FAIL-BOTH: authoritative journal persists the settled unresolved failure');
    const orient = run439(repoRoot, ['orient', '--project', 'issue-439', '--json']);
    assert(orient.reason === 'review_attempt_unresolved' && (orient.attempt_ids || []).includes('gate:1')
      && /repair-node --attempt-id gate:1/.test(orient.repair || ''),
      'REV-OPEN-FENCE: orient stays read-only and names exact attempt/recovery');
    const reopen = run439(repoRoot, ['reopen-node', '--project', 'issue-439', '--node-id', 'impl', '--json']);
    assert(reopen.reason === 'review_attempt_unresolved' && (reopen.attempt_ids || []).includes('gate:1'),
      'REOPEN-FENCE: unresolved failed attempt blocks generic reopen');
    rm439(repoRoot);
  }

  // REV-SEQ-FAIL-BOTH: fused close uses the identical effective-pass and settlement transaction.
  {
    const { repoRoot, cacheDir, planPath } = make439Repo('off');
    const gateNonce = openGate439(repoRoot, cacheDir);
    fs.writeFileSync(path.join(cacheDir, 'gate.md'),
      'evidence-binding: gate ' + (gateNonce || '') + '\nverdict: pass\nfindings_blocking: 0\n'
      + 'finding: id=F-fused scope=in_scope action=fix status=open file=docs/a.md\n');
    const before = fs.readFileSync(planPath, 'utf8');
    const fused = run439(repoRoot, ['close-and-open-next', '--project', 'issue-439', '--node-id', 'gate', '--json']);
    assert(fused.result === 'review_failed' && fused.reason === 'unresolved_in_scope_fix'
      && fused.attempt_id === 'gate:1',
      'REV-SEQ-FAIL-BOTH: fused close cannot pass an unresolved canonical in-scope fix');
    assert(ledgerStatus439(planPath, 'gate') === 'pending' && fs.readFileSync(planPath, 'utf8') !== before,
      'REV-SEQ-FAIL-BOTH: fused failure returns the exact gate pending without opening a successor');
    rm439(repoRoot);
  }

  // T439-8: close gate with verdict:PASS → NO speculative_review_required (the bet held).
  {
    const { repoRoot, cacheDir } = make439Repo('consent');
    const gateNonce = openGate439(repoRoot, cacheDir);
    run439(repoRoot, ['open-ready', '--project', 'issue-439', '--speculative-consent', '--json']);
    fs.writeFileSync(path.join(cacheDir, 'gate.md'),
      'evidence-binding: gate ' + (gateNonce || '') + '\nverdict: pass\nfindings_blocking: 0\n');
    const r = run439(repoRoot, ['close-node', '--project', 'issue-439', '--node-id', 'gate', '--json']);
    assert(r.result === 'ok', 'T439-8: gate close succeeds on a pass verdict');
    assert(!r.speculative_review_required, 'T439-8: a verdict:pass gate does NOT surface speculative_review_required');
    rm439(repoRoot);
  }

  // T439-9: CLOSE-TIME guard — a speculative node CANNOT close while its gate is still in_progress
  // (else its review pointer + discard handle would vanish). The work ran concurrently (the win); only
  // the formal complete is held until the bet resolves.
  {
    const { repoRoot, cacheDir, planPath } = make439Repo('consent');
    openGate439(repoRoot, cacheDir);
    run439(repoRoot, ['open-ready', '--project', 'issue-439', '--speculative-consent', '--json']);
    // docs has valid evidence + nonce, but its gate is still in_progress.
    writeLegAwareEvidence(cacheDir, 'docs', 'doc-updater');
    const r = run439(repoRoot, ['close-node', '--project', 'issue-439', '--node-id', 'docs', '--json']);
    assert(r.result === 'refuse' && r.reason === 'gate_not_complete',
      'T439-9: closing a speculative node while its gate is open refuses gate_not_complete, got ' + JSON.stringify(r));
    assert(ledgerStatus439(planPath, 'docs') === 'in_progress', 'T439-9: docs stays in_progress (held, not completed)');
    rm439(repoRoot);
  }

  // T439-10: the close-time guard makes the review REACHABLE — docs is held in the running set, so when
  // the gate later closes verdict:fail, speculative_review_required still names docs (the coherence the
  // review + discard mechanism depends on; without the guard docs would have vanished on early close).
  {
    const { repoRoot, cacheDir } = make439Repo('consent');
    const gateNonce = openGate439(repoRoot, cacheDir);
    run439(repoRoot, ['open-ready', '--project', 'issue-439', '--speculative-consent', '--json']);
    // docs tries to close first but is HELD (gate open) — proving the held state precedes the gate close.
    writeLegAwareEvidence(cacheDir, 'docs', 'doc-updater');
    const held = run439(repoRoot, ['close-node', '--project', 'issue-439', '--node-id', 'docs', '--json']);
    assert(held.reason === 'gate_not_complete', 'T439-10: docs is held before the gate resolves');
    // Now the gate closes verdict:fail → review names docs (still in the running set).
    fs.writeFileSync(path.join(cacheDir, 'gate.md'),
      'evidence-binding: gate ' + (gateNonce || '') + '\nverdict: fail\nfindings_blocking: 1\nfinding: id=x scope=in-scope severity=high status=open desc=bad\n');
    const r = run439(repoRoot, ['close-node', '--project', 'issue-439', '--node-id', 'gate', '--json']);
    assert(r.result === 'review_failed' && r.attempt_id === 'gate:1',
      'T439-10: held speculative work cannot turn a failed review into a successful close, got ' + JSON.stringify(r));
    rm439(repoRoot);
  }

  // -------------------------------------------------------------------------
  // #597 — the `auto` tier + default flip (READ-side pieces; the WRITE-side AC4/AC2/O1 tests live in the
  // #596 block). At policy:auto, open-ready acts on the speculative READ set with NO --speculative-consent
  // (the flag is a no-op); a discard records role/gate telemetry.
  // -------------------------------------------------------------------------

  // T597-1 (AC2 — auto opens speculatively WITHOUT the flag): policy:auto + gate open → open-ready opens
  // the read node docs with NO --speculative-consent (mirror of T439-1 but flagless).
  {
    const { repoRoot, cacheDir } = make439Repo('auto');
    openGate439(repoRoot, cacheDir);
    const r = run439(repoRoot, ['open-ready', '--project', 'issue-439', '--json']); // NO --speculative-consent
    assert(r.result === 'ok' && (r.opened || []).some(n => n.id === 'docs'),
      'T597-1 (AC2): open-ready at policy:auto opens docs with NO consent flag, got ' + JSON.stringify((r.opened || []).map(n => n.id)));
    const rs = readRS439(cacheDir);
    const docsEntry = rs && (rs.nodes || []).find(n => n.id === 'docs');
    assert(docsEntry && docsEntry.speculative === true, 'T597-1 (AC2): docs running-set entry is marked speculative:true at auto');
    rm439(repoRoot);
  }

  // T597-2 (AC2 — the flag is a NO-OP at auto, never an error): the SAME policy:auto plan, but the run
  // ALSO passes --speculative-consent — it must be accepted (back-compat) and still open docs.
  {
    const { repoRoot, cacheDir } = make439Repo('auto');
    openGate439(repoRoot, cacheDir);
    const r = run439(repoRoot, ['open-ready', '--project', 'issue-439', '--speculative-consent', '--json']);
    assert(r.result === 'ok' && (r.opened || []).some(n => n.id === 'docs'),
      'T597-2 (AC2): --speculative-consent at auto is accepted as a no-op and still opens docs, got ' + JSON.stringify(r));
    rm439(repoRoot);
  }

  // T597-4 (AC5 — discard telemetry): a speculative discard at auto records node id / role / gate in the
  // durable provenance log, so the economics of `auto` are observable per run (no silent cost).
  {
    const { repoRoot, cacheDir } = make439Repo('auto');
    openGate439(repoRoot, cacheDir);
    run439(repoRoot, ['open-ready', '--project', 'issue-439', '--json']); // opens docs speculatively (auto)
    const r = run439(repoRoot, ['discard-speculative', '--project', 'issue-439', '--node-id', 'docs', '--json']);
    assert(r.result === 'ok', 'T597-4 (AC5): discard-speculative ok, got ' + JSON.stringify(r));
    const logPath = path.join(cacheDir, 'provenance-log.jsonl');
    const lines = fs.readFileSync(logPath, 'utf8').trim().split('\n').map(l => { try { return JSON.parse(l); } catch (_) { return {}; } });
    const discardEntry = lines.reverse().find(e => e.event === 'discard-speculative' && e.nodeId === 'docs');
    assert(discardEntry && discardEntry.role === 'doc-updater' && discardEntry.gate === 'gate',
      'T597-4 (AC5): the discard provenance entry records role + gate, got ' + JSON.stringify(discardEntry));
    rm439(repoRoot);
  }
}

// ===========================================================================
// #596 (D-596-01) — speculative-WRITE kernel runtime. Extends the #439 speculative-READ kernel to
// write-bearing nodes: open-ready --speculative-consent opens a WRITE node behind an OPEN gate WITH a
// provisioned leg (marked speculative:true + kind:'write'); the close fence, gate-fail review surfacing,
// and per-leg-barrier→merge machinery are ALL REUSED verbatim (a size-1 lane_group); discard-speculative
// is DISCARD-ONLY for writes (leg teardown + evidence purge, no KEEP option); reconcile-running-set gains
// a crashed-speculative-write arm (roll-forward only on a confirmed gate verdict:pass). Driven as REAL
// subprocesses in a REAL git repo (the lifecycle reads git + fs).
//
// Two code-reviewer gates are load-bearing in the fixture: gate1 is the ANCESTOR gate writerW bets on
// (writerA -> gate1 -> writerW); gate2 is writerW's OWN downstream reviewer (writerW -> gate2 -> sink) —
// the G1 freeze grammar requires EVERY code-producing node to be post-dominated by a code-reviewer, and
// gate1 (upstream of writerW) does not satisfy that for writerW itself (design: "the gate it speculates
// past is its ancestor; its own reviewer is downstream and unaffected").
// ===========================================================================
{
  const { execFileSync } = require('child_process');
  const NODE_CLI_596 = path.join(__dirname, 'kaola-workflow-adaptive-node.js');
  const VALIDATOR_596 = path.join(__dirname, 'kaola-workflow-plan-validator.js');
  const node596 = require(path.join(__dirname, 'kaola-workflow-adaptive-node.js'));
  const PROJECT_596 = 'issue-596';

  // writerA(write) -> gate1(reviewer, the bet) -> writerW(write) -> gate2(reviewer, writerW's own) -> sink.
  // policy defaults to 'consent' (existing callers unchanged); pass 'auto' for the #597 default-tier tests.
  function make596Repo(policy) {
    const repoRoot = fs.mkdtempSync(path.join(os.tmpdir(), 'kw-596-'));
    const projDir = path.join(repoRoot, 'kaola-workflow', PROJECT_596);
    const cacheDir = path.join(projDir, '.cache');
    fs.mkdirSync(cacheDir, { recursive: true });
    const planPath = path.join(projDir, 'workflow-plan.md');
    const plan = [
      '# Workflow Plan — issue-596', '',
      '## Meta', 'labels: area:scripts', 'sink: CHANGELOG.md', 'speculative_open_policy: ' + (policy || 'consent'), '',
      '## Nodes', '',
      '| id | role | depends_on | declared_write_set | cardinality | shape |',
      '| --- | --- | --- | --- | --- | --- |',
      '| writerA | tdd-guide     | —       | a.js         | 1 | sequence |',
      '| gate1   | code-reviewer | writerA | —            | 1 | sequence |',
      '| writerW | tdd-guide     | gate1   | w.js         | 1 | sequence |',
      '| gate2   | code-reviewer | writerW | —            | 1 | sequence |',
      '| sink    | finalize      | gate2   | CHANGELOG.md | 1 | sequence |', '',
      '## Node Ledger', '',
      '| id | status |', '| --- | --- |',
      '| writerA | complete |', '| gate1 | pending |', '| writerW | pending |', '| gate2 | pending |', '| sink | pending |', '',
    ].join('\n') + '\n';
    fs.writeFileSync(planPath, plan);
    fs.writeFileSync(path.join(projDir, 'workflow-state.md'), '# State\n');
    fs.writeFileSync(path.join(repoRoot, 'a.js'), '// writerA\n');
    const g = (a) => execFileSync('git', ['-C', repoRoot, ...a], { encoding: 'utf8', stdio: ['ignore', 'ignore', 'ignore'] });
    g(['init']); g(['config', 'user.email', 'kw@test']); g(['config', 'user.name', 'kw']); g(['config', 'commit.gpgsign', 'false']);
    try { execFileSync('node', [VALIDATOR_596, planPath, '--freeze', '--repair', '--json'], { cwd: repoRoot, encoding: 'utf8' }); } catch (_) {}
    fs.writeFileSync(path.join(repoRoot, '.gitignore'), '.kw/\n');
    g(['add', '-A']); g(['commit', '-m', 'init']);
    execFileSync('node', [VALIDATOR_596, planPath, '--record-base', '--node-id', 'writerA', '--json'],
      { cwd: repoRoot, encoding: 'utf8' });
    return { repoRoot, project: PROJECT_596, projDir, cacheDir, planPath, g };
  }

  // Sibling variant: writerA -> gate1 -> {writerW1(set1), writerW2(set2)} -> gate2 -> sink. Both siblings'
  // ONLY unsatisfied dep is gate1, so BOTH are speculative-eligible simultaneously.
  function make596PairRepo(set1, set2) {
    const repoRoot = fs.mkdtempSync(path.join(os.tmpdir(), 'kw-596p-'));
    const projDir = path.join(repoRoot, 'kaola-workflow', PROJECT_596);
    const cacheDir = path.join(projDir, '.cache');
    fs.mkdirSync(cacheDir, { recursive: true });
    const planPath = path.join(projDir, 'workflow-plan.md');
    const plan = [
      '# Workflow Plan — issue-596 (pair)', '',
      '## Meta', 'labels: area:scripts', 'sink: CHANGELOG.md', 'speculative_open_policy: consent', '',
      '## Nodes', '',
      '| id | role | depends_on | declared_write_set | cardinality | shape |',
      '| --- | --- | --- | --- | --- | --- |',
      '| writerA | tdd-guide     | —              | a.js         | 1 | sequence |',
      '| gate1   | code-reviewer | writerA        | —            | 1 | sequence |',
      '| writerW1 | tdd-guide    | gate1          | ' + set1 + ' | 1 | sequence |',
      '| writerW2 | tdd-guide    | gate1          | ' + set2 + ' | 1 | sequence |',
      '| gate2   | code-reviewer | writerW1,writerW2 | —         | 1 | sequence |',
      '| sink    | finalize      | gate2          | CHANGELOG.md | 1 | sequence |', '',
      '## Node Ledger', '',
      '| id | status |', '| --- | --- |',
      '| writerA | complete |', '| gate1 | pending |', '| writerW1 | pending |', '| writerW2 | pending |', '| gate2 | pending |', '| sink | pending |', '',
    ].join('\n') + '\n';
    fs.writeFileSync(planPath, plan);
    fs.writeFileSync(path.join(projDir, 'workflow-state.md'), '# State\n');
    fs.writeFileSync(path.join(repoRoot, 'a.js'), '// writerA\n');
    const g = (a) => execFileSync('git', ['-C', repoRoot, ...a], { encoding: 'utf8', stdio: ['ignore', 'ignore', 'ignore'] });
    g(['init']); g(['config', 'user.email', 'kw@test']); g(['config', 'user.name', 'kw']); g(['config', 'commit.gpgsign', 'false']);
    try { execFileSync('node', [VALIDATOR_596, planPath, '--freeze', '--repair', '--json'], { cwd: repoRoot, encoding: 'utf8' }); } catch (_) {}
    fs.writeFileSync(path.join(repoRoot, '.gitignore'), '.kw/\n');
    g(['add', '-A']); g(['commit', '-m', 'init']);
    execFileSync('node', [VALIDATOR_596, planPath, '--record-base', '--node-id', 'writerA', '--json'],
      { cwd: repoRoot, encoding: 'utf8' });
    return { repoRoot, project: PROJECT_596, projDir, cacheDir, planPath, g };
  }

  function run596(repoRoot, subArgs, extraEnv) {
    try {
      const stdout = execFileSync('node', [NODE_CLI_596, ...subArgs], { cwd: repoRoot, encoding: 'utf8', env: { ...process.env, ...(extraEnv || {}) } });
      let p = {}; try { p = JSON.parse(stdout.trim().split('\n').pop()); } catch (_) {}
      return { exitCode: 0, ...p };
    } catch (err) {
      const status = (err.status == null) ? 1 : err.status;
      let p = {}; try { p = JSON.parse(String(err.stdout || '').trim().split('\n').pop()); } catch (_) {}
      return { exitCode: status, ...p };
    }
  }
  function readRS596(cacheDir) { try { return JSON.parse(fs.readFileSync(path.join(cacheDir, 'running-set.json'), 'utf8')); } catch (_) { return null; } }
  function ledgerStatus596(planPath, id) {
    const txt = fs.readFileSync(planPath, 'utf8');
    const body = txt.slice(txt.indexOf('## Node Ledger'));
    const m = body.match(new RegExp('^\\|\\s*' + id + '\\s*\\|\\s*(\\S+)\\s*\\|', 'm'));
    return m ? m[1] : null;
  }
  function worktreePaths596(repoRoot) {
    let out = '';
    try { out = execFileSync('git', ['-C', repoRoot, 'worktree', 'list', '--porcelain'], { encoding: 'utf8' }); } catch (_) { return []; }
    return String(out).split('\n').filter(l => l.indexOf('worktree ') === 0).map(l => l.slice('worktree '.length).trim());
  }
  function branchExists596(repoRoot, branch) {
    try { execFileSync('git', ['-C', repoRoot, 'rev-parse', '--verify', '--quiet', 'refs/heads/' + branch], { stdio: ['ignore', 'ignore', 'ignore'] }); return true; }
    catch (_) { return false; }
  }
  function legBaseRefExists596(repoRoot, project, id) {
    try { execFileSync('git', ['-C', repoRoot, 'show-ref', '--verify', '--quiet', 'refs/kaola-workflow/leg-base/' + project + '/' + id], { stdio: ['ignore', 'ignore', 'ignore'] }); return true; }
    catch (_) { return false; }
  }
  // Open gate1 via the REAL scheduler (a normal read-only ready node) and return its nonce.
  function openGate1_596(repoRoot, project) {
    const r = run596(repoRoot, ['open-ready', '--project', project || PROJECT_596, '--json']);
    const gateEntry = (r.opened || []).find(n => n.id === 'gate1');
    return gateEntry ? gateEntry.nonce : null;
  }
  // tdd-guide requires evidence-binding + RED + GREEN tokens (ROLE_TOKEN_REGISTRY); writerW/writerW1/
  // writerW2 are all tdd-guide in these fixtures.
  function writeValidEvidence596(cacheDir, id) {
    return writeLegAwareEvidence(cacheDir, id, 'tdd-guide');
  }
  function rm596(p) { try { fs.rmSync(p, { recursive: true, force: true }); } catch (_) {} }

  // T596-1 (AC1 happy path): plan writerA -> gate1 -> writerW; writerW's set is exact-disjoint from all
  // live writers (there are none live). With policy consent + --speculative-consent and gate1 in_progress,
  // open-ready opens writerW in a provisioned leg (a size-1 lane_group).
  {
    const { repoRoot, cacheDir, project } = make596Repo();
    openGate1_596(repoRoot);
    const r = run596(repoRoot, ['open-ready', '--project', project, '--speculative-consent', '--json']);
    assert(r.result === 'ok' && (r.opened || []).some(n => n.id === 'writerW'),
      'T596-1: open-ready --speculative-consent opens writerW, got ' + JSON.stringify((r.opened || []).map(n => n.id)));
    assert(r.laneGroup && r.laneGroup.group_id === 'lg-writerW' && JSON.stringify(r.laneGroup.members) === JSON.stringify(['writerW']),
      'T596-1: a size-1 lane_group forms for the lone speculative writer, got ' + JSON.stringify(r.laneGroup));
    assert(r.laneGroup.legs && r.laneGroup.legs.writerW && r.laneGroup.legs.writerW.legPath,
      'T596-1: the lane_group carries a provisioned leg for writerW, got ' + JSON.stringify(r.laneGroup.legs));
    const rs = readRS596(cacheDir);
    const w = rs && (rs.nodes || []).find(n => n.id === 'writerW');
    assert(w && w.speculative === true && w.speculativeGate === 'gate1' && w.kind === 'write' && w.group_id === 'lg-writerW',
      'T596-1: running-set entry marked speculative:true, kind:write, speculativeGate:gate1, got ' + JSON.stringify(w));
    const wts = worktreePaths596(repoRoot);
    assert(wts.some(p => p.endsWith(path.join('.kw', 'legs', project, 'writerW'))), 'T596-1: leg worktree provisioned, got ' + JSON.stringify(wts));
    assert(branchExists596(repoRoot, 'kw/legs/' + project + '/writerW'), 'T596-1: leg branch provisioned');
    assert(ledgerStatus596(r && r.planPath || path.join(repoRoot, 'kaola-workflow', project, 'workflow-plan.md'), 'writerW') === 'in_progress',
      'T596-1: writerW ledger flipped to in_progress');
    rm596(repoRoot);
  }

  // T596-2 (AC2 close fence): writerW's close while gate1 is open refuses gate_not_complete — the SAME
  // speculativeCloseGuard the read half uses, unchanged, exercised here by a WRITE member.
  {
    const { repoRoot, cacheDir, planPath, project } = make596Repo();
    openGate1_596(repoRoot);
    run596(repoRoot, ['open-ready', '--project', project, '--speculative-consent', '--json']);
    writeValidEvidence596(cacheDir, 'writerW');
    const r = run596(repoRoot, ['close-node', '--project', project, '--node-id', 'writerW', '--json']);
    assert(r.result === 'refuse' && r.reason === 'gate_not_complete',
      'T596-2: closing a speculative WRITE node while its gate is open refuses gate_not_complete, got ' + JSON.stringify(r));
    assert(r.speculativeGate === 'gate1', 'T596-2: gate_not_complete names the open gate');
    assert(ledgerStatus596(planPath, 'writerW') === 'in_progress', 'T596-2: writerW stays in_progress (held, not completed)');
    rm596(repoRoot);
  }

  // T596-3 (AC3 pass path): gate1 closes verdict:pass -> writerW closes normally; the leg merges through
  // the EXISTING per-leg barrier -> octopus/merge path (no new merge code); union barrier green.
  {
    const { repoRoot, cacheDir, planPath, project } = make596Repo();
    const gate1Nonce = openGate1_596(repoRoot);
    const open = run596(repoRoot, ['open-ready', '--project', project, '--speculative-consent', '--json']);
    assert(open.result === 'ok' && open.laneGroup, 'T596-3: setup speculative open ok');
    const legPath = open.laneGroup.legs.writerW.legPath;
    fs.writeFileSync(path.join(legPath, 'w.js'), '// writerW in-lane (leg)\n');
    writeValidEvidence596(cacheDir, 'writerW');
    fs.writeFileSync(path.join(cacheDir, 'gate1.md'), 'evidence-binding: gate1 ' + (gate1Nonce || '') + '\nverdict: pass\nfindings_blocking: 0\n');
    const rGate = run596(repoRoot, ['close-node', '--project', project, '--node-id', 'gate1', '--json']);
    assert(rGate.result === 'ok' && !rGate.speculative_review_required, 'T596-3: gate1 closes verdict:pass with NO speculative_review_required, got ' + JSON.stringify(rGate));
    const rW = run596(repoRoot, ['close-node', '--project', project, '--node-id', 'writerW', '--json']);
    assert(rW.result === 'ok' && rW.barrier === 'group_passed' && rW.synthesized === true && typeof rW.mergeCommit === 'string' && rW.mergeCommit.length >= 7,
      'T596-3: writerW closes via the group (octopus-merge) union barrier ⇒ group_passed + synthesized, got ' + JSON.stringify(rW));
    const head = execFileSync('git', ['-C', repoRoot, 'ls-tree', '-r', '--name-only', 'HEAD'], { encoding: 'utf8' });
    assert(head.includes('w.js'), 'T596-3: w.js reaches HEAD after the union barrier merge, got ' + JSON.stringify(head.split('\n').filter(Boolean)));
    assert(ledgerStatus596(planPath, 'writerW') === 'complete', 'T596-3: writerW ledger complete');
    const wts = worktreePaths596(repoRoot);
    assert(!wts.some(p => p.indexOf(path.join('.kw', 'legs')) !== -1), 'T596-3: leg worktree torn down on clean completion, got ' + JSON.stringify(wts));
    rm596(repoRoot);
  }

  // T596-4 (AC4 fail path): gate1 closes verdict:fail -> discard-speculative on writerW removes the leg
  // worktree + branch + leg-base ref; ledger row back to pending; baseline dropped; evidence discarded;
  // the PARENT worktree is byte-identical to pre-speculation (w.js never existed at the parent root).
  {
    const { repoRoot, cacheDir, planPath, project } = make596Repo();
    const gate1Nonce = openGate1_596(repoRoot);
    const open = run596(repoRoot, ['open-ready', '--project', project, '--speculative-consent', '--json']);
    assert(open.result === 'ok' && open.laneGroup, 'T596-4: setup speculative open ok');
    assert(fs.existsSync(path.join(cacheDir, 'writerW.md')), 'T596-4: writerW evidence auto-seeded at open');
    assert(fs.existsSync(path.join(cacheDir, 'barrier-base-writerW')), 'T596-4: writerW baseline recorded at open');
    fs.writeFileSync(path.join(cacheDir, 'gate1.md'), 'evidence-binding: gate1 ' + (gate1Nonce || '') + '\nverdict: fail\nfindings_blocking: 1\nfinding: id=x scope=in-scope severity=high status=open desc=bad\n');
    const rGate = run596(repoRoot, ['close-node', '--project', project, '--node-id', 'gate1', '--json']);
    assert(rGate.result === 'review_failed' && rGate.attempt_id === 'gate1:1',
      'T596-4: gate1 verdict:fail becomes a settled failed review transaction, got ' + JSON.stringify(rGate));
    const r = run596(repoRoot, ['discard-speculative', '--project', project, '--node-id', 'writerW', '--json']);
    assert(r.result === 'ok' && r.discarded === true && r.legTornDown === true && r.evidenceDiscarded === true && r.groupCleared === true,
      'T596-4: discard-speculative tears down the leg + purges evidence + clears the (sole-member) group, got ' + JSON.stringify(r));
    assert(ledgerStatus596(planPath, 'writerW') === 'pending', 'T596-4: writerW ledger row back to pending');
    const wts = worktreePaths596(repoRoot);
    assert(!wts.some(p => p.indexOf(path.join('.kw', 'legs')) !== -1), 'T596-4: leg worktree removed, got ' + JSON.stringify(wts));
    assert(!branchExists596(repoRoot, 'kw/legs/' + project + '/writerW'), 'T596-4: leg branch removed');
    assert(!legBaseRefExists596(repoRoot, project, 'writerW'), 'T596-4: leg-base ref removed');
    assert(!fs.existsSync(path.join(cacheDir, 'barrier-base-writerW')), 'T596-4: baseline dropped');
    assert(!fs.existsSync(path.join(cacheDir, 'writerW.md')), 'T596-4: evidence discarded (file purged)');
    const rs = readRS596(cacheDir);
    assert(!(rs && (rs.nodes || []).some(n => n.id === 'writerW')), 'T596-4: writerW removed from the running set');
    assert(!(rs && rs.lane_group), 'T596-4: lane_group entirely cleared (sole member discarded)');
    assert(!fs.existsSync(path.join(repoRoot, 'w.js')), 'T596-4: parent worktree byte-identical to pre-speculation — w.js never existed at the parent root');
    const porcelainW = execFileSync('git', ['-C', repoRoot, 'status', '--porcelain', '--', 'w.js'], { encoding: 'utf8' });
    assert(porcelainW.trim() === '', 'T596-4: git sees no trace of w.js at the parent');
    rm596(repoRoot);
  }

  // T596-5 (AC5 refusal — direct unit test of the runtime exact-overlap re-check). NOTE on why this is a
  // direct unit test rather than a full open-ready lifecycle test: the FREEZE WALL already refuses two
  // concurrent (antichain) sibling nodes declaring the SAME exact file at freeze time — "concurrent
  // siblings X and Y both write ... (parallel non-fanout write overlap)" (plan-validator.js's freeze-grammar
  // check; exact overlap NEVER relaxes anywhere in this codebase) — so writerW1/writerW2 sharing an exact
  // path can never reach a FROZEN plan in the first place, and the running-set's write-node-runs-strictly-
  // alone invariant means a genuinely LIVE writer is unreachable alongside an open gate through open-ready
  // alone. The runtime re-verification (selectSpeculativeWriteGroup → validator --parallel-safe, the SAME
  // predicate normal co-open uses) is therefore intentional belt-and-suspenders defense-in-depth, proven
  // directly here with a real validator subprocess (--parallel-safe reads the plan's Node rows directly —
  // it does not require the plan to be frozen, so make596PairRepo's fixture, which the freeze grammar
  // rejects for these declared sets, is still a valid --parallel-safe input).
  {
    const { planPath } = make596PairRepo('shared.js', 'shared.js');
    const realShell = (sp, args) => node596.shellNode(sp, args);
    const excludedVsLive = node596.selectSpeculativeWriteGroup(
      [{ id: 'writerW1', declared_write_set: 'shared.js' }],
      [{ id: 'writerW2', kind: 'write' }], // stand-in for a genuinely live writer
      planPath, realShell, false, null
    );
    assert(excludedVsLive.chosen.length === 0 && excludedVsLive.excluded.join(',') === 'writerW1',
      'T596-5: a candidate overlapping an already-open write node is excluded, got ' + JSON.stringify(excludedVsLive));
    const disjointVsLive = node596.selectSpeculativeWriteGroup(
      [{ id: 'writerW1', declared_write_set: 'shared.js' }],
      [], planPath, realShell, false, null
    );
    assert(disjointVsLive.chosen.length === 1 && disjointVsLive.chosen[0].id === 'writerW1' && disjointVsLive.excluded.length === 0,
      'T596-5: a lone candidate with NO live writers is trivially eligible, got ' + JSON.stringify(disjointVsLive));
  }

  // T596-6 (AC5 refusal — no leg capability): KAOLA_PARALLEL_WRITES=0 (the SAME worktree-capable
  // condition normal co-open requires) excludes writerW from THIS open; read speculation is unaffected
  // (there is none in this fixture, but the exclusion is scoped to write candidates only, never a refuse).
  {
    const { repoRoot, cacheDir, planPath, project } = make596Repo();
    openGate1_596(repoRoot);
    const r = run596(repoRoot, ['open-ready', '--project', project, '--speculative-consent', '--json'], { KAOLA_PARALLEL_WRITES: '0' });
    assert(r.result === 'ok' && (r.opened || []).length === 0, 'T596-6: no write opens on a host without leg capability, got ' + JSON.stringify(r.opened));
    assert(r.speculativeWriteExcluded && r.speculativeWriteExcluded.reason === 'no_leg_capability' && (r.speculativeWriteExcluded.nodeIds || []).includes('writerW'),
      'T596-6: speculativeWriteExcluded names the no_leg_capability reason, got ' + JSON.stringify(r.speculativeWriteExcluded));
    assert(ledgerStatus596(planPath, 'writerW') === 'pending', 'T596-6: writerW ledger row untouched');
    rm596(repoRoot);
  }

  // T596-7 (AC6 cap accounting): two DISJOINT speculative write siblings under a write fan-out ceiling of
  // 1 (KAOLA_FANOUT_CAP=1) — only ONE opens this call; the frontier never exceeds the cap.
  {
    const { repoRoot, cacheDir, planPath, project } = make596PairRepo('w1.js', 'w2.js');
    openGate1_596(repoRoot);
    const r = run596(repoRoot, ['open-ready', '--project', project, '--speculative-consent', '--json'], { KAOLA_FANOUT_CAP: '1' });
    assert(r.result === 'ok' && (r.opened || []).length === 1, 'T596-7: exactly ONE speculative write opens under the cap, got ' + JSON.stringify((r.opened || []).map(n => n.id)));
    assert(r.laneGroup && r.laneGroup.members.length === 1, 'T596-7: the formed group has exactly one member, got ' + JSON.stringify(r.laneGroup));
    const openedId = r.opened[0].id;
    const otherId = openedId === 'writerW1' ? 'writerW2' : 'writerW1';
    assert(ledgerStatus596(planPath, otherId) === 'pending', 'T596-7: the capped-out sibling stays pending, got ' + ledgerStatus596(planPath, otherId));
    const rs = readRS596(cacheDir);
    assert(!(rs && (rs.nodes || []).some(n => n.id === otherId)), 'T596-7: the capped-out sibling never entered the running set');
    rm596(repoRoot);
  }

  // T596-8 (AC7 crash repair — kill BETWEEN leg provision and ledger flip): the leg is already
  // provisioned on disk but writerW's ledger row is manually reverted to pending (simulating the crash
  // window) and running-set.json is flagged mid-open — reconcile-running-set rolls it back cleanly:
  // no orphan leg survives, idempotent (the EXISTING #463 lane-group crash-repair machinery, reused
  // verbatim — the speculative write leg is an ordinary lane_group leg to that machinery).
  {
    const { repoRoot, cacheDir, planPath, project } = make596Repo();
    openGate1_596(repoRoot);
    const open = run596(repoRoot, ['open-ready', '--project', project, '--speculative-consent', '--json']);
    assert(open.result === 'ok' && open.laneGroup, 'T596-8: setup speculative open ok');
    // Simulate the crash: writerW's ledger row reverts to pending; running-set flags it mid-open.
    let plan = fs.readFileSync(planPath, 'utf8');
    const ledgerStart = plan.indexOf('## Node Ledger');
    const head = plan.slice(0, ledgerStart), tail = plan.slice(ledgerStart);
    plan = head + tail.replace(/^\|\s*writerW\s*\|\s*in_progress\s*\|/m, '| writerW | pending |');
    fs.writeFileSync(planPath, plan);
    const rs0 = readRS596(cacheDir);
    rs0.state = 'opening';
    rs0.nodes = rs0.nodes.map(n => (n.id === 'writerW' ? { ...n, opening: true } : n));
    fs.writeFileSync(path.join(cacheDir, 'running-set.json'), JSON.stringify(rs0, null, 2));
    const rec = run596(repoRoot, ['reconcile-running-set', '--project', project, '--json']);
    assert(rec.result === 'ok', 'T596-8: reconcile ok, got ' + JSON.stringify(rec));
    const wts = worktreePaths596(repoRoot);
    assert(!wts.some(p => p.indexOf(path.join('.kw', 'legs')) !== -1), 'T596-8: no orphan leg survives, got ' + JSON.stringify(wts));
    assert(!branchExists596(repoRoot, 'kw/legs/' + project + '/writerW'), 'T596-8: leg branch torn down');
    assert(!fs.existsSync(path.join(cacheDir, 'writerW.md')), 'T596-8: evidence purged on rollback');
    // Idempotent: a second reconcile is a clean no-op.
    const rec2 = run596(repoRoot, ['reconcile-running-set', '--project', project, '--json']);
    assert(rec2.result === 'ok', 'T596-8: second reconcile is idempotent (ok, no throw), got ' + JSON.stringify(rec2));
    rm596(repoRoot);
  }

  // T596-9 (AC7 crash repair — the crashed-speculative-write ARM, gate resolved FAIL): writerW's ledger
  // row DID flip to in_progress (the general roll-forward candidate) but running-set.json is stuck
  // 'opening' (Phase 3 never completed) AND gate1 has since resolved verdict:FAIL — reconcile rolls
  // writerW BACK despite its in_progress ledger row (the conservative override: roll-forward only on a
  // CONFIRMED gate verdict:pass).
  {
    const { repoRoot, cacheDir, planPath, project } = make596Repo();
    const gate1Nonce = openGate1_596(repoRoot);
    const open = run596(repoRoot, ['open-ready', '--project', project, '--speculative-consent', '--json']);
    assert(open.result === 'ok' && open.laneGroup, 'T596-9: setup speculative open ok');
    fs.writeFileSync(path.join(cacheDir, 'gate1.md'), 'evidence-binding: gate1 ' + (gate1Nonce || '') + '\nverdict: fail\nfindings_blocking: 1\nfinding: id=x scope=in-scope severity=high status=open desc=bad\n');
    // Close gate1 directly at the plan/ledger level (bypass the close-time guard's running-set removal —
    // we want gate1 TERMINAL while writerW's running-set entry stays exactly as open-ready left it, to
    // isolate the reconcile-time gate check from the close-node speculative-review machinery).
    const rGate = run596(repoRoot, ['close-node', '--project', project, '--node-id', 'gate1', '--json']);
    assert(rGate.result === 'review_failed', 'T596-9: gate1 settles verdict:fail without exposing successors, got ' + JSON.stringify(rGate));
    assert(ledgerStatus596(planPath, 'writerW') === 'in_progress', 'T596-9: writerW ledger row is STILL in_progress (the roll-forward candidate)');
    // Flag running-set.json mid-open (the Phase-3-never-ran crash window); writerW's ledger row is
    // deliberately left in_progress (unlike T596-9).
    const rs0 = readRS596(cacheDir);
    rs0.state = 'opening';
    rs0.nodes = rs0.nodes.map(n => (n.id === 'writerW' ? { ...n, opening: true } : n));
    fs.writeFileSync(path.join(cacheDir, 'running-set.json'), JSON.stringify(rs0, null, 2));
    const rec = run596(repoRoot, ['reconcile-running-set', '--project', project, '--json']);
    assert(rec.result === 'ok', 'T596-9: reconcile ok, got ' + JSON.stringify(rec));
    assert((rec.rolledBack || []).includes('writerW'), 'T596-9: writerW is rolled BACK despite in_progress ledger (gate resolved fail), got ' + JSON.stringify(rec.rolledBack));
    assert(ledgerStatus596(planPath, 'writerW') === 'pending', 'T596-9: writerW ledger reset to pending');
    const wts = worktreePaths596(repoRoot);
    assert(!wts.some(p => p.indexOf(path.join('.kw', 'legs')) !== -1), 'T596-9: writerW leg torn down (gate-fail override), got ' + JSON.stringify(wts));
    assert(!fs.existsSync(path.join(cacheDir, 'writerW.md')), 'T596-9: writerW evidence purged (gate-fail override)');
    rm596(repoRoot);
  }

  // T596-10 (AC7 crash repair — the crashed-speculative-write ARM, gate resolved PASS): the SAME
  // running-set-stuck-opening window as T596-9, but gate1 resolves verdict:PASS — reconcile rolls
  // writerW FORWARD (keeps it live; its leg survives; running-set.json promotes to 'open').
  {
    const { repoRoot, cacheDir, planPath, project } = make596Repo();
    const gate1Nonce = openGate1_596(repoRoot);
    const open = run596(repoRoot, ['open-ready', '--project', project, '--speculative-consent', '--json']);
    assert(open.result === 'ok' && open.laneGroup, 'T596-10: setup speculative open ok');
    fs.writeFileSync(path.join(cacheDir, 'gate1.md'), 'evidence-binding: gate1 ' + (gate1Nonce || '') + '\nverdict: pass\nfindings_blocking: 0\n');
    const rGate = run596(repoRoot, ['close-node', '--project', project, '--node-id', 'gate1', '--json']);
    assert(rGate.result === 'ok' && !rGate.speculative_review_required, 'T596-10: gate1 closes verdict:pass, got ' + JSON.stringify(rGate));
    const rs0 = readRS596(cacheDir);
    rs0.state = 'opening';
    rs0.nodes = rs0.nodes.map(n => (n.id === 'writerW' ? { ...n, opening: true } : n));
    fs.writeFileSync(path.join(cacheDir, 'running-set.json'), JSON.stringify(rs0, null, 2));
    const rec = run596(repoRoot, ['reconcile-running-set', '--project', project, '--json']);
    assert(rec.result === 'ok', 'T596-10: reconcile ok, got ' + JSON.stringify(rec));
    assert((rec.rolledForward || []).includes('writerW'), 'T596-10: writerW rolls FORWARD (gate confirmed pass), got ' + JSON.stringify(rec.rolledForward));
    assert(ledgerStatus596(planPath, 'writerW') === 'in_progress', 'T596-10: writerW ledger stays in_progress');
    const wts = worktreePaths596(repoRoot);
    assert(wts.some(p => p.endsWith(path.join('.kw', 'legs', project, 'writerW'))), 'T596-10: writerW leg SURVIVES the roll-forward, got ' + JSON.stringify(wts));
    const rsAfter = readRS596(cacheDir);
    assert(rsAfter && rsAfter.state === 'open', 'T596-10: running-set promoted back to open');
    rm596(repoRoot);
  }

  // T596-11 (AC8 inertness — consent flag absent): policy:consent is authored, but --speculative-consent
  // is NOT passed this call — writerW does not open (mirrors T439-2 for a write member).
  {
    const { repoRoot, project } = make596Repo();
    openGate1_596(repoRoot);
    const r = run596(repoRoot, ['open-ready', '--project', project, '--json']);
    assert((r.opened || []).every(n => n.id !== 'writerW'), 'T596-11: no speculative write open without the consent flag, got ' + JSON.stringify((r.opened || []).map(n => n.id)));
    rm596(repoRoot);
  }

  // T599-1 (issue #599 — fail-open bug): selectSpeculativeWriteGroup's --parallel-safe re-check must
  // mirror tryFormLaneGroup's fail-CLOSED posture on a validator SUBPROCESS FAILURE (crash / unparseable
  // JSON / any non-ok result carrying no `overlapping` array) — it must NOT proceed with every candidate
  // just because "for (const o of (ps.overlapping || []))" finds nothing to iterate. Direct unit test via
  // the SAME injectable seam T596-5 uses (selectSpeculativeWriteGroup takes `shell` as a parameter) — a
  // fault-injecting shell mock (the M3/M4 idiom above) is the cleanest seam; no real subprocess crash is
  // needed to prove the selection logic.
  {
    const { planPath } = make596PairRepo('shared.js', 'shared.js');

    // (a) validator subprocess CRASH: shellNode's documented fail-closed shape on "throw with no
    // stdout" is `{ exitCode: status }` — no `result`, no `overlapping` field at all.
    const crashedShell = () => ({ exitCode: 1 });
    const crashed = node596.selectSpeculativeWriteGroup(
      [{ id: 'writerW1', declared_write_set: 'shared.js' }],
      [{ id: 'writerW2', kind: 'write' }], // a live writer forces the >=2-id --parallel-safe call
      planPath, crashedShell, false, null
    );
    assert(crashed.chosen.length === 0,
      'T599-1a: a validator subprocess crash excludes EVERY candidate (no speculative open), got ' + JSON.stringify(crashed));
    assert(crashed.excluded.join(',') === 'writerW1',
      'T599-1a: the crash-excluded candidate is named in excluded, got ' + JSON.stringify(crashed.excluded));

    // (b) unparseable-JSON shape: exitCode 0 but no `result`/`overlapping` field survived parsing
    // (shellNode's safeJsonParse returns {} when no line parses as an object).
    const garbledShell = () => ({ exitCode: 0 });
    const garbled = node596.selectSpeculativeWriteGroup(
      [{ id: 'writerW1', declared_write_set: 'shared.js' }],
      [{ id: 'writerW2', kind: 'write' }],
      planPath, garbledShell, false, null
    );
    assert(garbled.chosen.length === 0,
      'T599-1b: an unparseable-JSON validator result excludes EVERY candidate too, got ' + JSON.stringify(garbled));

    // (c) well-formed non-ok WITH an `overlapping` array (even empty) keeps the EXISTING per-pair
    // exclusion behavior — this is NOT a malformed result, so it must not be swept into the new
    // exclude-everything branch.
    const wellFormedShell = () => ({ exitCode: 1, result: 'refuse', overlapping: [] });
    const wellFormed = node596.selectSpeculativeWriteGroup(
      [{ id: 'writerW1', declared_write_set: 'shared.js' }],
      [{ id: 'writerW2', kind: 'write' }],
      planPath, wellFormedShell, false, null
    );
    assert(wellFormed.chosen.length === 1 && wellFormed.chosen[0].id === 'writerW1' && wellFormed.excluded.length === 0,
      'T599-1c: a well-formed non-ok result with an EMPTY overlapping array keeps the existing per-pair posture (nothing excluded), got ' + JSON.stringify(wellFormed));
  }

  // =========================================================================
  // #597 — the `auto` tier + default flip (WRITE-side pieces; the READ-side AC2/AC5 tests live in the
  // #439 block where the read fixtures are). open-ready acts on the speculative set at `auto`; every #596
  // safety condition holds identically at auto; the O1 relabel separates a crash/garbled non-open from a
  // genuine live-writer overlap.
  // =========================================================================

  // T597-3 (AC4 — a #596 safety condition holds IDENTICALLY at auto): the leg-capability precondition
  // (KAOLA_PARALLEL_WRITES=0) excludes the speculative WRITE member at auto EXACTLY as at consent (T596-6)
  // — auto relaxes the ceremony, never a safety condition. Asserted at BOTH policies for parity.
  {
    for (const policy of ['auto', 'consent']) {
      const { repoRoot, planPath, project } = make596Repo(policy);
      openGate1_596(repoRoot);
      const flag = policy === 'consent' ? ['--speculative-consent'] : [];
      const r = run596(repoRoot, ['open-ready', '--project', project, ...flag, '--json'], { KAOLA_PARALLEL_WRITES: '0' });
      assert(r.result === 'ok' && (r.opened || []).length === 0,
        'T597-3 (AC4, ' + policy + '): no write opens without leg capability, got ' + JSON.stringify(r.opened));
      assert(r.speculativeWriteExcluded && r.speculativeWriteExcluded.reason === 'no_leg_capability' && (r.speculativeWriteExcluded.nodeIds || []).includes('writerW'),
        'T597-3 (AC4, ' + policy + '): speculativeWriteExcluded names no_leg_capability — identical at auto and consent, got ' + JSON.stringify(r.speculativeWriteExcluded));
      assert(ledgerStatus596(planPath, 'writerW') === 'pending', 'T597-3 (AC4, ' + policy + '): writerW ledger row untouched');
      rm596(repoRoot);
    }
  }

  // T597-3b (AC2 — WRITE speculation at auto opens WITH NO flag): the SAME #596 write fixture at policy
  // auto opens writerW in a provisioned leg with NO --speculative-consent (mirror of T596-1 flagless).
  {
    const { repoRoot, cacheDir, project } = make596Repo('auto');
    openGate1_596(repoRoot);
    const r = run596(repoRoot, ['open-ready', '--project', project, '--json']); // NO --speculative-consent
    assert(r.result === 'ok' && (r.opened || []).some(n => n.id === 'writerW'),
      'T597-3b (AC2 write): open-ready at policy:auto opens writerW with NO consent flag, got ' + JSON.stringify((r.opened || []).map(n => n.id)));
    const rs = readRS596(cacheDir);
    const wEntry = rs && (rs.nodes || []).find(n => n.id === 'writerW');
    assert(wEntry && wEntry.speculative === true && wEntry.kind === 'write', 'T597-3b (AC2 write): writerW entry is speculative:true kind:write at auto');
    rm596(repoRoot);
  }

  // T597-5 (O1 — the fail-closed exclude-all branch gets a DISTINCT reason): selectSpeculativeWriteGroup
  // labels a crash/garbled non-open `parallel_safe_indeterminate` (the disjointness verdict is unknown),
  // while a genuine per-pair overlap keeps `overlaps_live_writer`. Direct unit test via the injectable
  // shell seam (mirrors T599-1).
  {
    const { planPath } = make596PairRepo('shared.js', 'shared.js');
    const twoCand = [{ id: 'writerW1', declared_write_set: 'shared.js' }];
    const liveWriter = [{ id: 'writerW2', kind: 'write' }];

    const crashed = node596.selectSpeculativeWriteGroup(twoCand, liveWriter, planPath, () => ({ exitCode: 1 }), false, null);
    assert(crashed.excluded.length > 0 && crashed.excludedReason === 'parallel_safe_indeterminate',
      'T597-5 (O1): a validator crash yields excludedReason parallel_safe_indeterminate, got ' + JSON.stringify(crashed));

    const garbled = node596.selectSpeculativeWriteGroup(twoCand, liveWriter, planPath, () => ({ exitCode: 0 }), false, null);
    assert(garbled.excludedReason === 'parallel_safe_indeterminate',
      'T597-5 (O1): a garbled/unparseable validator result is also parallel_safe_indeterminate, got ' + JSON.stringify(garbled));

    // Genuine per-pair overlap (well-formed non-ok naming the pair) keeps the overlaps_live_writer reason.
    const overlapShell = () => ({ exitCode: 1, result: 'refuse', overlapping: [{ a: 'writerW1', b: 'writerW2' }] });
    const overlap = node596.selectSpeculativeWriteGroup(twoCand, liveWriter, planPath, overlapShell, false, null);
    assert(overlap.excluded.join(',') === 'writerW1' && overlap.excludedReason === 'overlaps_live_writer',
      'T597-5 (O1): a genuine per-pair overlap keeps overlaps_live_writer, got ' + JSON.stringify(overlap));
  }

  // T615-SPEC-DIRTY-DEGRADE (D-615-01) — the SPECULATIVE-write mirror of #615-MIXED-SERIAL-LANE-DEGRADE.
  //   The non-speculative co-open already gates lane-group formation on parent cleanliness; the
  //   speculative-write arm (a write betting on an OPEN ancestor gate) forms a size-1 legged lane_group
  //   TOO, so its last-member close runs the IDENTICAL commit-based group barrier + parent-clean fence and
  //   must carry the SAME precondition. Fixture: writerA(complete, its declared production file a.js left
  //   UNCOMMITTED in the parent — the finalize-owned-commit serial-accumulation dirt) -> gate1 (the live
  //   ancestor bet) -> writerW(write). At speculative_open_policy:auto, open-ready with NO
  //   --speculative-consent would (pre-fix) open writerW in a provisioned leg over that dirt, whose
  //   last-member close is the two-horned deadlock (Horn A --parent-clean-check refuses parent_dirty on
  //   a.js; Horn B committing a.js → write_set_overflow at the commit-based group barrier).
  //   RED (pre-fix): writerW opens with a lane_group / group_id.
  //   GREEN (post-fix): writerW is EXCLUDED from this open — opened is empty, speculativeWriteExcluded
  //     names parent_dirty, NO lane_group forms, and writerW's ledger row stays pending (it waits for gate1
  //     normally, exactly like the non-speculative serial-degrade).
  //   Falsification: T597-3b (clean parent, same shape) STILL opens writerW at auto — the exclusion bites
  //     ONLY the dirty-parent speculative shape, never a clean-parent speculative open.
  {
    // make596Repo commits a.js; here writerA's production file must be left UNCOMMITTED, so build the same
    // shape inline and leave a.js dirty AFTER the init commit (mirrors #615-MIXED-SERIAL-LANE-DEGRADE).
    function make615SpecRepo() {
      const repoRoot = fs.mkdtempSync(path.join(os.tmpdir(), 'kw-615spec-'));
      const projDir = path.join(repoRoot, 'kaola-workflow', PROJECT_596);
      const cacheDir = path.join(projDir, '.cache');
      fs.mkdirSync(cacheDir, { recursive: true });
      const planPath = path.join(projDir, 'workflow-plan.md');
      const plan = [
        '# Workflow Plan — issue-596 (615-spec)', '',
        '## Meta', 'labels: area:scripts', 'sink: CHANGELOG.md', 'speculative_open_policy: auto', '',
        '## Nodes', '',
        '| id | role | depends_on | declared_write_set | cardinality | shape |',
        '| --- | --- | --- | --- | --- | --- |',
        '| writerA | tdd-guide     | —       | a.js         | 1 | sequence |',
        '| gate1   | code-reviewer | writerA | —            | 1 | sequence |',
        '| writerW | tdd-guide     | gate1   | w.js         | 1 | sequence |',
        '| gate2   | code-reviewer | writerW | —            | 1 | sequence |',
        '| sink    | finalize      | gate2   | CHANGELOG.md | 1 | sequence |', '',
        '## Node Ledger', '',
        '| id | status |', '| --- | --- |',
        '| writerA | complete |', '| gate1 | pending |', '| writerW | pending |', '| gate2 | pending |', '| sink | pending |', '',
      ].join('\n') + '\n';
      fs.writeFileSync(planPath, plan);
      fs.writeFileSync(path.join(projDir, 'workflow-state.md'), '# State\n');
      const g = (a) => execFileSync('git', ['-C', repoRoot, ...a], { encoding: 'utf8', stdio: ['ignore', 'ignore', 'ignore'] });
      g(['init']); g(['config', 'user.email', 'kw@test']); g(['config', 'user.name', 'kw']); g(['config', 'commit.gpgsign', 'false']);
      try { execFileSync('node', [VALIDATOR_596, planPath, '--freeze', '--repair', '--json'], { cwd: repoRoot, encoding: 'utf8' }); } catch (_) {}
      fs.writeFileSync(path.join(repoRoot, '.gitignore'), '.kw/\n');
      g(['add', '-A']); g(['commit', '-m', 'init']);
      // writerA ran and produced a.js, but serial nodes never commit (finalize-owned-commit contract) —
      // leave it UNCOMMITTED in the parent worktree: the out-of-allowband production dirt the fence catches.
      fs.writeFileSync(path.join(repoRoot, 'a.js'), '// uncommitted production from writerA\n');
      return { repoRoot, cacheDir, planPath, project: PROJECT_596 };
    }

    const { repoRoot, cacheDir, planPath, project } = make615SpecRepo();
    openGate1_596(repoRoot, project); // opens gate1 read-only (no parent-clean-check on a read open)
    // GREEN assertion (FAILS pre-fix = the RED signature, PASSES post-fix).
    const r = run596(repoRoot, ['open-ready', '--project', project, '--json']); // policy auto ⇒ NO --speculative-consent
    assert(r.result === 'ok', 'T615-SPEC: open-ready ok, got ' + JSON.stringify(r));
    assert(!(r.opened || []).some(n => n.id === 'writerW'),
      'T615-SPEC: a speculative write over a parent carrying uncommitted production dirt MUST NOT open (its size-1 lane group would deadlock at the last-member close) — expected exclusion, got opened ' + JSON.stringify((r.opened || []).map(n => n.id)));
    assert(!r.laneGroup,
      'T615-SPEC: NO lane_group descriptor forms on the dirty-parent speculative degrade, got ' + JSON.stringify(r.laneGroup));
    assert(r.speculativeWriteExcluded && r.speculativeWriteExcluded.reason === 'parent_dirty' && (r.speculativeWriteExcluded.nodeIds || []).includes('writerW'),
      'T615-SPEC: speculativeWriteExcluded names parent_dirty for writerW, got ' + JSON.stringify(r.speculativeWriteExcluded));
    const rs = readRS596(cacheDir);
    assert(!rs || !rs.lane_group,
      'T615-SPEC: running-set.json carries NO lane_group key on the degrade, got ' + JSON.stringify(rs && rs.lane_group));
    assert(ledgerStatus596(planPath, 'writerW') === 'pending',
      'T615-SPEC: writerW ledger row stays pending (waits for gate1 normally), got ' + ledgerStatus596(planPath, 'writerW'));
    rm596(repoRoot);
  }
}

// ===========================================================================
// #472 (dispatch fidelity): open-next does NOT silently single-open an INDEPENDENT ≥2 frontier — it
// signals enterBatch so the skeleton routes to a concurrent ONE-MESSAGE dispatch; a width-1 frontier
// stays serial (width is the planner's call — no forced minimum). deriveMaxSimultaneousOpen proves
// everConcurrent from the durable opened/closed telemetry.
// ===========================================================================
{
  // T472-DIVERT: auto-pick open-next at a ≥2 independent read frontier → enterBatch (no single-open).
  {
    let planContent = makePlan(['| a | pending | |', '| b | pending | |', '| review | pending | |', '| finalize | pending | |']);
    const shellStub = (sp, a) => {
      const base = path.basename(sp);
      if (base === 'kaola-workflow-plan-validator.js' && (a || []).includes('--resume-check')) return { exitCode: 0, ok: true };
      if (base === 'kaola-workflow-next-action.js') return {
        exitCode: 0, result: 'ok',
        readySet: [{ id: 'a', role: 'code-explorer', model: 'sonnet', declared_write_set: '—', dependsOn: [] }, { id: 'b', role: 'code-explorer', model: 'sonnet', declared_write_set: '—', dependsOn: [] }],
        readyPending: [{ id: 'a', role: 'code-explorer', model: 'sonnet', declared_write_set: '—' }, { id: 'b', role: 'code-explorer', model: 'sonnet', declared_write_set: '—' }],
        nextNode: { id: 'a', role: 'code-explorer', model: 'sonnet', declared_write_set: '—' }, allDone: false,
      };
      return { exitCode: 1 };
    };
    const r = runOpenNext({ planPath: '/fake/kaola-workflow/test-project/workflow-plan.md', statePath: '/fake/kaola-workflow/test-project/workflow-state.md', project: 'test-project', nodeId: null, shell: shellStub, readFile: (f) => f.endsWith('workflow-plan.md') ? planContent : makeState(), writeFile: (f, c) => { if (f.endsWith('workflow-plan.md')) planContent = c; } });
    assert(r.result === 'ok' && r.enterBatch === true, 'T472-DIVERT: open-next at a ≥2 independent frontier signals enterBatch, got ' + JSON.stringify(r));
    assert(r.opened === null, 'T472-DIVERT: open-next does NOT single-open a ≥2 frontier (opened:null)');
    assert(Array.isArray(r.frontier) && r.frontier.map(n => n.id).sort().join(',') === 'a,b', 'T472-DIVERT: frontier carries both authored nodes, got ' + JSON.stringify(r.frontier));
    assert(!planContent.includes('| a | in_progress'), 'T472-DIVERT: NO ledger row was flipped (zero single-open mutation)');
  }
  // T472-SERIAL: width-1 frontier → open-next single-opens serially (no enterBatch — no forced width).
  {
    let planContent = makePlan(['| solo | pending | |', '| review | pending | |', '| finalize | pending | |']);
    const shellStub = (sp, a) => {
      const base = path.basename(sp);
      if (base === 'kaola-workflow-plan-validator.js' && (a || []).includes('--resume-check')) return { exitCode: 0, ok: true };
      if (base === 'kaola-workflow-next-action.js') return { exitCode: 0, result: 'ok', readySet: [{ id: 'solo', role: 'tdd-guide', model: 'sonnet', declared_write_set: 'a.js', dependsOn: [] }], readyPending: [{ id: 'solo', role: 'tdd-guide', model: 'sonnet', declared_write_set: 'a.js' }], nextNode: { id: 'solo', role: 'tdd-guide', model: 'sonnet', declared_write_set: 'a.js' }, allDone: false };
      if (base === 'kaola-workflow-commit-node.js') return { exitCode: 0, result: 'ok', mode: 'per-node-start', nodeId: 'solo', overallOk: true };
      if (base === 'kaola-workflow-task-mirror.js') return { exitCode: 0, status: 'ok' };
      return { exitCode: 1 };
    };
    const r = runOpenNext({ planPath: '/fake/kaola-workflow/test-project/workflow-plan.md', statePath: '/fake/kaola-workflow/test-project/workflow-state.md', project: 'test-project', nodeId: null, shell: shellStub, readFile: (f) => f.endsWith('workflow-plan.md') ? planContent : makeState(), writeFile: (f, c) => { if (f.endsWith('workflow-plan.md')) planContent = c; } });
    assert(r.result === 'ok' && !r.enterBatch, 'T472-SERIAL: width-1 frontier does NOT enterBatch (no forced width), got ' + JSON.stringify(r));
    assert(r.opened && r.opened.id === 'solo', 'T472-SERIAL: width-1 single-opens serially, got ' + JSON.stringify(r.opened));
  }
  // T472-NODEID: an explicit --node-id at a ≥2 frontier is EXEMPT (the operator asked for one node).
  {
    let planContent = makePlan(['| a | pending | |', '| b | pending | |', '| review | pending | |', '| finalize | pending | |']);
    const shellStub = (sp, a) => {
      const base = path.basename(sp);
      if (base === 'kaola-workflow-plan-validator.js' && (a || []).includes('--resume-check')) return { exitCode: 0, ok: true };
      if (base === 'kaola-workflow-next-action.js') return { exitCode: 0, result: 'ok', readySet: [{ id: 'a', role: 'code-explorer', model: 'sonnet', declared_write_set: '—', dependsOn: [] }, { id: 'b', role: 'code-explorer', model: 'sonnet', declared_write_set: '—', dependsOn: [] }], readyPending: [{ id: 'a' }, { id: 'b' }], nextNode: { id: 'a' }, allDone: false };
      if (base === 'kaola-workflow-commit-node.js') return { exitCode: 0, result: 'ok', mode: 'per-node-start', nodeId: 'a', overallOk: true };
      if (base === 'kaola-workflow-task-mirror.js') return { exitCode: 0, status: 'ok' };
      return { exitCode: 1 };
    };
    const r = runOpenNext({ planPath: '/fake/kaola-workflow/test-project/workflow-plan.md', statePath: '/fake/kaola-workflow/test-project/workflow-state.md', project: 'test-project', nodeId: 'a', shell: shellStub, readFile: (f) => f.endsWith('workflow-plan.md') ? planContent : makeState(), writeFile: (f, c) => { if (f.endsWith('workflow-plan.md')) planContent = c; } });
    assert(r.result === 'ok' && !r.enterBatch && r.opened && r.opened.id === 'a', 'T472-NODEID: explicit --node-id single-opens (exempt from the divert), got ' + JSON.stringify(r));
  }
  // T472-TELEMETRY: deriveMaxSimultaneousOpen proves everConcurrent from the durable opened/closed events.
  {
    const concurrent = [
      JSON.stringify({ node: 'a', event: 'opened', ts: '2026-06-14T10:00:00.000Z' }),
      JSON.stringify({ node: 'b', event: 'opened', ts: '2026-06-14T10:00:01.000Z' }),
      JSON.stringify({ node: 'a', event: 'closed', ts: '2026-06-14T10:00:05.000Z' }),
      JSON.stringify({ node: 'b', event: 'closed', ts: '2026-06-14T10:00:06.000Z' }),
    ].join('\n') + '\n';
    const dc = deriveMaxSimultaneousOpen(concurrent);
    assert(dc.maxSimultaneousOpen === 2 && dc.everConcurrent === true, 'T472-TELEMETRY: overlapping opens → max 2 + everConcurrent true, got ' + JSON.stringify(dc));
    const serial = [
      JSON.stringify({ node: 'a', event: 'opened', ts: '2026-06-14T10:00:00.000Z' }),
      JSON.stringify({ node: 'a', event: 'closed', ts: '2026-06-14T10:00:01.000Z' }),
      JSON.stringify({ node: 'b', event: 'opened', ts: '2026-06-14T10:00:02.000Z' }),
      JSON.stringify({ node: 'b', event: 'closed', ts: '2026-06-14T10:00:03.000Z' }),
    ].join('\n') + '\n';
    const ds = deriveMaxSimultaneousOpen(serial);
    assert(ds.maxSimultaneousOpen === 1 && ds.everConcurrent === false, 'T472-TELEMETRY: serial opens → max 1 + everConcurrent false (the 100%-serial signature), got ' + JSON.stringify(ds));
    const handoff = [
      JSON.stringify({ node: 'a', event: 'opened', ts: '2026-06-14T10:00:00.000Z' }),
      JSON.stringify({ node: 'a', event: 'closed', ts: '2026-06-14T10:00:01.000Z' }),
      JSON.stringify({ node: 'b', event: 'opened', ts: '2026-06-14T10:00:01.000Z' }),
      JSON.stringify({ node: 'b', event: 'closed', ts: '2026-06-14T10:00:02.000Z' }),
    ].join('\n') + '\n';
    assert(deriveMaxSimultaneousOpen(handoff).everConcurrent === false, 'T472-TELEMETRY: same-ts close→open hand-off is NOT counted as concurrent (conservative)');
    // SPOOF guard: a crash-resume re-open of ONE node (two `opened`, no intervening `closed` — appendNode-
    // Timing appends unconditionally) must NOT inflate to everConcurrent (distinct-node-id tracking).
    const dupOpen = [
      JSON.stringify({ node: 'a', event: 'opened', ts: '2026-06-14T10:00:00.000Z' }),
      JSON.stringify({ node: 'a', event: 'opened', ts: '2026-06-14T10:00:02.000Z' }),
      JSON.stringify({ node: 'a', event: 'closed', ts: '2026-06-14T10:00:05.000Z' }),
    ].join('\n') + '\n';
    const dd = deriveMaxSimultaneousOpen(dupOpen);
    assert(dd.maxSimultaneousOpen === 1 && dd.everConcurrent === false, 'T472-TELEMETRY: a single-node re-open does NOT spoof everConcurrent (distinct node-ids), got ' + JSON.stringify(dd));
    // Genuine 3-wide concurrency (incl. a never-closed node) is still counted.
    const wide = [
      JSON.stringify({ node: 'a', event: 'opened', ts: '2026-06-14T10:00:00.000Z' }),
      JSON.stringify({ node: 'b', event: 'opened', ts: '2026-06-14T10:00:01.000Z' }),
      JSON.stringify({ node: 'c', event: 'opened', ts: '2026-06-14T10:00:02.000Z' }),
    ].join('\n') + '\n';
    assert(deriveMaxSimultaneousOpen(wide).maxSimultaneousOpen === 3, 'T472-TELEMETRY: 3 distinct concurrent opens (none closed) → max 3');
  }
}

// ---------------------------------------------------------------------------
// #558: runOrient SURFACES dispatchFidelity (everConcurrent / maxSimultaneousOpen) from the durable
// node-timings.jsonl on a real run — so a regression to silent serialization auto-alarms (the #472
// close-criterion), not only via a hand-run probe. Additive field + fail-closed (absent telemetry →
// zeroed trace, never a refuse — telemetry must never block a lifecycle transition).
// ---------------------------------------------------------------------------
{
  const plan = makePlan([
    '| impl-core | complete | |',
    '| impl-other | complete | |',
    '| review | complete | |',
    '| finalize | complete | |',
  ]);
  const state = makeState();
  const shellStub = function(scriptPath) {
    const base = path.basename(scriptPath);
    if (base === 'kaola-workflow-plan-validator.js') return { exitCode: 0, ok: true };
    if (base === 'kaola-workflow-next-action.js') return { exitCode: 0, result: 'ok', readySet: [], nextNode: null, allDone: true };
    return { exitCode: 1 };
  };
  const orientWithTimings = (timings) => runOrient({
    planPath: '/fake/kaola-workflow/test-project/workflow-plan.md',
    statePath: '/fake/kaola-workflow/test-project/workflow-state.md',
    project: 'test-project',
    shell: shellStub,
    readFile: (fpath) => {
      if (fpath.endsWith('workflow-plan.md')) return plan;
      if (fpath.endsWith('workflow-state.md')) return state;
      if (fpath.endsWith('node-timings.jsonl')) { if (timings == null) throw new Error('ENOENT'); return timings; }
      throw new Error('ENOENT: ' + fpath);
    },
    writeFile: () => { throw new Error('orient must not write'); },
    cacheExists: () => false,
  });
  const concurrent = [
    JSON.stringify({ node: 'a', event: 'opened', ts: '2026-06-14T10:00:00.000Z' }),
    JSON.stringify({ node: 'b', event: 'opened', ts: '2026-06-14T10:00:01.000Z' }),
    JSON.stringify({ node: 'a', event: 'closed', ts: '2026-06-14T10:00:05.000Z' }),
    JSON.stringify({ node: 'b', event: 'closed', ts: '2026-06-14T10:00:06.000Z' }),
  ].join('\n') + '\n';
  const rc = orientWithTimings(concurrent);
  assert(rc.result === 'ok' && rc.dispatchFidelity && rc.dispatchFidelity.everConcurrent === true && rc.dispatchFidelity.maxSimultaneousOpen === 2,
    '#558: runOrient surfaces dispatchFidelity {everConcurrent:true,max:2} from overlapping node-timings, got ' + JSON.stringify(rc.dispatchFidelity));
  const serial = [
    JSON.stringify({ node: 'a', event: 'opened', ts: '2026-06-14T10:00:00.000Z' }),
    JSON.stringify({ node: 'a', event: 'closed', ts: '2026-06-14T10:00:01.000Z' }),
    JSON.stringify({ node: 'b', event: 'opened', ts: '2026-06-14T10:00:02.000Z' }),
    JSON.stringify({ node: 'b', event: 'closed', ts: '2026-06-14T10:00:03.000Z' }),
  ].join('\n') + '\n';
  const rs = orientWithTimings(serial);
  assert(rs.dispatchFidelity && rs.dispatchFidelity.everConcurrent === false && rs.dispatchFidelity.maxSimultaneousOpen === 1,
    '#558: serial node-timings → dispatchFidelity everConcurrent false / max 1, got ' + JSON.stringify(rs.dispatchFidelity));
  const ra = orientWithTimings(null);
  assert(ra.result === 'ok' && ra.dispatchFidelity && ra.dispatchFidelity.everConcurrent === false && ra.dispatchFidelity.maxSimultaneousOpen === 0,
    '#558: absent node-timings → zeroed dispatchFidelity, orient still ok (telemetry never blocks), got ' + JSON.stringify(ra.dispatchFidelity));
}

// ===========================================================================
// #590 — serial open-next records the per-node baseline BEFORE flipping the ledger
// row (mirroring runOpenReady Phase 2 baseline-on-disk → Phase 3 single plan write).
// Direct-call tests over runOpenNext's injected seams. RED (pre-#590 write-first order):
// a baseline failure strands the row in_progress with no baseline on disk (a later close
// dead-ends baseline_missing). GREEN (baseline-first): a baseline failure leaves the ledger
// PENDING — a clean idempotent re-open, no in_progress-without-baseline state.
// ===========================================================================
{
  // -- T-590-order-fail: baseline FAILS → NO ledger flip write; refuse baseline_failed; row pending. --
  {
    const plan = makePlan([
      '| impl-core | pending | |',
      '| impl-other | pending | |',
      '| review | pending | |',
      '| finalize | pending | |',
    ]);
    let planContent = plan;
    let sawPlanWrite = false;
    let baselineInvoked = false;
    let baselineSawWriteAtInvoke = null;
    const shellStub = function (scriptPath, args) {
      const base = path.basename(scriptPath);
      const a = args || [];
      if (base === 'kaola-workflow-plan-validator.js' && a.includes('--resume-check')) return { exitCode: 0, ok: true };
      if (base === 'kaola-workflow-next-action.js') {
        return {
          exitCode: 0, result: 'ok', allDone: false,
          readySet: [{ id: 'impl-core', role: 'tdd-guide', model: 'sonnet', declared_write_set: 'scripts/adaptive-node.js', dependsOn: [] }],
          nextNode: { id: 'impl-core', role: 'tdd-guide', model: 'sonnet', declared_write_set: 'scripts/adaptive-node.js' },
        };
      }
      if (base === 'kaola-workflow-commit-node.js' && a.includes('--start')) {
        baselineInvoked = true;
        baselineSawWriteAtInvoke = sawPlanWrite; // ordering probe: was the plan already written when baseline ran?
        return { exitCode: 1, result: 'refuse', reason: 'baseline_missing', errors: ['stub baseline failure'] };
      }
      return { exitCode: 1, result: 'refuse' };
    };
    const result = runOpenNext({
      planPath: '/fake/kaola-workflow/test-project/workflow-plan.md',
      statePath: '/fake/kaola-workflow/test-project/workflow-state.md',
      project: 'test-project', nodeId: null, shell: shellStub,
      readFile: (fp) => { if (fp.endsWith('workflow-plan.md')) return planContent; return makeState(); },
      writeFile: (fp, content) => { if (fp.endsWith('workflow-plan.md')) { sawPlanWrite = true; planContent = content; } },
    });
    assert(result.result === 'refuse' && result.reason === 'baseline_failed',
      'T-590-order-fail: baseline failure → refuse baseline_failed, got ' + JSON.stringify({ result: result.result, reason: result.reason }));
    assert(baselineInvoked === true, 'T-590-order-fail: commit-node --start was invoked');
    assert(baselineSawWriteAtInvoke === false,
      'T-590-order-fail: baseline recorded BEFORE any ledger flip write (baseline-first ordering)');
    assert(sawPlanWrite === false,
      'T-590-order-fail: NO ledger flip write on baseline failure — row never stranded in_progress-without-baseline');
    assert(!/\|\s*impl-core\s*\|\s*in_progress\s*\|/.test(planContent),
      'T-590-order-fail: ledger row still pending after the refuse');
  }

  // -- T-590-order-ok: baseline SUCCEEDS → baseline recorded BEFORE the ledger flip; row ends in_progress. --
  {
    const plan = makePlan([
      '| impl-core | pending | |',
      '| impl-other | pending | |',
      '| review | pending | |',
      '| finalize | pending | |',
    ]);
    let planContent = plan;
    let sawPlanWrite = false;
    let baselineSawWriteAtInvoke = null;
    const shellStub = function (scriptPath, args) {
      const base = path.basename(scriptPath);
      const a = args || [];
      if (base === 'kaola-workflow-plan-validator.js' && a.includes('--resume-check')) return { exitCode: 0, ok: true };
      if (base === 'kaola-workflow-next-action.js') {
        return {
          exitCode: 0, result: 'ok', allDone: false,
          readySet: [{ id: 'impl-core', role: 'tdd-guide', model: 'sonnet', declared_write_set: 'scripts/adaptive-node.js', dependsOn: [] }],
          nextNode: { id: 'impl-core', role: 'tdd-guide', model: 'sonnet', declared_write_set: 'scripts/adaptive-node.js' },
        };
      }
      if (base === 'kaola-workflow-commit-node.js' && a.includes('--start')) {
        baselineSawWriteAtInvoke = sawPlanWrite;
        return { exitCode: 0, result: 'ok', mode: 'per-node-start', nodeId: 'impl-core', overallOk: true, recordBase: { base: 'deadbeefcafe0000', reused: false } };
      }
      return { exitCode: 1, result: 'refuse' };
    };
    const result = runOpenNext({
      planPath: '/fake/kaola-workflow/test-project/workflow-plan.md',
      statePath: '/fake/kaola-workflow/test-project/workflow-state.md',
      project: 'test-project', nodeId: null, shell: shellStub,
      readFile: (fp) => { if (fp.endsWith('workflow-plan.md')) return planContent; return makeState(); },
      writeFile: (fp, content) => { if (fp.endsWith('workflow-plan.md')) { sawPlanWrite = true; planContent = content; } },
    });
    assert(result.result === 'ok' && result.baselineRecorded === true,
      'T-590-order-ok: baseline success → open ok, got ' + JSON.stringify({ result: result.result, baselineRecorded: result.baselineRecorded }));
    assert(baselineSawWriteAtInvoke === false,
      'T-590-order-ok: baseline recorded BEFORE the ledger flip write (baseline-first)');
    assert(sawPlanWrite === true && /\|\s*impl-core\s*\|\s*in_progress\s*\|/.test(planContent),
      'T-590-order-ok: ledger flipped in_progress AFTER the baseline');
  }
}

// ===========================================================================
// #621 — the #590 baseline-first ordering was applied to runOpenNext but NOT mirrored in
// runCloseAndOpenNext's FUSED ADVANCE (the ledger flip for the NEXT node ran BEFORE its
// baseline was recorded) nor in runReopenNode (the reopen flip ran BEFORE its fresh baseline).
// RED (pre-#621 order in each): a baseline failure for the newly-opened/reopened node still
// left it in_progress with NO baseline on disk. GREEN (baseline-first, mirroring #590): a
// baseline failure leaves that row PENDING — a clean re-open/retry, never an
// in_progress-without-baseline strand.
// ===========================================================================
{
  // -- T-621-fused-fail: fused advance — baseline FAILS for the NEXT node → NO ledger flip
  //    write for it; refuse baseline_failed; the CLOSE half (impl-core→complete) is preserved. --
  {
    const plan = makePlan([
      '| impl-core | in_progress | |',
      '| impl-other | pending | |',
      '| review | pending | |',
      '| finalize | pending | |',
    ]);
    const cacheFiles = {
      '/fake/kaola-workflow/test-project/.cache/impl-core.md':
        'RED: test failed as expected\nGREEN: test passed after implementation\n5 assertions',
    };
    let planContent = plan;
    const shellStub = function (scriptPath, args) {
      const base = path.basename(scriptPath);
      const argsArr = args || [];
      if (base === 'kaola-workflow-commit-node.js' && !argsArr.includes('--start')) {
        return { exitCode: 0, result: 'ok', mode: 'per-node', nodeId: 'impl-core', overallOk: true, selectorCheck: { isSelector: false, ok: true }, barrierCheck: { exitCode: 0, result: 'pass' } };
      }
      if (base === 'kaola-workflow-commit-node.js' && argsArr.includes('--start')) {
        return { exitCode: 1, result: 'refuse', reason: 'baseline_missing', errors: ['stub baseline failure'] };
      }
      if (base === 'kaola-workflow-next-action.js') {
        return {
          exitCode: 0, result: 'ok', allDone: false,
          readySet: [{ id: 'impl-other', role: 'implementer', model: 'sonnet', declared_write_set: 'scripts/other.js', dependsOn: ['impl-core'] }],
          nextNode: { id: 'impl-other', role: 'implementer', model: 'sonnet', declared_write_set: 'scripts/other.js' },
        };
      }
      return { exitCode: 1, result: 'refuse' };
    };
    const result = runCloseAndOpenNext({
      planPath: '/fake/kaola-workflow/test-project/workflow-plan.md',
      statePath: '/fake/kaola-workflow/test-project/workflow-state.md',
      project: 'test-project', nodeId: 'impl-core', shell: shellStub,
      readFile: (fpath) => {
        if (fpath.endsWith('workflow-plan.md')) return planContent;
        if (fpath.endsWith('workflow-state.md')) return makeState();
        if (cacheFiles[fpath]) return cacheFiles[fpath];
        throw new Error('ENOENT: ' + fpath);
      },
      writeFile: (fpath, content) => { if (fpath.endsWith('workflow-plan.md')) planContent = content; },
      cacheExists: (fpath) => !!cacheFiles[fpath],
    });
    assert(result.result === 'refuse' && result.reason === 'baseline_failed',
      'T-621-fused-fail: baseline failure for the NEXT node refuses baseline_failed, got ' + JSON.stringify({ result: result.result, reason: result.reason }));
    assert(/\|\s*impl-core\s*\|\s*complete\s*\|/.test(planContent),
      'T-621-fused-fail: the CLOSE half (impl-core→complete) is preserved despite the OPEN half failing');
    assert(!/\|\s*impl-other\s*\|\s*in_progress\s*\|/.test(planContent),
      'T-621-fused-fail: impl-other never flips in_progress without a recorded baseline');
    assert(/\|\s*impl-other\s*\|\s*pending\s*\|/.test(planContent),
      'T-621-fused-fail: impl-other row left PENDING on the baseline failure — a clean re-open, no in_progress-without-baseline strand');
  }

  // -- T-621-fused-ok: fused advance — baseline recorded BEFORE the impl-other ledger flip write. --
  {
    const plan = makePlan([
      '| impl-core | in_progress | |',
      '| impl-other | pending | |',
      '| review | pending | |',
      '| finalize | pending | |',
    ]);
    const cacheFiles = {
      '/fake/kaola-workflow/test-project/.cache/impl-core.md':
        'RED: test failed as expected\nGREEN: test passed after implementation\n5 assertions',
    };
    let planContent = plan;
    let sawImplOtherWrite = false;
    let baselineSawWriteAtInvoke = null;
    const shellStub = function (scriptPath, args) {
      const base = path.basename(scriptPath);
      const argsArr = args || [];
      if (base === 'kaola-workflow-commit-node.js' && !argsArr.includes('--start')) {
        return { exitCode: 0, result: 'ok', mode: 'per-node', nodeId: 'impl-core', overallOk: true, selectorCheck: { isSelector: false, ok: true }, barrierCheck: { exitCode: 0, result: 'pass' } };
      }
      if (base === 'kaola-workflow-commit-node.js' && argsArr.includes('--start')) {
        baselineSawWriteAtInvoke = sawImplOtherWrite;
        return { exitCode: 0, result: 'ok', mode: 'per-node-start', nodeId: 'impl-other', overallOk: true, recordBase: { base: 'deadbeefcafe0001', reused: false } };
      }
      if (base === 'kaola-workflow-next-action.js') {
        return {
          exitCode: 0, result: 'ok', allDone: false,
          readySet: [{ id: 'impl-other', role: 'implementer', model: 'sonnet', declared_write_set: 'scripts/other.js', dependsOn: ['impl-core'] }],
          nextNode: { id: 'impl-other', role: 'implementer', model: 'sonnet', declared_write_set: 'scripts/other.js' },
        };
      }
      return { exitCode: 1, result: 'refuse' };
    };
    const result = runCloseAndOpenNext({
      planPath: '/fake/kaola-workflow/test-project/workflow-plan.md',
      statePath: '/fake/kaola-workflow/test-project/workflow-state.md',
      project: 'test-project', nodeId: 'impl-core', shell: shellStub,
      readFile: (fpath) => {
        if (fpath.endsWith('workflow-plan.md')) return planContent;
        if (fpath.endsWith('workflow-state.md')) return makeState();
        if (cacheFiles[fpath]) return cacheFiles[fpath];
        throw new Error('ENOENT: ' + fpath);
      },
      writeFile: (fpath, content) => {
        if (fpath.endsWith('workflow-plan.md')) {
          if (/\|\s*impl-other\s*\|\s*in_progress\s*\|/.test(content)) sawImplOtherWrite = true;
          planContent = content;
        }
      },
      cacheExists: (fpath) => !!cacheFiles[fpath],
    });
    assert(result.result === 'ok' && result.opened && result.opened.id === 'impl-other',
      'T-621-fused-ok: baseline success → fused advance opens impl-other, got ' + JSON.stringify(result));
    assert(baselineSawWriteAtInvoke === false,
      'T-621-fused-ok: baseline recorded BEFORE the impl-other in_progress ledger write (baseline-first ordering)');
    assert(/\|\s*impl-other\s*\|\s*in_progress\s*\|/.test(planContent),
      'T-621-fused-ok: impl-other flipped in_progress AFTER the baseline succeeded');
  }

  // -- T-621-reopen: runReopenNode — a baseline failure over the crash window leaves the reopened
  //    node PENDING (gates already folded), and a RETRY over that SAME window succeeds idempotently. --
  {
    const planNodes = [
      '| a | tdd-guide | — | scripts/a.js | 1 | sequence |',
      '| impl | tdd-guide | a | scripts/b.js | 1 | sequence |',
      '| review | code-reviewer | impl | — | 1 | sequence |',
      '| finalize | finalize | review | — | 1 | sequence |',
    ];
    let planContent = makePlan([
      '| a | complete | |', '| impl | complete | |', '| review | complete | |', '| finalize | complete | |',
    ], planNodes);
    const removed = [];
    let baselineSawInProgressAtInvoke = null;
    const shell1 = (scriptPath) => {
      const base = path.basename(scriptPath);
      if (base === 'kaola-workflow-commit-node.js') {
        baselineSawInProgressAtInvoke = /\|\s*impl\s*\|\s*in_progress\s*\|/.test(planContent);
        return { exitCode: 1, result: 'refuse', reason: 'baseline_missing', errors: ['stub baseline failure'] };
      }
      return { exitCode: 0, result: 'ok' }; // --drop-base calls
    };
    const result = runReopenNode({
      planPath: '/fake/kaola-workflow/test-project/workflow-plan.md', project: 'test-project', nodeId: 'impl',
      shell: shell1,
      readFile: (f) => { if (f.endsWith('workflow-plan.md')) return planContent; throw new Error('ENOENT ' + f); },
      writeFile: (f, c) => { if (f.endsWith('workflow-plan.md')) planContent = c; },
      cacheExists: (f) => /barrier-base-/.test(f),
      unlink: (f) => removed.push(path.basename(f)),
    });
    assert(result.result === 'refuse' && result.reason === 'baseline_failed',
      'T-621-reopen: baseline failure refuses baseline_failed, got ' + JSON.stringify(result));
    assert(/\|\s*impl\s*\|\s*pending\s*\|/.test(planContent),
      'T-621-reopen: impl row left PENDING on the baseline failure (never in_progress-without-baseline)');
    assert(/\|\s*review\s*\|\s*pending\s*\|/.test(planContent),
      'T-621-reopen: the post-dominating gate is already folded to pending on disk (the prep-write landed)');
    assert(baselineSawInProgressAtInvoke === false,
      'T-621-reopen: commit-node --start was invoked while impl was STILL pending on disk (baseline-first)');

    // -- RETRY over the SAME crash window: impl is now genuinely 'pending' on disk (gates already
    // folded) — a repeated reopen-node call must succeed idempotently once the baseline stub is fixed,
    // NOT refuse node_not_complete. --
    const shell2 = (scriptPath) => (path.basename(scriptPath) === 'kaola-workflow-commit-node.js'
      ? { exitCode: 0, result: 'ok', recordBase: { base: 'deadbeefcafe0002', reused: false } }
      : { exitCode: 0, result: 'ok' });
    const result2 = runReopenNode({
      planPath: '/fake/kaola-workflow/test-project/workflow-plan.md', project: 'test-project', nodeId: 'impl',
      shell: shell2,
      readFile: (f) => { if (f.endsWith('workflow-plan.md')) return planContent; throw new Error('ENOENT ' + f); },
      writeFile: (f, c) => { if (f.endsWith('workflow-plan.md')) planContent = c; },
      cacheExists: (f) => /barrier-base-/.test(f),
      unlink: (f) => removed.push(path.basename(f)),
    });
    assert(result2.result === 'ok',
      'T-621-reopen: RETRY over the same crash window succeeds idempotently, got ' + JSON.stringify(result2));
    assert(/\|\s*impl\s*\|\s*in_progress\s*\|/.test(planContent),
      'T-621-reopen: retry flips impl in_progress once the baseline succeeds');
  }
}

// ===========================================================================
// #585 — scheduler mutual-exclusion lock. A project-scoped O_EXCL lockfile
// (kaola-workflow/{project}/.cache/scheduler.lock) is acquired at the CLI (main())
// boundary before any mutating scheduler subcommand body, released in a finally. A held
// lock is NEVER taken over: a dead/aged holder refuses scheduler_lock_stale with a
// one-session manual-removal hint (fail-closed — no unlink of another process's lock),
// so a crashed holder never wedges the project. The run*
// bodies stay lock-free (the in-memory rsHarness above never enters main() — so the 1078
// assertions above ARE the serial-path-unchanged regression proof).
// ===========================================================================

// -- T-585-stale (unit): isStaleLock — same-host dead pid → stale; same-host live pid → not stale;
//    cross-host old ts → stale (age fallback); cross-host fresh ts → not stale; corrupt → stale. --
{
  const DEAD_PID = 2147483646; // above any real pid on this box → process.kill(pid,0) throws ESRCH
  assert(isStaleLock({ pid: DEAD_PID, host: os.hostname(), ts: Date.now(), subcommand: 'open-ready' }) === true,
    'T-585-stale: same-host DEAD pid → stale');
  assert(isStaleLock({ pid: process.pid, host: os.hostname(), ts: Date.now(), subcommand: 'open-ready' }) === false,
    'T-585-stale: same-host LIVE pid (this process) → not stale');
  assert(isStaleLock({ pid: 1234, host: 'ghost-host-' + Math.random().toString(16).slice(2), ts: Date.now() - LANE_STALENESS_MS - 60000 }) === true,
    'T-585-stale: cross-host OLD ts → stale (age fallback)');
  assert(isStaleLock({ pid: 1234, host: 'ghost-host-' + Math.random().toString(16).slice(2), ts: Date.now() }) === false,
    'T-585-stale: cross-host FRESH ts → not stale (age fallback)');
  assert(isStaleLock(null) === true, 'T-585-stale: null/corrupt holder → stale');
}

// -- T-585-acquire / T-585-release (unit): O_EXCL claim, live-holder refuse, idempotent release,
//    dead-holder typed STALE refusal — driven directly against a real lockfile under $TMPDIR.
//    NOTE: acquireProjectLock NEVER unlinks another process's lock (an unlink-based takeover
//    double-acquires under concurrency — two takers holding the same stale decision both claim
//    after the other's unlink); a dead holder is CLASSIFIED stale:true and refused. --
{
  const tmp = fs.mkdtempSync(path.join(os.tmpdir(), 'lock585-unit-'));
  const lockPath = path.join(tmp, '.cache', SCHEDULER_LOCK_NAME);
  // (a) clean acquire → ok + file present carrying our payload.
  const a1 = acquireProjectLock(lockPath, { subcommand: 'open-ready' });
  assert(a1.ok === true && typeof a1.release === 'function', 'T-585-acquire: clean O_EXCL claim ok + release closure');
  assert(fs.existsSync(lockPath), 'T-585-acquire: lock file present after acquire');
  const held = JSON.parse(fs.readFileSync(lockPath, 'utf8'));
  assert(held.pid === process.pid && held.subcommand === 'open-ready' && typeof held.host === 'string',
    'T-585-acquire: payload carries pid + subcommand + host');
  // (b) a SECOND acquire while held by a LIVE holder → refuse stale:false with the holder (never double-acquire).
  const a2 = acquireProjectLock(lockPath, { subcommand: 'close-node' });
  assert(a2.ok === false && a2.stale === false && a2.holder && a2.holder.pid === process.pid,
    'T-585-acquire: second acquire refused stale:false by the live holder (no double-acquire)');
  // (c) release removes the file.
  a1.release();
  assert(!fs.existsSync(lockPath), 'T-585-release: release removes the lock file');
  // (d) release is idempotent (no throw when the file is already gone).
  a1.release();
  assert(!fs.existsSync(lockPath), 'T-585-release: second release is a no-op (idempotent)');
  // (e) stale REFUSAL (no auto-takeover): plant a DEAD-pid holder → acquire refuses ok:false + stale:true
  //     and the lockfile payload is byte-untouched (this function never unlinks another process's lock).
  fs.mkdirSync(path.dirname(lockPath), { recursive: true });
  const deadPayload = JSON.stringify({ pid: 2147483646, host: os.hostname(), ts: Date.now(), subcommand: 'open-ready' });
  fs.writeFileSync(lockPath, deadPayload);
  const a3 = acquireProjectLock(lockPath, { subcommand: 'open-ready' });
  assert(a3.ok === false && a3.stale === true, 'T-585-stale-refuse(unit): dead-pid holder → ok:false + stale:true (no auto-takeover)');
  assert(a3.holder && a3.holder.pid === 2147483646, 'T-585-stale-refuse(unit): refusal carries the dead holder payload');
  assert(fs.readFileSync(lockPath, 'utf8') === deadPayload, 'T-585-stale-refuse(unit): the stale lockfile is byte-untouched (never a non-holder unlink)');
  fs.rmSync(tmp, { recursive: true, force: true });
}

// -- T-595-orphan (unit, fault-injection): a payload write that throws right after the O_EXCL create
//    must NOT orphan an empty lockfile. Monkey-patches fs.writeFileSync to fail exactly once (after the
//    real openSync('wx') has already claimed the file) so acquireProjectLock's catch runs with a
//    non-EEXIST error. No-takeover invariant: the unlink this exercises can only ever run inside the
//    SAME call that just created the file via 'wx' (the fault is injected on our own write, not a
//    foreign holder's) — it can never remove another process's lock. --
{
  const tmp = fs.mkdtempSync(path.join(os.tmpdir(), 'lock595-unit-'));
  const lockPath = path.join(tmp, '.cache', SCHEDULER_LOCK_NAME);
  const origWriteFileSync = fs.writeFileSync;
  let injected = false;
  fs.writeFileSync = function (...args) {
    if (!injected) {
      injected = true;
      const err = new Error('T-595 injected fault: simulated disk-full on payload write');
      err.code = 'EFAULTINJECT';
      throw err;
    }
    return origWriteFileSync.apply(fs, args);
  };
  let threw = null;
  try {
    acquireProjectLock(lockPath, { subcommand: 'open-ready' });
  } catch (err) {
    threw = err;
  } finally {
    fs.writeFileSync = origWriteFileSync;
  }
  assert(threw && threw.code === 'EFAULTINJECT', 'T-595-orphan: the injected write failure propagates (non-EEXIST → rethrow)');
  assert(!fs.existsSync(lockPath), 'T-595-orphan: the just-created lockfile is NOT orphaned after a payload-write failure');
  // Follow-up acquire in the SAME process must succeed cleanly — no lingering wrong-flavor scheduler_locked refusal.
  const follow = acquireProjectLock(lockPath, { subcommand: 'open-ready' });
  assert(follow.ok === true, 'T-595-orphan: a follow-up acquireProjectLock succeeds (no orphaned-lockfile refusal)');
  follow.release();
  assert(!fs.existsSync(lockPath), 'T-595-orphan: follow-up release cleans up');
  fs.rmSync(tmp, { recursive: true, force: true });
}

// -- Real-subprocess #585 tests: the lock is enforced in main() (the CLI boundary), so these drive the
//    real adaptive-node CLI in a real $TMPDIR git repo. The read-frontier fixture (ra code-explorer +
//    rb knowledge-lookup → finalize) co-opens as a read fan-out (no legs), giving two closeable
//    in_progress members for the close-node race and a clean pending frontier for the open-ready race. --
{
  const { execFileSync, spawnSync } = require('child_process');
  const NODE_CLI = path.join(__dirname, 'kaola-workflow-adaptive-node.js');
  const VALIDATOR = path.join(__dirname, 'kaola-workflow-plan-validator.js');

  function makeReadFrontierRepo() {
    const repoRoot = fs.mkdtempSync(path.join(os.tmpdir(), 'lock585-repo-'));
    const project = 'test-project';
    const projDir = path.join(repoRoot, 'kaola-workflow', project);
    const cacheDir = path.join(projDir, '.cache');
    fs.mkdirSync(cacheDir, { recursive: true });
    const planPath = path.join(projDir, 'workflow-plan.md');
    const plan = [
      '# Workflow Plan — test-project', '',
      '## Meta', 'labels: area:scripts', 'sink: CHANGELOG.md', '',
      '## Nodes', '',
      '| id | role | depends_on | declared_write_set | cardinality | shape |',
      '| --- | --- | --- | --- | --- | --- |',
      '| ra | code-explorer | — | — | 1 | sequence |',
      '| rb | knowledge-lookup | — | — | 1 | sequence |',
      '| finalize | finalize | ra,rb | — | 1 | sequence |', '',
      '## Node Ledger', '',
      '| id | status |', '| --- | --- |',
      '| ra | pending |', '| rb | pending |', '| finalize | pending |', '',
    ].join('\n') + '\n';
    fs.writeFileSync(planPath, plan);
    fs.writeFileSync(path.join(projDir, 'workflow-state.md'), '# State\n');
    const g = (args) => execFileSync('git', ['-C', repoRoot, ...args], { encoding: 'utf8', stdio: ['ignore', 'ignore', 'ignore'] });
    g(['init']); g(['config', 'user.email', 'kw@test']); g(['config', 'user.name', 'kw']); g(['config', 'commit.gpgsign', 'false']);
    try { execFileSync('node', [VALIDATOR, planPath, '--freeze', '--repair', '--json'], { cwd: repoRoot, encoding: 'utf8' }); } catch (_) {}
    fs.writeFileSync(path.join(repoRoot, '.gitignore'), '.kw/\n');
    g(['add', '-A']); g(['commit', '-m', 'init']);
    return { repoRoot, project, planPath, cacheDir };
  }
  function runNode(repoRoot, subArgs, extraEnv) {
    const env = Object.assign({}, process.env, extraEnv || {});
    try {
      const stdout = execFileSync('node', [NODE_CLI, ...subArgs], { cwd: repoRoot, encoding: 'utf8', env });
      let parsed = {}; try { parsed = JSON.parse(stdout.trim().split('\n').pop()); } catch (_) {}
      return { exitCode: 0, ...parsed };
    } catch (err) {
      const status = (err.status == null) ? 1 : err.status;
      let parsed = {}; try { parsed = JSON.parse(String(err.stdout || '').trim().split('\n').pop()); } catch (_) {}
      return { exitCode: status, ...parsed };
    }
  }
  function writeEvidence(cacheDir, id) {
    return writeLegAwareEvidence(cacheDir, id,
      id === 'rb' ? 'knowledge-lookup' : 'code-explorer');
  }
  function readRS(cacheDir) { try { return JSON.parse(fs.readFileSync(path.join(cacheDir, 'running-set.json'), 'utf8')); } catch (_) { return null; } }
  function ledgerStatuses(planPath) {
    const txt = fs.readFileSync(planPath, 'utf8');
    const start = txt.indexOf('## Node Ledger');
    const body = start >= 0 ? txt.slice(start) : txt;
    const out = {};
    const re = /^\|\s*([A-Za-z0-9_-]+)\s*\|\s*(\S+)\s*\|/gm;
    let m; while ((m = re.exec(body)) !== null) { if (m[1] !== 'id') out[m[1]] = m[2]; }
    return out;
  }
  function inProgressSet(planPath) {
    const st = ledgerStatuses(planPath);
    return new Set(Object.keys(st).filter((k) => st[k] === 'in_progress'));
  }
  function rsNodeSet(cacheDir) {
    const rs = readRS(cacheDir);
    return new Set(rs && Array.isArray(rs.nodes) ? rs.nodes.map((n) => n.id) : []);
  }
  function setsEqual(a, b) { if (a.size !== b.size) return false; for (const x of a) if (!b.has(x)) return false; return true; }
  function cleanup(root) { try { fs.rmSync(root, { recursive: true, force: true }); } catch (_) {} }

  // raceN — a GENUINE N-process interleave. An orchestrator (node -e) spawns ALL N real adaptive-node
  // CLIs via child_process.spawn + Promise.all (concurrency INSIDE the orchestrator), then prints all
  // {code,out} as one JSON line; the parent sync-joins by spawnSync and parses each subprocess's last
  // JSON line. This is the suite's first genuine scheduler race (prior crash-window tests hand-built
  // states between sequential calls). raceTwo is the 2-caller convenience wrapper.
  function raceN(repoRoot, argvs) {
    const orch =
      'const { spawn } = require("child_process");' +
      'function run(a){return new Promise(function(res){var p=spawn(process.execPath,[' + JSON.stringify(NODE_CLI) + '].concat(a),{cwd:' + JSON.stringify(repoRoot) + ',env:process.env});var o="";var e="";p.stdout.on("data",function(d){o+=d});p.stderr.on("data",function(d){e+=d});p.on("close",function(c){res({code:c,out:o})});});}' +
      'Promise.all(' + JSON.stringify(argvs) + '.map(run)).then(function(rs){process.stdout.write("RACE:"+JSON.stringify(rs)+"\\n");});';
    const res = spawnSync(process.execPath, ['-e', orch], { cwd: repoRoot, encoding: 'utf8', env: process.env });
    const line = String(res.stdout || '').split('\n').filter((l) => l.indexOf('RACE:') === 0).pop() || 'RACE:[]';
    let arr = []; try { arr = JSON.parse(line.slice('RACE:'.length)); } catch (_) { arr = []; }
    return arr.map((r) => { let parsed = {}; try { parsed = JSON.parse(String(r.out || '').trim().split('\n').pop()); } catch (_) {} return { code: r.code, ...parsed }; });
  }
  function raceTwo(repoRoot, argv1, argv2) { return raceN(repoRoot, [argv1, argv2]); }

  // -- T-585-live-refuse: a LIVE holder's lock makes a guarded subcommand refuse scheduler_locked with
  //    ZERO mutation. RED: the advisory-only pre-fix CLI ignores the inert lock and co-opens the frontier. --
  {
    const { repoRoot, project, planPath, cacheDir } = makeReadFrontierRepo();
    fs.writeFileSync(path.join(cacheDir, SCHEDULER_LOCK_NAME),
      JSON.stringify({ pid: process.pid, host: os.hostname(), ts: Date.now(), subcommand: 'open-ready' }));
    const r = runNode(repoRoot, ['open-ready', '--project', project, '--json']);
    assert(r.result === 'refuse' && r.reason === 'scheduler_locked',
      'T-585-live-refuse: open-ready refuses scheduler_locked under a live holder, got ' + JSON.stringify({ result: r.result, reason: r.reason }));
    assert(r.exitCode === 1, 'T-585-live-refuse: non-zero exit on contention');
    assert(typeof r.operator_hint === 'string' && r.operator_hint.length > 0, 'T-585-live-refuse: typed operator_hint present');
    assert(fs.existsSync(path.join(cacheDir, SCHEDULER_LOCK_NAME)), 'T-585-live-refuse: the live holder lock is NOT removed by the refused caller');
    const st = ledgerStatuses(planPath);
    assert(st.ra === 'pending' && st.rb === 'pending', 'T-585-live-refuse: ledger unchanged (no in_progress) — zero mutation');
    assert(readRS(cacheDir) === null, 'T-585-live-refuse: no running set written');
    cleanup(repoRoot);
  }

  // record-evidence mutates the same project cache and therefore shares the scheduler lock.
  {
    const { repoRoot, project, cacheDir } = makeReadFrontierRepo();
    fs.writeFileSync(path.join(cacheDir, 'barrier-base-ra'), 'dddddddddddd-rest\n');
    const evidencePath = path.join(cacheDir, 'ra.md');
    const before = fs.existsSync(evidencePath) ? fs.readFileSync(evidencePath, 'utf8') : null;
    fs.writeFileSync(path.join(cacheDir, SCHEDULER_LOCK_NAME),
      JSON.stringify({ pid: process.pid, host: os.hostname(), ts: Date.now(), subcommand: 'open-ready' }));
    const r = runNode(repoRoot, ['record-evidence', '--project', project, '--node-id', 'ra', '--stdin', '--json'], {},
      'evidence-binding: ra dddddddddddd\nverdict: pass\nfindings_blocking: 0\n');
    assert(r.result === 'refuse' && r.reason === 'scheduler_locked',
      'R1-LOCK: record-evidence refuses under a live project-lock holder');
    assert((fs.existsSync(evidencePath) ? fs.readFileSync(evidencePath, 'utf8') : null) === before,
      'R1-LOCK: lock contention leaves evidence bytes unchanged');
    cleanup(repoRoot);
  }

  // -- T-585-stale-refuse: a DEAD-pid holder is NEVER auto-taken-over (an unlink-based takeover
  //    double-acquires under concurrency). The CLI refuses with the DISTINCT typed reason
  //    scheduler_lock_stale, zero mutation, lock byte-intact; the operator_hint names the manual
  //    recovery (rm the literal lockPath from ONE session). The recovery narrative then pins the
  //    "never wedges" AC via the hint path: unlink by hand → re-run → proceeds. --
  {
    const { repoRoot, project, planPath, cacheDir } = makeReadFrontierRepo();
    const lockFile = path.join(cacheDir, SCHEDULER_LOCK_NAME);
    const stalePayload = JSON.stringify({ pid: 2147483646, host: os.hostname(), ts: Date.now(), subcommand: 'open-ready' });
    fs.writeFileSync(lockFile, stalePayload);
    const r = runNode(repoRoot, ['open-ready', '--project', project, '--json']);
    assert(r.result === 'refuse' && r.reason === 'scheduler_lock_stale',
      'T-585-stale-refuse: dead-holder lock → typed scheduler_lock_stale refusal (no auto-takeover), got ' + JSON.stringify({ result: r.result, reason: r.reason }));
    assert(r.exitCode === 1, 'T-585-stale-refuse: non-zero exit on the stale refusal');
    assert(typeof r.operator_hint === 'string' && /rm "[^"]*scheduler\.lock"/.test(r.operator_hint),
      'T-585-stale-refuse: operator_hint names the literal lockPath in an rm "<lockPath>" form, got ' + JSON.stringify(r.operator_hint));
    let lockNow = null; try { lockNow = fs.readFileSync(lockFile, 'utf8'); } catch (_) { lockNow = null; }
    assert(lockNow === stalePayload, 'T-585-stale-refuse: the stale lockfile is byte-intact (never auto-removed)');
    const st = ledgerStatuses(planPath);
    assert(st.ra === 'pending' && st.rb === 'pending', 'T-585-stale-refuse: ledger unchanged — zero mutation');
    assert(readRS(cacheDir) === null, 'T-585-stale-refuse: no running set written');
    // Recovery narrative (the hinted step): the operator removes the lock by hand from ONE session, then
    // re-runs → the frontier opens (a dead holder never permanently wedges the project).
    try { fs.unlinkSync(lockFile); } catch (_) {}
    const r2 = runNode(repoRoot, ['open-ready', '--project', project, '--json']);
    assert(r2.result === 'ok' && Array.isArray(r2.opened) && r2.opened.length === 2,
      'T-585-stale-refuse: after the operator removes the lock, open-ready proceeds (never wedges), got ' + JSON.stringify({ result: r2.result, opened: r2.opened && r2.opened.map((n) => n.id), reason: r2.reason }));
    assert(!fs.existsSync(lockFile), 'T-585-stale-refuse: lock released after the recovered serial call');
    cleanup(repoRoot);
  }
  // -- age-based cross-host twin: an OLD-ts cross-host holder is ALSO a typed stale refusal (age fallback). --
  {
    const { repoRoot, project, cacheDir } = makeReadFrontierRepo();
    fs.writeFileSync(path.join(cacheDir, SCHEDULER_LOCK_NAME),
      JSON.stringify({ pid: 4242, host: 'ghost-host-' + Math.random().toString(16).slice(2), ts: Date.now() - LANE_STALENESS_MS - 3600000, subcommand: 'open-ready' }));
    const r = runNode(repoRoot, ['open-ready', '--project', project, '--json']);
    assert(r.result === 'refuse' && r.reason === 'scheduler_lock_stale',
      'T-585-stale-refuse(age): old cross-host holder → scheduler_lock_stale refusal, got ' + JSON.stringify({ result: r.result, reason: r.reason }));
    cleanup(repoRoot);
  }

  // -- T-585-release: a normal serial open-ready leaves NO scheduler.lock behind (finally-release). --
  {
    const { repoRoot, project, cacheDir } = makeReadFrontierRepo();
    const r = runNode(repoRoot, ['open-ready', '--project', project, '--json']);
    assert(r.result === 'ok', 'T-585-release: serial open-ready ok');
    assert(!fs.existsSync(path.join(cacheDir, SCHEDULER_LOCK_NAME)), 'T-585-release: no scheduler.lock left after a clean serial call');
    cleanup(repoRoot);
  }

  // -- T-585-open-ready×2 (genuine race): two concurrent open-ready on ONE project must NOT double-open.
  //    RED: advisory-only → both read running-set=null → both open the frontier (double-dispatch). GREEN:
  //    exactly one opens; the other refuses scheduler_locked (or, if fully serialized, sees the set already
  //    open and opens nothing). Durable invariant EVERY trial: set(ledger in_progress) === set(running-set). --
  {
    const TRIALS = 5;
    let everDoubleOpen = false;
    let everInvariantViolated = false;
    for (let t = 0; t < TRIALS; t++) {
      const { repoRoot, project, planPath, cacheDir } = makeReadFrontierRepo();
      const rs = raceTwo(repoRoot, ['open-ready', '--project', project, '--json'], ['open-ready', '--project', project, '--json']);
      const nonEmptyOpens = rs.filter((r) => r && r.result === 'ok' && Array.isArray(r.opened) && r.opened.length > 0).length;
      if (nonEmptyOpens > 1) everDoubleOpen = true;
      if (!setsEqual(inProgressSet(planPath), rsNodeSet(cacheDir))) everInvariantViolated = true;
      cleanup(repoRoot);
    }
    assert(everDoubleOpen === false,
      'T-585-open-ready×2: no trial double-opened the frontier (the lock serializes concurrent open-ready)');
    assert(everInvariantViolated === false,
      'T-585-open-ready×2: set(ledger in_progress) === set(running-set) held in every trial');
  }

  // -- T-585-close-node×2 (genuine race): two concurrent close-node for two co-open read-frontier members
  //    must not lose a complete flip. RED: each whole-plan rewrite clobbers the other → 1 complete for 2
  //    result:ok (lost update). GREEN: at most one close is result:ok per race (the other refuses
  //    scheduler_locked), so completeMembers >= #(ok); a serial retry then completes both (no wedge). --
  {
    const TRIALS = 5;
    let everLostUpdate = false;
    let everWedged = false;
    let racesRun = 0;
    for (let t = 0; t < TRIALS; t++) {
      const { repoRoot, project, planPath, cacheDir } = makeReadFrontierRepo();
      const open = runNode(repoRoot, ['open-ready', '--project', project, '--json']);
      if (!(open.result === 'ok' && Array.isArray(open.opened) && open.opened.length === 2)) { cleanup(repoRoot); continue; }
      writeEvidence(cacheDir, 'ra'); writeEvidence(cacheDir, 'rb');
      racesRun++;
      const rs = raceTwo(repoRoot,
        ['close-node', '--node-id', 'ra', '--project', project, '--json'],
        ['close-node', '--node-id', 'rb', '--project', project, '--json']);
      const oks = rs.filter((r) => r && r.result === 'ok').length;
      const st = ledgerStatuses(planPath);
      const completeMembers = ['ra', 'rb'].filter((id) => st[id] === 'complete').length;
      if (completeMembers < oks) everLostUpdate = true;
      // GREEN recovery: serially retry any member still not complete → both must reach complete (no wedge).
      for (const id of ['ra', 'rb']) {
        if (ledgerStatuses(planPath)[id] !== 'complete') runNode(repoRoot, ['close-node', '--node-id', id, '--project', project, '--json']);
      }
      const stFinal = ledgerStatuses(planPath);
      if (!(stFinal.ra === 'complete' && stFinal.rb === 'complete')) everWedged = true;
      cleanup(repoRoot);
    }
    assert(racesRun > 0, 'T-585-close-node×2: at least one race trial ran (co-open setup succeeded)');
    assert(everLostUpdate === false,
      'T-585-close-node×2: no trial lost a complete flip (completeMembers >= #result:ok in every race)');
    assert(everWedged === false,
      'T-585-close-node×2: a serial retry completes both members after every race (the lock never wedges the project)');
  }

  // -- T-585-stale-race (repair proof): N=6 concurrent open-ready against a PLANTED dead-PID stale lock.
  //    An unlink-based auto-takeover double-acquires here (two takers holding the same stale decision
  //    both claim after the other's unlink — the first taker ALWAYS succeeds, so ANY result:ok fails the
  //    zero-acquisition assertion deterministically). With takeover removed, NO code path succeeds
  //    against an existing lockfile: all N refuse scheduler_lock_stale, the planted lockfile survives
  //    byte-identical (no non-holder unlink EVER), and durable state is untouched. --
  {
    const TRIALS = 3;
    const N = 6;
    let everAcquired = false;
    let everWrongShape = false;
    let everLockMutated = false;
    let everLedgerMutated = false;
    let everRunningSet = false;
    for (let t = 0; t < TRIALS; t++) {
      const { repoRoot, project, planPath, cacheDir } = makeReadFrontierRepo();
      const lockFile = path.join(cacheDir, SCHEDULER_LOCK_NAME);
      const stalePayload = JSON.stringify({ pid: 2147483646, host: os.hostname(), ts: Date.now(), subcommand: 'open-ready' });
      fs.writeFileSync(lockFile, stalePayload);
      const argvs = [];
      for (let i = 0; i < N; i++) argvs.push(['open-ready', '--project', project, '--json']);
      const rs = raceN(repoRoot, argvs);
      if (rs.length !== N || rs.some((r) => r && r.result === 'ok')) everAcquired = true;
      if (!(rs.length === N && rs.every((r) => r && r.result === 'refuse' && r.reason === 'scheduler_lock_stale' && r.code === 1))) everWrongShape = true;
      let lockNow = null; try { lockNow = fs.readFileSync(lockFile, 'utf8'); } catch (_) { lockNow = null; }
      if (lockNow !== stalePayload) everLockMutated = true;
      const st = ledgerStatuses(planPath);
      if (!(st.ra === 'pending' && st.rb === 'pending' && st.finalize === 'pending')) everLedgerMutated = true;
      if (readRS(cacheDir) !== null) everRunningSet = true;
      cleanup(repoRoot);
    }
    assert(everAcquired === false,
      'T-585-stale-race: ZERO acquisitions across ' + N + ' concurrent callers vs a stale lock in every trial (no code path succeeds against an existing lockfile)');
    assert(everWrongShape === false,
      'T-585-stale-race: ALL ' + N + ' concurrent callers refuse scheduler_lock_stale (exit 1) in every trial');
    assert(everLockMutated === false,
      'T-585-stale-race: the planted stale lockfile survives byte-identical in every trial (no non-holder unlink ever)');
    assert(everLedgerMutated === false,
      'T-585-stale-race: ledger stays all-pending in every trial (zero mutation)');
    assert(everRunningSet === false,
      'T-585-stale-race: no running-set.json written in any trial');
  }
}

// ===========================================================================
// CLUSTER T607 — main-session-gate runtime write fence (layers 2+3).
//   Layer 2: open-next / fused-advance record an opened main-session-gate into
//            running-set.json as kind:'gate'; close + reconcile remove it; the
//            kind-consumer audit (slot math / liveHasWrite / selectSpeculative /
//            reconcile budget) shows no false-fence or miscount from a live gate.
//   Layer 3: gate evidence requires a column-0 `instrumentation: none | <node-id>`
//            token; a named node must be a ledger WRITER.
// ===========================================================================
{
  // -- Layer 3: evidence-token presence ------------------------------------
  // T607-L3a: verdict present but NO instrumentation token → refuse (shape/instrumentation).
  const rNoInstr = checkEvidenceShape('main-session-gate', 'vgate',
    'verdict: pass\nfindings_blocking: 0\nGPU true-black confirmed\n');
  assert(rNoInstr.ok === false, 'T607-L3a: gate evidence missing instrumentation token → not ok');
  assert(rNoInstr.kind === 'shape' && rNoInstr.missingTokenClass === 'instrumentation',
    'T607-L3a: missing instrumentation → shape/instrumentation, got ' + JSON.stringify({ k: rNoInstr.kind, m: rNoInstr.missingTokenClass }));

  // T607-L3b: verdict + `instrumentation: none` → ok (no upstream provisioning declared).
  const rNone = checkEvidenceShape('main-session-gate', 'vgate',
    'verdict: pass\ninstrumentation: none\nfindings_blocking: 0\n');
  assert(rNone.ok === true, 'T607-L3b: verdict + instrumentation: none → ok, got ' + JSON.stringify(rNone));

  // T607-L3c: verdict + `instrumentation: none` but verdict absent still refuses on verdict FIRST.
  const rNoneNoVerdict = checkEvidenceShape('main-session-gate', 'vgate',
    'instrumentation: none\nfindings_blocking: 0\n');
  assert(rNoneNoVerdict.ok === false && rNoneNoVerdict.missingTokenClass === 'verdict',
    'T607-L3c: verdict precedence — missing verdict refuses verdict even with instrumentation, got ' + JSON.stringify(rNoneNoVerdict));

  // T607-L3d: `instrumentation: <node-id>` naming a ledger WRITER → ok (covers-instrumentation
  // interpretation: named node exists in the ledger and is a writer with a non-empty declared set).
  const ledgerNodes = [
    { id: 'probe', role: 'tdd-guide', declared_write_set: 'crates/x/tests/probe.rs' },
    { id: 'reader', role: 'code-explorer', declared_write_set: '—' },
    { id: 'vgate', role: 'main-session-gate', declared_write_set: '—' },
  ];
  const rNamedWriter = checkEvidenceShape('main-session-gate', 'vgate',
    'verdict: pass\ninstrumentation: probe\n', { ledgerNodes });
  assert(rNamedWriter.ok === true, 'T607-L3d: instrumentation names a ledger writer → ok, got ' + JSON.stringify(rNamedWriter));

  // T607-L3e: named node ABSENT from the ledger → refuse.
  const rNamedAbsent = checkEvidenceShape('main-session-gate', 'vgate',
    'verdict: pass\ninstrumentation: ghost\n', { ledgerNodes });
  assert(rNamedAbsent.ok === false && rNamedAbsent.missingTokenClass === 'instrumentation_node',
    'T607-L3e: instrumentation names a non-ledger node → refuse instrumentation_node, got ' + JSON.stringify(rNamedAbsent));

  // T607-L3f: named node is a READ-ONLY node (empty declared set) → refuse (not a writer).
  const rNamedReader = checkEvidenceShape('main-session-gate', 'vgate',
    'verdict: pass\ninstrumentation: reader\n', { ledgerNodes });
  assert(rNamedReader.ok === false && rNamedReader.missingTokenClass === 'instrumentation_node',
    'T607-L3f: instrumentation names a read-only node → refuse instrumentation_node, got ' + JSON.stringify(rNamedReader));

  // T607-L3g: with NO ledgerNodes opt, the named-node check is SKIPPED (token presence still enforced) —
  // the --verify preflight / legacy 3-arg callers keep the presence gate but not the deeper ledger check.
  const rNamedNoLedger = checkEvidenceShape('main-session-gate', 'vgate',
    'verdict: pass\ninstrumentation: probe\n');
  assert(rNamedNoLedger.ok === true, 'T607-L3g: named token without ledgerNodes opt → presence-only pass, got ' + JSON.stringify(rNamedNoLedger));
}

{
  // -- Layer 2: open-next records a main-session-gate as kind:'gate' --------
  // T607-L2a: open-next of a ready main-session-gate writes running-set.json with a kind:'gate' entry.
  const gatePlan = makePlan([
    '| impl | complete | |',
    '| vgate | pending | |',
    '| done | pending | |',
  ], [
    '| impl | implementer | — | lib/a.js | 1 | sequence |',
    '| vgate | main-session-gate | impl | — | 1 | sequence |',
    '| done | finalize | vgate | CHANGELOG.md | 1 | sequence |',
  ]);
  const gate = { id: 'vgate', role: 'main-session-gate', declared_write_set: '—' };
  const h = rsHarness({ [RS_PLAN_PATH]: gatePlan }, (base) => {
    if (base === 'kaola-workflow-next-action.js') {
      return { exitCode: 0, result: 'ok', allDone: false, readySet: [gate], readyPending: [gate], nextNode: gate };
    }
    if (base === 'kaola-workflow-commit-node.js') return { exitCode: 0, result: 'ok', recordBase: { base: 'abcdef012345aaaa' } };
    return { exitCode: 0, result: 'ok' };
  });
  const r = runOpenNext({ planPath: RS_PLAN_PATH, project: 'p', shell: h.shell, readFile: h.readFile, writeFile: h.writeFile, cacheExists: h.cacheExists, mkdirp: h.mkdirp });
  assert(r.result === 'ok' && r.opened && r.opened.id === 'vgate', 'T607-L2a: open-next opens the gate, got ' + JSON.stringify(r.reason || r));
  const set2a = h.files[RS_SET_PATH] ? JSON.parse(h.files[RS_SET_PATH]) : null;
  assert(set2a && (set2a.nodes || []).some(n => n.id === 'vgate' && n.kind === 'gate'),
    'T607-L2a: gate recorded as kind:gate in running-set.json, got ' + JSON.stringify(set2a));

  // T607-L2b: open-next of a NON-gate serial node writes NO gate entry (byte-identical: serial
  // non-gate opens never touch the running set).
  const serialPlan = makePlan([
    '| impl | pending | |',
    '| done | pending | |',
  ], [
    '| impl | implementer | — | lib/a.js | 1 | sequence |',
    '| done | finalize | impl | CHANGELOG.md | 1 | sequence |',
  ]);
  const implNode = { id: 'impl', role: 'implementer', declared_write_set: 'lib/a.js' };
  const h2 = rsHarness({ [RS_PLAN_PATH]: serialPlan }, (base) => {
    if (base === 'kaola-workflow-next-action.js') {
      return { exitCode: 0, result: 'ok', allDone: false, readySet: [implNode], readyPending: [implNode], nextNode: implNode };
    }
    if (base === 'kaola-workflow-commit-node.js') return { exitCode: 0, result: 'ok', recordBase: { base: 'abcdef012345bbbb' } };
    return { exitCode: 0, result: 'ok' };
  });
  const r2 = runOpenNext({ planPath: RS_PLAN_PATH, project: 'p', shell: h2.shell, readFile: h2.readFile, writeFile: h2.writeFile, cacheExists: h2.cacheExists, mkdirp: h2.mkdirp });
  assert(r2.result === 'ok' && r2.opened && r2.opened.id === 'impl', 'T607-L2b: open-next opens the serial node');
  const set2b = h2.files[RS_SET_PATH] ? JSON.parse(h2.files[RS_SET_PATH]) : null;
  assert(!set2b || !(set2b.nodes || []).some(n => n.kind === 'gate'), 'T607-L2b: a non-gate serial open records NO gate entry');
}

{
  // -- Layer 2: fused-advance records a gate ------------------------------
  // T607-L2c: close-and-open-next closing a node whose NEXT node is a main-session-gate records the
  // gate as kind:'gate' during the fused advance (the inline open path, not runOpenNext).
  const plan = makePlan([
    '| impl | in_progress | |',
    '| vgate | pending | |',
    '| done | pending | |',
  ], [
    '| impl | implementer | — | lib/a.js | 1 | sequence |',
    '| vgate | main-session-gate | impl | — | 1 | sequence |',
    '| done | finalize | vgate | CHANGELOG.md | 1 | sequence |',
  ]);
  const gate = { id: 'vgate', role: 'main-session-gate', declared_write_set: '—' };
  // Seed evidence for impl (a tdd-guide-less implementer close needs its tokens; use implementer role).
  const cachePath = '/p/.cache/impl.md';
  const h = rsHarness({
    [RS_PLAN_PATH]: plan,
    [cachePath]: 'evidence-binding: impl implbase0000\nnon_tdd_reason: config\nbuild-green: fixture passes\n',
    ['/p/.cache/barrier-base-impl']: 'implbase0000zzzz',
  }, (base) => {
    if (base === 'kaola-workflow-next-action.js') {
      return { exitCode: 0, result: 'ok', allDone: false, readyPending: [gate], nextNode: gate };
    }
    if (base === 'kaola-workflow-commit-node.js') return { exitCode: 0, result: 'ok', recordBase: { base: 'fusedbase012345' }, selectorCheck: {} };
    return { exitCode: 0, result: 'ok' };
  });
  const r = runCloseAndOpenNext({ planPath: RS_PLAN_PATH, project: 'p', nodeId: 'impl', shell: h.shell, readFile: h.readFile, writeFile: h.writeFile, cacheExists: h.cacheExists, mkdirp: h.mkdirp });
  assert(r.result === 'ok' && r.closed === 'impl' && r.opened && r.opened.id === 'vgate',
    'T607-L2c: close-and-open-next fused-advances to the gate, got ' + JSON.stringify(r.reason || { closed: r.closed, opened: r.opened && r.opened.id }));
  const set2c = h.files[RS_SET_PATH] ? JSON.parse(h.files[RS_SET_PATH]) : null;
  assert(set2c && (set2c.nodes || []).some(n => n.id === 'vgate' && n.kind === 'gate'),
    'T607-L2c: fused-advance records the gate as kind:gate, got ' + JSON.stringify(set2c));
}

{
  // -- Layer 2: close removes the gate; reconcile no-ops on a lone live gate --
  // T607-L2d: close-and-open-next closing the gate removes its running-set entry.
  const plan = makePlan([
    '| impl | complete | |',
    '| vgate | in_progress | |',
    '| done | pending | |',
  ], [
    '| impl | implementer | — | lib/a.js | 1 | sequence |',
    '| vgate | main-session-gate | impl | — | 1 | sequence |',
    '| done | finalize | vgate | CHANGELOG.md | 1 | sequence |',
  ]);
  const doneNode = { id: 'done', role: 'finalize', declared_write_set: 'CHANGELOG.md' };
  const h = rsHarness({
    [RS_PLAN_PATH]: plan,
    [RS_SET_PATH]: JSON.stringify({ state: 'open', nodes: [{ id: 'vgate', role: 'main-session-gate', kind: 'gate', declared_write_set: '—' }] }),
    ['/p/.cache/vgate.md']: 'evidence-binding: vgate gatebase0000\nverdict: pass\ninstrumentation: none\nfindings_blocking: 0\n',
    ['/p/.cache/barrier-base-vgate']: 'gatebase0000zzzz',
  }, (base) => {
    if (base === 'kaola-workflow-next-action.js') {
      return { exitCode: 0, result: 'ok', allDone: false, readyPending: [doneNode], nextNode: doneNode };
    }
    if (base === 'kaola-workflow-commit-node.js') return { exitCode: 0, result: 'ok', recordBase: { base: 'donebase0123456' }, selectorCheck: {} };
    return { exitCode: 0, result: 'ok' };
  });
  const r = runCloseAndOpenNext({ planPath: RS_PLAN_PATH, project: 'p', nodeId: 'vgate', shell: h.shell, readFile: h.readFile, writeFile: h.writeFile, cacheExists: h.cacheExists, mkdirp: h.mkdirp });
  assert(r.result === 'ok' && r.closed === 'vgate', 'T607-L2d: gate closes, got ' + JSON.stringify(r.reason || r));
  const set2d = h.files[RS_SET_PATH] ? JSON.parse(h.files[RS_SET_PATH]) : null;
  assert(!set2d || !(set2d.nodes || []).some(n => n.id === 'vgate'),
    'T607-L2d: closing the gate removes it from the running set, got ' + JSON.stringify(set2d));

  // T607-L2e: reconcile-running-set NO-OPs on a lone live gate (in_progress, non-opening) — nothing to
  // reconcile, the gate stays a legitimately-live member.
  const planE = makePlan([
    '| impl | complete | |',
    '| vgate | in_progress | |',
    '| done | pending | |',
  ], [
    '| impl | implementer | — | lib/a.js | 1 | sequence |',
    '| vgate | main-session-gate | impl | — | 1 | sequence |',
    '| done | finalize | vgate | CHANGELOG.md | 1 | sequence |',
  ]);
  const hE = rsHarness({
    [RS_PLAN_PATH]: planE,
    [RS_SET_PATH]: JSON.stringify({ state: 'open', max_concurrent: 8, nodes: [{ id: 'vgate', role: 'main-session-gate', kind: 'gate', declared_write_set: '—' }] }),
  }, () => ({ exitCode: 0, result: 'ok' }));
  const rE = runReconcileRunningSet({ planPath: RS_PLAN_PATH, project: 'p', shell: hE.shell, readFile: hE.readFile, writeFile: hE.writeFile, cacheExists: hE.cacheExists, unlink: hE.unlink });
  assert(rE.result === 'ok' && rE.reconciled === false && rE.reason === 'not_opening',
    'T607-L2e: reconcile no-ops (not_opening) on a lone live gate, got ' + JSON.stringify(rE));
  const setE = hE.files[RS_SET_PATH] ? JSON.parse(hE.files[RS_SET_PATH]) : null;
  assert(setE && (setE.nodes || []).some(n => n.id === 'vgate' && n.kind === 'gate'),
    'T607-L2e: the live gate is preserved by reconcile');
}

{
  // -- Kind-consumer audit: a live gate does not miscount slot math / write-exclusivity ----
  // T607-KC1: open-ready speculative-read fan-out behind a live gate gets the FULL read cap (the gate
  // does NOT consume a read slot) and liveHasWrite stays false (a gate is not a write).
  const plan = [
    '# Workflow Plan — test-project', '',
    '## Meta', 'labels: area:scripts', 'speculative_open_policy: auto', '',
    '## Nodes', '',
    '| id | role | depends_on | declared_write_set | cardinality | shape |',
    '| --- | --- | --- | --- | --- | --- |',
    '| impl | implementer | — | lib/a.js | 1 | sequence |',
    '| vgate | main-session-gate | impl | — | 1 | sequence |',
    '| ra | code-reviewer | vgate | — | 1 | sequence |',
    '| rb | security-reviewer | vgate | — | 1 | sequence |',
    '| done | finalize | ra rb | CHANGELOG.md | 1 | sequence |', '',
    '## Node Ledger', '',
    '| id | status | notes |', '| --- | --- | --- |',
    '| impl | complete | |',
    '| vgate | in_progress | |',
    '| ra | pending | |',
    '| rb | pending | |',
    '| done | pending | |', '',
  ].join('\n') + '\n';
  const specRa = { id: 'ra', role: 'code-reviewer', declared_write_set: '—', speculativeGate: 'vgate' };
  const specRb = { id: 'rb', role: 'security-reviewer', declared_write_set: '—', speculativeGate: 'vgate' };
  const h = rsHarness({
    [RS_PLAN_PATH]: plan,
    [RS_SET_PATH]: JSON.stringify({ state: 'open', max_concurrent: 8, nodes: [{ id: 'vgate', role: 'main-session-gate', kind: 'gate', declared_write_set: '—' }] }),
  }, (base) => {
    if (base === 'kaola-workflow-next-action.js') {
      return { exitCode: 0, result: 'ok', allDone: false, readyPending: [], speculativePending: [specRa, specRb] };
    }
    if (base === 'kaola-workflow-commit-node.js') return { exitCode: 0, result: 'ok', recordBase: { base: 'specbase0123456' } };
    return { exitCode: 0, result: 'ok' };
  });
  const r = runOpenReady({ planPath: RS_PLAN_PATH, project: 'p', max: null, fanoutCapReadonly: 8, shell: h.shell, readFile: h.readFile, writeFile: h.writeFile, cacheExists: h.cacheExists, mkdirp: h.mkdirp });
  assert(r.result === 'ok' && r.kind === 'read', 'T607-KC1: speculative reads open behind a live gate (kind read), got ' + JSON.stringify({ res: r.result, kind: r.kind, reason: r.reason }));
  assert((r.opened || []).length === 2, 'T607-KC1: BOTH speculative reads open (gate did not eat a read slot), got ' + (r.opened || []).length);
  const setKC = h.files[RS_SET_PATH] ? JSON.parse(h.files[RS_SET_PATH]) : null;
  assert(setKC && (setKC.nodes || []).some(n => n.id === 'vgate' && n.kind === 'gate'), 'T607-KC1: the live gate survives the open-ready write (concat, not replace)');
  assert(setKC && (setKC.nodes || []).filter(n => n.speculative).length === 2, 'T607-KC1: both speculative reads recorded');
}

// ---------------------------------------------------------------------------
// T611-AC2: Codex join protocol — per-node wait budget on every dispatch card.
// The budget is derived from the node's effort tier (reasoning=40m, standard=20m) with a
// concrete role-default (20m) when no tier resolves — NEVER null, so a running agent's
// non-interrupt-before-budget rule always has a number. Planner override rides the tier.
// ---------------------------------------------------------------------------
{
  const schema = require('./kaola-workflow-adaptive-schema');
  assert(schema.waitBudgetMinutes('reasoning').wait_budget_minutes === 40
    && schema.waitBudgetMinutes('reasoning').wait_budget_source === 'planner_model',
    'T611-AC2: reasoning tier → 40m budget (planner_model), got ' + JSON.stringify(schema.waitBudgetMinutes('reasoning')));
  assert(schema.waitBudgetMinutes('standard').wait_budget_minutes === 20,
    'T611-AC2: standard tier → 20m budget, got ' + JSON.stringify(schema.waitBudgetMinutes('standard')));
  // Legacy {opus,sonnet} cells normalize to the SAME budget as their neutral tokens (byte-parity).
  assert(schema.waitBudgetMinutes('opus').wait_budget_minutes === 40, 'T611-AC2: legacy opus alias → 40m (== reasoning)');
  assert(schema.waitBudgetMinutes('sonnet').wait_budget_minutes === 20, 'T611-AC2: legacy sonnet alias → 20m (== standard)');
  // No tier resolves → a CONCRETE role-default budget (never null), tagged role_default.
  assert(schema.waitBudgetMinutes(null).wait_budget_minutes === 20
    && schema.waitBudgetMinutes(null).wait_budget_source === 'role_default',
    'T611-AC2: no tier → concrete role_default budget (never null), got ' + JSON.stringify(schema.waitBudgetMinutes(null)));
  assert(schema.waitBudgetMinutes('').wait_budget_minutes === 20, 'T611-AC2: blank tier → role_default budget');
  assert(schema.waitBudgetMinutes('nonsense').wait_budget_source === 'role_default', 'T611-AC2: out-of-vocab tier → role_default');
  // buildDispatch emits wait_budget_minutes on EVERY card (orient/open-next/open-ready share this builder).
  const dReasoning = buildDispatch({ id: 'x', role: 'code-architect', model: 'reasoning', declared_write_set: 'a.js' }, { nonce: 'n', evidence_file: '.cache/x.md' });
  assert(dReasoning.wait_budget_minutes === 40 && dReasoning.wait_budget_source === 'planner_model',
    'T611-AC2: buildDispatch card carries the tier-derived budget, got ' + JSON.stringify({ b: dReasoning.wait_budget_minutes, s: dReasoning.wait_budget_source }));
  const dNone = buildDispatch({ id: 'y', role: 'finalize', model: null, declared_write_set: '—' }, { nonce: 'n', evidence_file: '.cache/y.md' });
  assert(dNone.wait_budget_minutes === 20 && dNone.wait_budget_source === 'role_default',
    'T611-AC2: an untiered card still carries a concrete role-default budget, got ' + JSON.stringify({ b: dNone.wait_budget_minutes, s: dNone.wait_budget_source }));
}

// ---------------------------------------------------------------------------
// T611-AC5: typed delegation outcomes in the node evidence contract. An OPTIONAL column-0
// `delegation_outcome: <token>` line, closed vocabulary {completed, returned_partial,
// interrupted_unresponsive, interrupted_obsolete}. ABSENT ⇒ completed (back-compat: existing
// evidence has no such line and must not red). A PRESENT unknown value is a typed refusal.
// ---------------------------------------------------------------------------
{
  const schema = require('./kaola-workflow-adaptive-schema');
  // parse helper: absent ⇒ completed default (found=false); present known ⇒ parsed; unknown ⇒ valid:false.
  assert(schema.parseDelegationOutcome('some evidence\nno token').outcome === 'completed'
    && schema.parseDelegationOutcome('some evidence').found === false,
    'T611-AC5: absent token ⇒ completed default, found=false');
  assert(schema.parseDelegationOutcome('delegation_outcome: interrupted_unresponsive').outcome === 'interrupted_unresponsive'
    && schema.parseDelegationOutcome('delegation_outcome: interrupted_unresponsive').valid === true,
    'T611-AC5: a present known token parses + is valid');
  assert(schema.parseDelegationOutcome('delegation_outcome: bogus').valid === false,
    'T611-AC5: an unknown token → valid:false');
  assert(schema.DELEGATION_OUTCOME_VOCABULARY.length === 4 && schema.DELEGATION_OUTCOME_DEFAULT === 'completed',
    'T611-AC5: vocabulary is the 4 tokens with completed default');
  // checkEvidenceShape: absent token is inert (existing tdd-guide evidence still passes).
  assert(checkEvidenceShape('tdd-guide', 'n1', 'RED: fail\nGREEN: pass').ok === true,
    'T611-AC5: evidence without the token is unaffected (completed default)');
  // a valid `completed` token passes.
  assert(checkEvidenceShape('tdd-guide', 'n1', 'delegation_outcome: completed\nRED: fail\nGREEN: pass').ok === true,
    'T611-AC5: delegation_outcome: completed passes');
  // an interrupted-path token passes when the role tokens are present.
  assert(checkEvidenceShape('implementer', 'n2', 'delegation_outcome: returned_partial\nnon_tdd_reason: x\nregression-green: pass').ok === true,
    'T611-AC5: an interrupted-path token (returned_partial) passes with the role tokens present');
  // an unknown token is a typed refusal, independent of role (checked before the role branches).
  const bad = checkEvidenceShape('tdd-guide', 'n1', 'delegation_outcome: exploded\nRED\nGREEN');
  assert(bad.ok === false && bad.missingTokenClass === 'delegation_outcome',
    'T611-AC5: unknown delegation_outcome → typed refusal (delegation_outcome), got ' + JSON.stringify(bad));
}

// ---------------------------------------------------------------------------
// T611-AC3: reconcile writer kill-safety. A departing (rolled-back / capped-out) WRITER member is a
// potentially-interrupted in-place writer whose worktree may hold PARTIAL edits. reconcile-running-set
// diffs its actual changes vs its declared write set (via --barrier-check) and emits a typed, FAIL-CLOSED
// per-writer verdict: `adopt` (changes ⊆ set) or `halt` (stray writes OUTSIDE the set) + the offending
// paths. Non-destructive: reconcile NEVER auto-deletes; it hands the halt to the orchestrator/consent valve.
// ---------------------------------------------------------------------------
{
  // A live stable read member 'a' consumes the single ceiling slot; the opening WRITER 'w' is capped out
  // (budget = ceiling(1) - live(1) = 0) → 'w' is a departing writer that gets reconciled.
  const mkWriterReconcilePlan = () => makePlan(['| a | in_progress | |', '| w | in_progress | |'], [
    '| a | code-reviewer | — | — | 1 | sequence |',
    '| w | implementer | — | scripts/a.js | 1 | sequence |',
  ]);
  const mkWriterReconcileSet = () => JSON.stringify({ state: 'open', max_concurrent: 1, nodes: [
    { id: 'a', role: 'code-reviewer', kind: 'read' },
    { id: 'w', role: 'implementer', kind: 'write', opening: true },
  ] });

  // (i) adopt — barrier-check passes (all changes ⊆ declared set).
  {
    const h = rsHarness({ [RS_PLAN_PATH]: mkWriterReconcilePlan(), [RS_SET_PATH]: mkWriterReconcileSet() },
      () => ({ exitCode: 0, result: 'ok' }),
      (base, a) => { if (a.includes('--barrier-check')) return { exitCode: 0, result: 'pass', outOfAllow: [] }; return null; });
    const r = runReconcileRunningSet({ planPath: RS_PLAN_PATH, project: 'p', shell: h.shell, readFile: h.readFile, writeFile: h.writeFile, cacheExists: h.cacheExists, unlink: h.unlink });
    assert(r.result === 'ok' && Array.isArray(r.writerReconciliation) && r.writerReconciliation.length === 1,
      'T611-AC3(i): exactly one writer reconciled, got ' + JSON.stringify(r.writerReconciliation));
    assert(r.writerReconciliation[0].node_id === 'w' && r.writerReconciliation[0].verdict === 'adopt',
      'T611-AC3(i): contained writer → adopt, got ' + JSON.stringify(r.writerReconciliation[0]));
    assert(r.writerReconciliation[0].outOfWriteSet.length === 0, 'T611-AC3(i): adopt carries no out-of-set paths');
  }

  // (ii) halt — barrier-check refuses with out-of-write-set paths (the stray-edit hazard). Fail-closed,
  //      NON-DESTRUCTIVE: verdict halt + the offending paths; reconcile never unlinks a production file.
  {
    const h = rsHarness({ [RS_PLAN_PATH]: mkWriterReconcilePlan(), [RS_SET_PATH]: mkWriterReconcileSet() },
      () => ({ exitCode: 0, result: 'ok' }),
      (base, a) => { if (a.includes('--barrier-check')) return { exitCode: 1, result: 'refuse', reason: 'write_set_overflow', outOfAllow: ['setup_daily_quant.sh', 'tests/x.js'] }; return null; });
    const r = runReconcileRunningSet({ planPath: RS_PLAN_PATH, project: 'p', shell: h.shell, readFile: h.readFile, writeFile: h.writeFile, cacheExists: h.cacheExists, unlink: h.unlink });
    assert(r.writerReconciliation.length === 1 && r.writerReconciliation[0].verdict === 'halt',
      'T611-AC3(ii): stray-write writer → halt, got ' + JSON.stringify(r.writerReconciliation[0]));
    assert(r.writerReconciliation[0].outOfWriteSet.includes('setup_daily_quant.sh')
      && r.writerReconciliation[0].outOfWriteSet.includes('tests/x.js'),
      'T611-AC3(ii): halt lists the offending out-of-write-set paths, got ' + JSON.stringify(r.writerReconciliation[0].outOfWriteSet));
    assert(r.writerReconciliation[0].reason === 'write_set_overflow', 'T611-AC3(ii): halt carries the barrier reason');
    // Non-destructive: the reconcile emits an overall halt hint so the orchestrator/consent valve decides.
    assert(r.writerHalt === true, 'T611-AC3(ii): a halt verdict surfaces writerHalt:true on the envelope');
  }

  // (iii) a READ member being rolled back is NOT a writer → no reconciliation entry (writers only).
  {
    const plan = makePlan(['| a | in_progress | |', '| b | pending | |'], [
      '| a | code-reviewer | — | — | 1 | sequence |',
      '| b | security-reviewer | — | — | 1 | sequence |',
    ]);
    const crashed = JSON.stringify({ state: 'opening', nodes: [
      { id: 'a', role: 'code-reviewer', kind: 'read', opening: true },
      { id: 'b', role: 'security-reviewer', kind: 'read', opening: true },
    ] });
    const h = rsHarness({ [RS_PLAN_PATH]: plan, [RS_SET_PATH]: crashed }, () => ({ exitCode: 0, result: 'ok' }));
    const r = runReconcileRunningSet({ planPath: RS_PLAN_PATH, project: 'p', shell: h.shell, readFile: h.readFile, writeFile: h.writeFile, cacheExists: h.cacheExists, unlink: h.unlink });
    assert(Array.isArray(r.writerReconciliation) && r.writerReconciliation.length === 0,
      'T611-AC3(iii): a rolled-back READ member yields no writer reconciliation entry, got ' + JSON.stringify(r.writerReconciliation));
    assert(r.writerHalt !== true, 'T611-AC3(iii): no writer halt when no writer departs');
  }

  // (iv) FAIL-CLOSED on an UNVERIFIABLE barrier — the shellNode-swallowed-failure hazard. shellNode never
  //      throws: a SIGKILL'd / jetsam-killed / crashed / non-JSON / missing-validator --barrier-check yields
  //      a RESULTLESS truthy object `{exitCode:N}` (safeJsonParse('') === {}). That MUST halt (positive
  //      confirmation), never silently adopt a writer whose diff could not be verified.
  {
    const h = rsHarness({ [RS_PLAN_PATH]: mkWriterReconcilePlan(), [RS_SET_PATH]: mkWriterReconcileSet() },
      () => ({ exitCode: 0, result: 'ok' }),
      (base, a) => { if (a.includes('--barrier-check')) return { exitCode: 1 }; return null; });
    const r = runReconcileRunningSet({ planPath: RS_PLAN_PATH, project: 'p', shell: h.shell, readFile: h.readFile, writeFile: h.writeFile, cacheExists: h.cacheExists, unlink: h.unlink });
    assert(r.writerReconciliation.length === 1 && r.writerReconciliation[0].verdict === 'halt'
      && r.writerReconciliation[0].reason === 'barrier_unverifiable',
      'T611-AC3(iv): a resultless {exitCode:N} barrier (killed/crashed) → fail-closed halt(barrier_unverifiable), got ' + JSON.stringify(r.writerReconciliation[0]));
    assert(r.writerHalt === true, 'T611-AC3(iv): an unverifiable barrier surfaces writerHalt:true (never a silent adopt)');
  }

  // (v) FAIL-CLOSED on an UNRECOGNIZED result token — a garbage `{result:'banana'}` is not the explicit
  //     pass/ok confirmation, so it must halt too (never fall through to adopt).
  {
    const h = rsHarness({ [RS_PLAN_PATH]: mkWriterReconcilePlan(), [RS_SET_PATH]: mkWriterReconcileSet() },
      () => ({ exitCode: 0, result: 'ok' }),
      (base, a) => { if (a.includes('--barrier-check')) return { exitCode: 0, result: 'banana' }; return null; });
    const r = runReconcileRunningSet({ planPath: RS_PLAN_PATH, project: 'p', shell: h.shell, readFile: h.readFile, writeFile: h.writeFile, cacheExists: h.cacheExists, unlink: h.unlink });
    assert(r.writerReconciliation[0].verdict === 'halt' && r.writerReconciliation[0].reason === 'barrier_unverifiable',
      'T611-AC3(v): an unrecognized barrier result token → fail-closed halt(barrier_unverifiable), got ' + JSON.stringify(r.writerReconciliation[0]));
    assert(r.writerHalt === true, 'T611-AC3(v): unrecognized result surfaces writerHalt:true');
  }

  // (vi) the explicit clean confirmations still adopt — positive confirmation accepts BOTH the real barrier
  //      `result:'pass'` AND the harness/CLI `result:'ok'` (no regression on the happy path).
  {
    for (const okResult of ['pass', 'ok']) {
      const h = rsHarness({ [RS_PLAN_PATH]: mkWriterReconcilePlan(), [RS_SET_PATH]: mkWriterReconcileSet() },
        () => ({ exitCode: 0, result: 'ok' }),
        (base, a) => { if (a.includes('--barrier-check')) return { exitCode: 0, result: okResult, outOfAllow: [] }; return null; });
      const r = runReconcileRunningSet({ planPath: RS_PLAN_PATH, project: 'p', shell: h.shell, readFile: h.readFile, writeFile: h.writeFile, cacheExists: h.cacheExists, unlink: h.unlink });
      assert(r.writerReconciliation[0].verdict === 'adopt' && r.writerHalt === false,
        'T611-AC3(vi): an explicit clean barrier result:' + okResult + ' → adopt, writerHalt false, got ' + JSON.stringify(r.writerReconciliation[0]));
    }
  }
}

// ===========================================================================
// #612 — the run-progress mirror must fail CLOSED on an untrusted (heuristic-resolved) mainRoot.
// The mirror may write ONLY when mainRoot is trustworthy: affirmatively resolved from the project's
// own workflow-state.md `main_root:` field, OR a fallback (git-common-dir) root that DEMONSTRABLY
// already owns the project (its frozen workflow-plan.md is present). A misresolved heuristic root must
// never fabricate a foreign kaola-workflow/<project>/ tree (the leak class). Driven as REAL
// subprocesses in REAL git repos + linked worktrees under $TMPDIR (the resolution reads git + fs).
// ===========================================================================
{
  const { execFileSync } = require('child_process');
  const NODE_CLI_612 = path.join(__dirname, 'kaola-workflow-adaptive-node.js');
  const VALIDATOR_612 = path.join(__dirname, 'kaola-workflow-plan-validator.js');

  const plan612 = (proj) => [
    '# Workflow Plan — ' + proj, '',
    '## Meta', 'labels: area:scripts', 'sink: CHANGELOG.md', '',
    '## Nodes', '',
    '| id | role | depends_on | declared_write_set | cardinality | shape |',
    '| --- | --- | --- | --- | --- | --- |',
    '| seed     | code-explorer | —     | —     | 1 | sequence |',
    '| n1       | tdd-guide     | seed  | a.js  | 1 | sequence |',
    '| review   | code-reviewer | n1    | —     | 1 | sequence |',
    '| finalize | finalize      | review| —     | 1 | sequence |', '',
    '## Node Ledger', '',
    '| id | status |', '| --- | --- |',
    '| seed | complete |',
    '| n1 | pending |',
    '| review | pending |',
    '| finalize | pending |', '',
  ].join('\n') + '\n';

  const g612 = (root, a) => execFileSync('git', ['-C', root, ...a], { encoding: 'utf8', stdio: ['ignore', 'ignore', 'ignore'] });
  const rm612 = (p) => { try { fs.rmSync(p, { recursive: true, force: true }); } catch (_) {} };
  const runNode612 = (cwd, subArgs) => {
    try {
      const stdout = execFileSync('node', [NODE_CLI_612, ...subArgs], { cwd, encoding: 'utf8' });
      let p = {}; try { p = JSON.parse(stdout.trim().split('\n').pop()); } catch (_) {}
      return { exitCode: 0, ...p };
    } catch (err) {
      const status = (err.status == null) ? 1 : err.status;
      let p = {}; try { p = JSON.parse(String(err.stdout || '').trim().split('\n').pop()); } catch (_) {}
      return { exitCode: status, ...p };
    }
  };
  const seedProject612 = (root, proj) => {
    const projDir = path.join(root, 'kaola-workflow', proj);
    fs.mkdirSync(path.join(projDir, '.cache'), { recursive: true });
    const planPath = path.join(projDir, 'workflow-plan.md');
    fs.writeFileSync(planPath, plan612(proj));
    fs.writeFileSync(path.join(projDir, 'workflow-state.md'), '# State\n');   // NO main_root: → fallback path
    try { execFileSync('node', [VALIDATOR_612, planPath, '--freeze', '--repair', '--json'], { cwd: root, encoding: 'utf8' }); } catch (_) {}
  };

  // ---- Fixture E (ESCAPE): mainRoot resolves (via the git-common-dir fallback, no main_root: field)
  //      to a checkout that does NOT own the project → the mirror must be SKIPPED. Pre-fix (fail-open)
  //      this fabricates kaola-workflow/<proj>/.cache/run-progress.json in the foreign main checkout.
  {
    const main = fs.mkdtempSync(path.join(os.tmpdir(), 'kw-612-esc-main-'));
    g612(main, ['init']); g612(main, ['config', 'user.email', 'kw@test']); g612(main, ['config', 'user.name', 'kw']); g612(main, ['config', 'commit.gpgsign', 'false']);
    fs.writeFileSync(path.join(main, '.gitignore'), '.kw/\n');
    fs.writeFileSync(path.join(main, 'README.md'), '# base\n');   // main has NO project of its own
    g612(main, ['add', '-A']); g612(main, ['commit', '-m', 'base']);
    const wt = fs.mkdtempSync(path.join(os.tmpdir(), 'kw-612-esc-wt-')); rm612(wt);
    let added = true;
    try { g612(main, ['worktree', 'add', '-b', 'kw612esc', wt, 'HEAD']); } catch (_) { added = false; }
    if (added) {
      // The project lives ONLY in the worktree's branch; main's working tree never had it.
      seedProject612(wt, 'issue-612e');
      g612(wt, ['add', '-A']); g612(wt, ['commit', '-m', 'seed proj in wt']);
      const r = runNode612(wt, ['open-next', '--project', 'issue-612e', '--json']);
      assert(r.result === 'ok', 'T612-escape: in-worktree open-next proceeds (so the mirror trigger is reached), got ' + JSON.stringify({ result: r.result, reason: r.reason }));
      const foreignMirror = path.join(main, 'kaola-workflow', 'issue-612e', '.cache', 'run-progress.json');
      assert(!fs.existsSync(foreignMirror),
        'T612-escape: the mirror must NOT be written to a heuristic-resolved main that does not own the project (fail-closed), but it appeared at ' + foreignMirror);
      assert(r.run_progress_mirror === undefined,
        'T612-escape: a skipped (untrusted-root) mirror surfaces NO run_progress_mirror warn field, got ' + JSON.stringify(r.run_progress_mirror));
      try { g612(main, ['worktree', 'remove', '--force', wt]); } catch (_) { rm612(wt); }
    } else {
      assert(true, 'T612-escape: skipped (git worktree add unavailable in this environment)');
      rm612(wt);
    }
    rm612(main);
  }

  // ---- Fixture L (LEGITIMATE): mainRoot (via the SAME fallback, no main_root: field) DOES own the
  //      project (its frozen plan is present) → the mirror is STILL written. Guards that the fail-closed
  //      fix does not regress the legitimate worktree mirror path (the #605 mirror behavior).
  {
    const main = fs.mkdtempSync(path.join(os.tmpdir(), 'kw-612-legit-main-'));
    g612(main, ['init']); g612(main, ['config', 'user.email', 'kw@test']); g612(main, ['config', 'user.name', 'kw']); g612(main, ['config', 'commit.gpgsign', 'false']);
    fs.writeFileSync(path.join(main, '.gitignore'), '.kw/\n');
    seedProject612(main, 'issue-612l');            // main OWNS the project (like the #605(a) fixture)
    g612(main, ['add', '-A']); g612(main, ['commit', '-m', 'seed proj in main']);
    const wt = fs.mkdtempSync(path.join(os.tmpdir(), 'kw-612-legit-wt-')); rm612(wt);
    let added = true;
    try { g612(main, ['worktree', 'add', '-b', 'kw612legit', wt, 'HEAD']); } catch (_) { added = false; }
    if (added) {
      const r = runNode612(wt, ['open-next', '--project', 'issue-612l', '--json']);
      assert(r.result === 'ok', 'T612-legit: in-worktree open-next proceeds, got ' + JSON.stringify({ result: r.result, reason: r.reason }));
      const ownedMirror = path.join(main, 'kaola-workflow', 'issue-612l', '.cache', 'run-progress.json');
      assert(fs.existsSync(ownedMirror),
        'T612-legit: the legitimate worktree mirror (main owns the project) is STILL written — no regression, expected at ' + ownedMirror);
      try { g612(main, ['worktree', 'remove', '--force', wt]); } catch (_) { rm612(wt); }
    } else {
      assert(true, 'T612-legit: skipped (git worktree add unavailable in this environment)');
      rm612(wt);
    }
    rm612(main);
  }
}

// ===========================================================================
// #641 (D-641-01) — RELAX the read∥write scheduler serialization: a WRITE frontier arriving while
// only READS are live no longer unconditionally holds (write_awaits_drain). R1 (default-on,
// structural) attempts a LEG-CONTAINED co-open — the mirror of the shipped #622 read-direction
// relaxation — fail-closed on four preconditions (legCoupled + parent-clean + --parallel-safe ok +
// no live lane_group); the G4 merge fence still holds the last-member merge behind live reads. R2b
// (consent-tier) permits a LEGLESS writer to co-open behind an `observes: scratch` adversarial-verifier
// over a DIRTY parent iff the writer's declared set is chain-verdict-invisible (R2a predicate).
// ===========================================================================

// ---------------------------------------------------------------------------
// #641-R1 FAIL-CLOSED MATRIX (AC2) — direct runOpenReady unit calls (rsHarness, mocked shell). Each
// precondition failing individually yields today's `write_awaits_drain` hold with ZERO mutation, PLUS a
// typed `serialDegradeReason` label naming the cause. These rows return BEFORE any leg provisioning, so
// no real git is touched. Shape: a live READ `g` in the running set + a ready WRITE `w` frontier.
// ---------------------------------------------------------------------------
{
  // A live read `g` (already in_progress + in the running set) with a ready write `w` → the else-branch
  // (write-only frontier + non-empty running set) that R1 relaxes.
  function rwPlan(writeRows) {
    return makePlan(
      ['| g | in_progress | |'].concat(writeRows.map(w => '| ' + w.id + ' | pending | |')),
      [
        '| g | code-reviewer | — | — | 1 | sequence |',
      ].concat(writeRows.map(w => '| ' + w.id + ' | implementer | — | ' + w.set + ' | 1 | sequence |')),
    );
  }
  function liveReadSet(extra) {
    return JSON.stringify(Object.assign({
      state: 'open', max_concurrent: 8,
      nodes: [{ id: 'g', role: 'code-reviewer', kind: 'read', baseline: 'recorded' }],
    }, extra || {}));
  }
  function nextActionWrites(writeRows) {
    return (base) => {
      if (base === 'kaola-workflow-next-action.js') {
        return { exitCode: 0, result: 'ok', allDone: false, readyPending: writeRows.map(w => ({ id: w.id, role: 'implementer', declared_write_set: w.set })) };
      }
      if (base === 'kaola-workflow-commit-node.js') return { exitCode: 0, result: 'ok' };
      return { exitCode: 1, result: 'refuse' };
    };
  }

  // Row A: KAOLA_PARALLEL_WRITES=0 (legCoupled false) → hold, serialDegradeReason:'parallel_writes_off'.
  {
    const plan = rwPlan([{ id: 'w', set: 'scripts/a.js' }]);
    const h = rsHarness({ [RS_PLAN_PATH]: plan, [RS_SET_PATH]: liveReadSet() }, nextActionWrites([{ id: 'w', set: 'scripts/a.js' }]));
    const r = withParallelWrites('0', () => runOpenReady({ planPath: RS_PLAN_PATH, project: 'p', max: null, fanoutCapReadonly: 8, shell: h.shell, readFile: h.readFile, writeFile: h.writeFile, cacheExists: h.cacheExists, mkdirp: h.mkdirp }));
    assert(r.result === 'ok' && r.opened.length === 0 && r.reason === 'write_awaits_drain', '#641-R1-A: KAOLA_PARALLEL_WRITES=0 holds (write_awaits_drain), got ' + JSON.stringify({ o: r.opened, reason: r.reason }));
    assert(r.serialDegradeReason === 'parallel_writes_off', '#641-R1-A: hold is labeled serialDegradeReason:parallel_writes_off, got ' + JSON.stringify(r.serialDegradeReason));
    assert(h.files[RS_PLAN_PATH].includes('| w | pending | |'), '#641-R1-A: ZERO mutation — w stays pending');
    assert(JSON.parse(h.files[RS_SET_PATH]).nodes.length === 1, '#641-R1-A: running set unchanged (still just g)');
  }

  // Row B: a live lane_group descriptor already present → hold, serialDegradeReason:'lane_group_live'.
  {
    const plan = rwPlan([{ id: 'w', set: 'scripts/a.js' }]);
    const withGroup = liveReadSet({
      max_concurrent: 2,
      lane_group: { group_id: 'lg-x', members: ['x'], write_union: ['scripts/z.js'], legs: { x: { legPath: '/lg/x', legBranch: 'kw/x', baseline: 'deadbeef' } } },
      nodes: [
        { id: 'g', role: 'code-reviewer', kind: 'read', baseline: 'recorded' },
        { id: 'x', role: 'implementer', kind: 'write', group_id: 'lg-x', baseline: 'recorded' },
      ],
    });
    const h = rsHarness({ [RS_PLAN_PATH]: plan, [RS_SET_PATH]: withGroup }, nextActionWrites([{ id: 'w', set: 'scripts/a.js' }]));
    const r = runOpenReady({ planPath: RS_PLAN_PATH, project: 'p', max: null, fanoutCapReadonly: 8, shell: h.shell, readFile: h.readFile, writeFile: h.writeFile, cacheExists: h.cacheExists, mkdirp: h.mkdirp });
    assert(r.result === 'ok' && r.opened.length === 0 && r.reason === 'write_awaits_drain', '#641-R1-B: live lane_group holds, got ' + JSON.stringify({ o: r.opened, reason: r.reason }));
    assert(r.serialDegradeReason === 'lane_group_live', '#641-R1-B: hold labeled serialDegradeReason:lane_group_live, got ' + JSON.stringify(r.serialDegradeReason));
    assert(JSON.parse(h.files[RS_SET_PATH]).lane_group.group_id === 'lg-x', '#641-R1-B: the live lane_group survives untouched (zero mutation)');
  }

  // Row C: parent carries production dirt (--parent-clean-check non-pass) → hold, serialDegradeReason:'parent_dirty'.
  {
    const plan = rwPlan([{ id: 'w', set: 'scripts/a.js' }]);
    const validatorStub = (base, args) => {
      if (args.includes('--resume-check')) return { exitCode: 0, ok: true };
      if (args.includes('--parent-clean-check')) return { exitCode: 0, result: 'parent_dirty' };
      return { exitCode: 0, result: 'ok' };
    };
    const h = rsHarness({ [RS_PLAN_PATH]: plan, [RS_SET_PATH]: liveReadSet() }, nextActionWrites([{ id: 'w', set: 'scripts/a.js' }]), validatorStub);
    const r = runOpenReady({ planPath: RS_PLAN_PATH, project: 'p', max: null, fanoutCapReadonly: 8, shell: h.shell, readFile: h.readFile, writeFile: h.writeFile, cacheExists: h.cacheExists, mkdirp: h.mkdirp });
    assert(r.result === 'ok' && r.opened.length === 0 && r.reason === 'write_awaits_drain', '#641-R1-C: dirty parent holds, got ' + JSON.stringify({ o: r.opened, reason: r.reason }));
    assert(r.serialDegradeReason === 'parent_dirty', '#641-R1-C: hold labeled serialDegradeReason:parent_dirty, got ' + JSON.stringify(r.serialDegradeReason));
    assert(h.files[RS_PLAN_PATH].includes('| w | pending | |'), '#641-R1-C: ZERO mutation — w stays pending');
  }

  // Row D: two disjoint-declared writers but --parallel-safe reports a per-pair OVERLAP → exclude all →
  //   hold, serialDegradeReason:'overlaps_live_writer'. (Clean parent; the validator overlap report is
  //   authoritative — G6/G13.)
  {
    const plan = rwPlan([{ id: 'w1', set: 'scripts/a.js' }, { id: 'w2', set: 'scripts/b.js' }]);
    const validatorStub = (base, args) => {
      if (args.includes('--resume-check')) return { exitCode: 0, ok: true };
      if (args.includes('--parent-clean-check')) return { exitCode: 0, result: 'pass' };
      if (args.includes('--parallel-safe')) return { exitCode: 1, result: 'refuse', overlapping: [{ a: 'w1', b: 'w2' }] };
      return { exitCode: 0, result: 'ok' };
    };
    const h = rsHarness({ [RS_PLAN_PATH]: plan, [RS_SET_PATH]: liveReadSet() }, nextActionWrites([{ id: 'w1', set: 'scripts/a.js' }, { id: 'w2', set: 'scripts/b.js' }]), validatorStub);
    const r = runOpenReady({ planPath: RS_PLAN_PATH, project: 'p', max: null, fanoutCapReadonly: 8, shell: h.shell, readFile: h.readFile, writeFile: h.writeFile, cacheExists: h.cacheExists, mkdirp: h.mkdirp });
    assert(r.result === 'ok' && r.opened.length === 0 && r.reason === 'write_awaits_drain', '#641-R1-D: overlap holds, got ' + JSON.stringify({ o: r.opened, reason: r.reason }));
    assert(r.serialDegradeReason === 'overlaps_live_writer', '#641-R1-D: hold labeled serialDegradeReason:overlaps_live_writer, got ' + JSON.stringify(r.serialDegradeReason));
  }

  // Row E: two writers, --parallel-safe returns a non-ok WITHOUT an overlapping report (validator crash /
  //   garbled) → fail-CLOSED exclude-all → hold, serialDegradeReason:'parallel_safe_indeterminate' (G7).
  {
    const plan = rwPlan([{ id: 'w1', set: 'scripts/a.js' }, { id: 'w2', set: 'scripts/b.js' }]);
    const validatorStub = (base, args) => {
      if (args.includes('--resume-check')) return { exitCode: 0, ok: true };
      if (args.includes('--parent-clean-check')) return { exitCode: 0, result: 'pass' };
      if (args.includes('--parallel-safe')) return { exitCode: 1, result: 'refuse' }; // no overlapping array
      return { exitCode: 0, result: 'ok' };
    };
    const h = rsHarness({ [RS_PLAN_PATH]: plan, [RS_SET_PATH]: liveReadSet() }, nextActionWrites([{ id: 'w1', set: 'scripts/a.js' }, { id: 'w2', set: 'scripts/b.js' }]), validatorStub);
    const r = runOpenReady({ planPath: RS_PLAN_PATH, project: 'p', max: null, fanoutCapReadonly: 8, shell: h.shell, readFile: h.readFile, writeFile: h.writeFile, cacheExists: h.cacheExists, mkdirp: h.mkdirp });
    assert(r.result === 'ok' && r.opened.length === 0 && r.reason === 'write_awaits_drain', '#641-R1-E: indeterminate holds, got ' + JSON.stringify({ o: r.opened, reason: r.reason }));
    assert(r.serialDegradeReason === 'parallel_safe_indeterminate', '#641-R1-E: hold labeled serialDegradeReason:parallel_safe_indeterminate, got ' + JSON.stringify(r.serialDegradeReason));
  }
}

// ---------------------------------------------------------------------------
// #641-AC5 SERIAL-FALLBACK BYTE-IDENTITY: with KAOLA_PARALLEL_WRITES=0 + NO running set + a single
// write frontier, open-ready opens exactly ONE write serially, NO lane_group, and — critically — emits
// NO `serialDegradeReason` field (byte-identical to pre-#641; the label is only added on the RELAXED
// else-branch hold, which the no-running-set path never reaches).
// ---------------------------------------------------------------------------
{
  const plan = makePlan(['| w | pending | |'], ['| w | implementer | — | scripts/a.js | 1 | sequence |']);
  const h = rsHarness({ [RS_PLAN_PATH]: plan }, (base) => {
    if (base === 'kaola-workflow-next-action.js') return { exitCode: 0, result: 'ok', allDone: false, readyPending: [{ id: 'w', role: 'implementer', declared_write_set: 'scripts/a.js' }] };
    if (base === 'kaola-workflow-commit-node.js') return { exitCode: 0, result: 'ok' };
    return { exitCode: 1, result: 'refuse' };
  });
  const r = withParallelWrites('0', () => runOpenReady({ planPath: RS_PLAN_PATH, project: 'p', max: null, fanoutCapReadonly: 8, shell: h.shell, readFile: h.readFile, writeFile: h.writeFile, cacheExists: h.cacheExists, mkdirp: h.mkdirp }));
  assert(r.result === 'ok' && r.kind === 'write' && r.opened.length === 1, '#641-AC5: serial single write open, got ' + JSON.stringify({ kind: r.kind, o: r.opened && r.opened.map(n => n.id) }));
  assert(r.serialDegradeReason === undefined, '#641-AC5: NO serialDegradeReason field on the no-running-set serial path (byte-identical), got ' + JSON.stringify(r.serialDegradeReason));
  assert(!r.laneGroup, '#641-AC5: no lane_group under the serial fallback');
}

// ---------------------------------------------------------------------------
// #641-R1 CO-RUN + MERGE FENCE + CRASH-RECONCILE — REAL git subprocess (leg provisioning touches real
// git, so the #292 io-shim trap forbids a direct-call test here). Shape: seed(complete) → g(read) ∥
// w(write scripts/a.js) → review → finalize. Tick 1 opens g (read-first partition, UNCHANGED). Tick 2
// co-opens w as a LEG-CONTAINED lane group behind the live read g (R1) — mixed read+leg-write running set.
// ---------------------------------------------------------------------------
{
  const { execFileSync } = require('child_process');
  const NODE_CLI = path.join(__dirname, 'kaola-workflow-adaptive-node.js');
  const VALIDATOR = path.join(__dirname, 'kaola-workflow-plan-validator.js');

  function makeRWRepo() {
    const repoRoot = fs.mkdtempSync(path.join(os.tmpdir(), 'kw641-rw-'));
    const project = 'test-project';
    const projDir = path.join(repoRoot, 'kaola-workflow', project);
    const cacheDir = path.join(projDir, '.cache');
    fs.mkdirSync(cacheDir, { recursive: true });
    const planPath = path.join(projDir, 'workflow-plan.md');
    const plan = [
      '# Workflow Plan — test-project', '',
      '## Meta', 'labels: area:scripts', 'sink: CHANGELOG.md', '',
      '## Nodes', '',
      '| id | role | depends_on | declared_write_set | cardinality | shape |',
      '| --- | --- | --- | --- | --- | --- |',
      '| seed     | code-explorer | —      | —            | 1 | sequence |',
      '| g        | code-explorer | seed   | —            | 1 | sequence |',
      '| w        | tdd-guide     | seed   | scripts/a.js | 1 | sequence |',
      '| review   | code-reviewer | g,w    | —            | 1 | sequence |',
      '| finalize | finalize      | review | —            | 1 | sequence |', '',
      '## Node Ledger', '',
      '| id | status |', '| --- | --- |',
      '| seed | complete |', '| g | pending |', '| w | pending |',
      '| review | pending |', '| finalize | pending |', '',
    ].join('\n') + '\n';
    fs.writeFileSync(planPath, plan);
    fs.writeFileSync(path.join(projDir, 'workflow-state.md'), '# State\n');
    const g = (args) => execFileSync('git', ['-C', repoRoot, ...args], { encoding: 'utf8', stdio: ['ignore', 'ignore', 'ignore'] });
    g(['init']); g(['config', 'user.email', 'kw@test']); g(['config', 'user.name', 'kw']); g(['config', 'commit.gpgsign', 'false']);
    try { execFileSync('node', [VALIDATOR, planPath, '--freeze', '--repair', '--json'], { cwd: repoRoot, encoding: 'utf8' }); } catch (_) {}
    fs.writeFileSync(path.join(repoRoot, '.gitignore'), '.kw/\n');
    g(['add', '-A']); g(['commit', '-m', 'init']);
    return { repoRoot, project, planPath, projDir, cacheDir };
  }
  function runNode(repoRoot, subArgs, extraEnv) {
    const env = Object.assign({}, process.env, extraEnv || {});
    try {
      const stdout = execFileSync('node', [NODE_CLI, ...subArgs], { cwd: repoRoot, encoding: 'utf8', env });
      let parsed = {}; try { parsed = JSON.parse(stdout.trim().split('\n').pop()); } catch (_) {}
      return { exitCode: 0, ...parsed };
    } catch (err) {
      const status = (err.status == null) ? 1 : err.status;
      let parsed = {}; try { parsed = JSON.parse(String(err.stdout || '').trim().split('\n').pop()); } catch (_) {}
      return { exitCode: status, ...parsed };
    }
  }
  function readRS(cacheDir) { try { return JSON.parse(fs.readFileSync(path.join(cacheDir, 'running-set.json'), 'utf8')); } catch (_) { return null; } }
  function ledgerStatus(planPath, id) {
    const txt = fs.readFileSync(planPath, 'utf8');
    const start = txt.indexOf('## Node Ledger');
    const body = start >= 0 ? txt.slice(start) : txt;
    const m = body.match(new RegExp('^\\|\\s*' + id + '\\s*\\|\\s*(\\S+)\\s*\\|', 'm'));
    return m ? m[1] : null;
  }
  function writeEvidence(cacheDir, id, role, extraLines) {
    return writeLegAwareEvidence(cacheDir, id, role, extraLines);
  }
  function cleanup(root) { try { fs.rmSync(root, { recursive: true, force: true }); } catch (_) {} }

  // Probe git worktree availability once — leg provisioning needs `git worktree add`.
  let worktreeOK = true;
  { const probe = fs.mkdtempSync(path.join(os.tmpdir(), 'kw641-probe-'));
    try {
      execFileSync('git', ['-C', probe, 'init'], { stdio: ['ignore', 'ignore', 'ignore'] });
      execFileSync('git', ['-C', probe, 'config', 'user.email', 'k@t'], { stdio: ['ignore', 'ignore', 'ignore'] });
      execFileSync('git', ['-C', probe, 'config', 'user.name', 'k'], { stdio: ['ignore', 'ignore', 'ignore'] });
      fs.writeFileSync(path.join(probe, 'f'), 'x'); execFileSync('git', ['-C', probe, 'add', '-A'], { stdio: ['ignore', 'ignore', 'ignore'] });
      execFileSync('git', ['-C', probe, 'commit', '-m', 'i'], { stdio: ['ignore', 'ignore', 'ignore'] });
    } catch (_) { worktreeOK = false; }
    cleanup(probe);
  }

  if (!worktreeOK) {
    assert(true, '#641-R1-CORUN: skipped (git unavailable in this environment)');
  } else {
    // -- CO-RUN + MERGE FENCE --------------------------------------------------
    {
      const { repoRoot, project, planPath, cacheDir } = makeRWRepo();
      // Tick 1: read-first partition opens g ALONE (G1 unchanged).
      const t1 = runNode(repoRoot, ['open-ready', '--project', project, '--json'], {});
      assert(t1.result === 'ok' && Array.isArray(t1.opened) && t1.opened.length === 1 && t1.opened[0].id === 'g',
        '#641-R1-CORUN t1: read-first partition opens g alone, got ' + JSON.stringify(t1.opened && t1.opened.map(n => n.id)));
      assert(!t1.laneGroup, '#641-R1-CORUN t1: no lane_group on the read open');
      assert(ledgerStatus(planPath, 'g') === 'in_progress' && ledgerStatus(planPath, 'w') === 'pending', '#641-R1-CORUN t1: g in_progress, w still pending');

      // Tick 2: the write-only frontier {w} arrives behind the LIVE read g → R1 co-opens w as a
      // LEG-CONTAINED lane group (instead of write_awaits_drain).
      const t2 = runNode(repoRoot, ['open-ready', '--project', project, '--json'], {});
      assert(t2.result === 'ok' && Array.isArray(t2.opened) && t2.opened.length === 1 && t2.opened[0].id === 'w',
        '#641-R1-CORUN t2: R1 co-opens the write w behind the live read (NOT write_awaits_drain), got ' + JSON.stringify({ opened: t2.opened && t2.opened.map(n => n.id), reason: t2.reason }));
      assert(t2.laneGroup && Array.isArray(t2.laneGroup.members) && t2.laneGroup.members.includes('w'),
        '#641-R1-CORUN t2: w co-opens as a size-1 lane group, got ' + JSON.stringify(t2.laneGroup));
      const rs2 = readRS(cacheDir);
      assert(rs2 && rs2.lane_group && rs2.lane_group.legs && rs2.lane_group.legs.w,
        '#641-R1-CORUN t2: co-open ⟹ a provisioned leg for w (the safe close path), got ' + JSON.stringify(rs2 && rs2.lane_group));
      assert(rs2.nodes.some(n => n.id === 'g' && n.kind === 'read') && rs2.nodes.some(n => n.id === 'w' && n.kind === 'write'),
        '#641-R1-CORUN t2: MIXED running set — the live read g alongside the leg-write w, got ' + JSON.stringify(rs2.nodes.map(n => ({ id: n.id, kind: n.kind }))));
      assert(ledgerStatus(planPath, 'w') === 'in_progress', '#641-R1-CORUN t2: w flipped in_progress');

      // MERGE FENCE (G4 retained): the last-member merge of w's group is HELD while the read g is still
      // live → close-node w refuses merge_awaits_read_drain (ZERO mutation). Seed real in-lane leg work
      // (so the per-member vacuity + leg barrier pass and the close reaches the merge fence).
      writeEvidence(cacheDir, 'w', 'tdd-guide');
      const legFileW = path.join(rs2.lane_group.legs.w.legPath, 'scripts', 'a.js');
      fs.mkdirSync(path.dirname(legFileW), { recursive: true });
      fs.writeFileSync(legFileW, '// w in-lane (leg)\n');
      const closeW = runNode(repoRoot, ['close-node', '--node-id', 'w', '--project', project, '--json'], {});
      assert(closeW.result === 'refuse' && closeW.reason === 'merge_awaits_read_drain',
        '#641-R1-CORUN merge-fence: the leg-write last-member merge is HELD while the read is live (merge_awaits_read_drain), got ' + JSON.stringify({ result: closeW.result, reason: closeW.reason }));
      assert(ledgerStatus(planPath, 'w') === 'in_progress', '#641-R1-CORUN merge-fence: ZERO mutation — w stays in_progress on the refuse');
      cleanup(repoRoot);
    }

    // -- CRASH-RECONCILE of a mixed read+leg-write running set ------------------
    {
      const { repoRoot, project, planPath, cacheDir } = makeRWRepo();
      runNode(repoRoot, ['open-ready', '--project', project, '--json'], {});      // tick1: open g
      const t2 = runNode(repoRoot, ['open-ready', '--project', project, '--json'], {}); // tick2: co-open w
      assert(t2.laneGroup && t2.laneGroup.members.includes('w'), '#641-R1-RECONCILE precondition: w co-opened as a lane group');
      // Simulate a crash mid-open: rewind the running set to state:'opening' with w flagged opening:true
      // (its ledger row DID flip to in_progress in tick 2 — the roll-FORWARD crash shape).
      const rsPath = path.join(cacheDir, 'running-set.json');
      const rs = JSON.parse(fs.readFileSync(rsPath, 'utf8'));
      rs.state = 'opening';
      rs.nodes = rs.nodes.map(n => (n.id === 'w' ? { ...n, opening: true } : n));
      fs.writeFileSync(rsPath, JSON.stringify(rs, null, 2));
      const rec = runNode(repoRoot, ['reconcile-running-set', '--project', project, '--json'], {});
      assert(rec.result === 'ok' && rec.reconciled === true, '#641-R1-RECONCILE: reconcile repairs the crashed mixed set, got ' + JSON.stringify({ result: rec.result, reconciled: rec.reconciled, reason: rec.reason }));
      const after = readRS(cacheDir);
      assert(after && after.state === 'open', '#641-R1-RECONCILE: state promoted back to open');
      assert(after.nodes.some(n => n.id === 'g') && after.nodes.some(n => n.id === 'w' && !n.opening),
        '#641-R1-RECONCILE: BOTH the live read g and the rolled-forward leg-write w survive, got ' + JSON.stringify(after.nodes.map(n => ({ id: n.id, opening: n.opening }))));
      assert(after.lane_group && after.lane_group.legs && after.lane_group.legs.w,
        '#641-R1-RECONCILE: the lane_group + its leg manifest survive the reconcile, got ' + JSON.stringify(after.lane_group));
      cleanup(repoRoot);
    }
  }
}

// ---------------------------------------------------------------------------
// #641-R2b CONSUMER (consent-tier) — over a DIRTY parent (R1's leg path can't apply: a leg would branch
// off HEAD and miss the uncommitted context), a LEGLESS writer may co-open behind an `observes: scratch`
// adversarial-verifier gate IFF every live read is such a gate AND the writer's declared set is
// scratch-observable-safe (the R2a predicate). Annotation ABSENT ⇒ serialize (write_awaits_drain,
// byte-identical). Direct runOpenReady unit calls (a LEGLESS open provisions NO leg ⇒ no real git).
// ---------------------------------------------------------------------------
{
  // A plan WITH the observes column so parseNodes surfaces the gate's annotation. `gate` (live read) +
  // `w` (ready write). role/observes/write-set parameterized.
  function makeObservesPlan(gateRole, gateObserves, writeRole, writeSet) {
    return [
      '# Workflow Plan — test-project', '',
      '## Meta', 'labels: area:scripts', '',
      '## Nodes', '',
      '| id | role | depends_on | declared_write_set | cardinality | shape | observes |',
      '| --- | --- | --- | --- | --- | --- | --- |',
      '| gate | ' + gateRole + ' | — | — | 1 | sequence | ' + gateObserves + ' |',
      '| w | ' + writeRole + ' | — | ' + writeSet + ' | 1 | sequence | — |', '',
      '## Node Ledger', '',
      '| id | status | notes |', '| --- | --- | --- |',
      '| gate | in_progress | |', '| w | pending | |', '',
    ].join('\n') + '\n';
  }
  function gateLiveSet(gateRole) {
    return JSON.stringify({ state: 'open', max_concurrent: 8, nodes: [{ id: 'gate', role: gateRole, kind: 'read', baseline: 'recorded' }] });
  }
  function dirtyParentStub(writeRole, writeSet) {
    return {
      shell: (base) => {
        if (base === 'kaola-workflow-next-action.js') return { exitCode: 0, result: 'ok', allDone: false, readyPending: [{ id: 'w', role: writeRole, declared_write_set: writeSet }] };
        if (base === 'kaola-workflow-commit-node.js') return { exitCode: 0, result: 'ok' };
        return { exitCode: 1, result: 'refuse' };
      },
      validator: (b, args) => {
        if (args.includes('--resume-check')) return { exitCode: 0, ok: true };
        if (args.includes('--parent-clean-check')) return { exitCode: 0, result: 'parent_dirty' }; // DIRTY parent
        return { exitCode: 0, result: 'ok' };
      },
    };
  }
  function runR2b(gateRole, gateObserves, writeRole, writeSet) {
    const stub = dirtyParentStub(writeRole, writeSet);
    const plan = makeObservesPlan(gateRole, gateObserves, writeRole, writeSet);
    const h = rsHarness({ [RS_PLAN_PATH]: plan, [RS_SET_PATH]: gateLiveSet(gateRole) }, stub.shell, stub.validator);
    const r = runOpenReady({ planPath: RS_PLAN_PATH, project: 'p', max: null, fanoutCapReadonly: 8, shell: h.shell, readFile: h.readFile, writeFile: h.writeFile, cacheExists: h.cacheExists, mkdirp: h.mkdirp });
    return { r, h };
  }

  // A: observes:scratch adversarial-verifier ∥ docs/decisions/** LEGLESS writer → CO-OPEN (legless, no
  //    leg group), even though the parent is dirty (the writer sees the uncommitted context; the scratch
  //    gate never observes its docs-band bytes — verdict from .cache + scratch, by contract).
  {
    const { r, h } = runR2b('adversarial-verifier', 'scratch', 'doc-updater', 'docs/decisions/D-641-01.md');
    assert(r.result === 'ok' && r.kind === 'write' && Array.isArray(r.opened) && r.opened.length === 1 && r.opened[0].id === 'w',
      '#641-R2b-A: observes:scratch gate ∥ docs/decisions writer CO-OPENS legless over a dirty parent, got ' + JSON.stringify({ opened: r.opened && r.opened.map(n => n.id), reason: r.reason, degrade: r.serialDegradeReason }));
    assert(!r.laneGroup, '#641-R2b-A: the co-open is LEGLESS (no lane group — the writer must see the uncommitted parent context)');
    const set = JSON.parse(h.files[RS_SET_PATH]);
    assert(!set.lane_group, '#641-R2b-A: running-set has NO lane_group (legless co-open)');
    assert(set.nodes.some(n => n.id === 'gate' && n.kind === 'read') && set.nodes.some(n => n.id === 'w' && n.kind === 'write'),
      '#641-R2b-A: MIXED running set — the scratch gate alongside the legless writer, got ' + JSON.stringify(set.nodes.map(n => ({ id: n.id, kind: n.kind }))));
    assert(h.files[RS_PLAN_PATH].includes('| w | in_progress | |'), '#641-R2b-A: w flipped in_progress');
    // The gate's dispatch discipline is pinned when it OPENS (a prior tick) — see #641-R2b-CARD below.
  }

  // B: observes:scratch gate ∥ a TEST-CONSUMED prose writer (docs/api.md) → HOLD (the writer's set is NOT
  //    scratch-observable-safe: a chain the gate could run reads it). Byte-identical parent_dirty hold.
  for (const bad of ['docs/api.md', 'CHANGELOG.md']) {
    const { r, h } = runR2b('adversarial-verifier', 'scratch', 'doc-updater', bad);
    assert(r.result === 'ok' && r.opened.length === 0 && r.reason === 'write_awaits_drain',
      '#641-R2b-B[' + bad + ']: a test-consumed-prose writer HOLDS behind the scratch gate, got ' + JSON.stringify({ opened: r.opened, reason: r.reason }));
    assert(r.serialDegradeReason === 'parent_dirty', '#641-R2b-B[' + bad + ']: labeled parent_dirty (R2b did not apply), got ' + JSON.stringify(r.serialDegradeReason));
    assert(h.files[RS_PLAN_PATH].includes('| w | pending | |'), '#641-R2b-B[' + bad + ']: ZERO mutation — w stays pending');
  }

  // C: an UN-annotated gate (a plain code-reviewer, no observes:scratch) ∥ a qualifying docs writer → HOLD.
  //    A full-diff observer is perturbed by a concurrent write; only the planner-declared scratch scope unlocks R2b.
  {
    const { r } = runR2b('code-reviewer', '—', 'doc-updater', 'docs/decisions/D-641-01.md');
    assert(r.result === 'ok' && r.opened.length === 0 && r.reason === 'write_awaits_drain',
      '#641-R2b-C: an un-annotated gate HOLDS even a qualifying writer, got ' + JSON.stringify({ opened: r.opened, reason: r.reason }));
    assert(r.serialDegradeReason === 'parent_dirty', '#641-R2b-C: labeled parent_dirty (no annotation ⇒ serialize), got ' + JSON.stringify(r.serialDegradeReason));
  }

  // D: un-annotated gate ∥ a SHARED-TREE (production) writer → HOLD (both the missing annotation AND the
  //    out-of-band write disqualify — a gate exists precisely to observe production changes).
  {
    const { r } = runR2b('code-reviewer', '—', 'implementer', 'scripts/x.js');
    assert(r.result === 'ok' && r.opened.length === 0 && r.reason === 'write_awaits_drain', '#641-R2b-D: shared-tree writer behind an un-annotated gate HOLDS, got ' + JSON.stringify({ opened: r.opened, reason: r.reason }));
    assert(r.serialDegradeReason === 'parent_dirty', '#641-R2b-D: labeled parent_dirty');
  }

  // E: even an ANNOTATED gate ∥ a SHARED-TREE (production) writer → HOLD (the annotation authorizes only a
  //    scratch-observable-safe write set; a production path is never observation-invisible).
  {
    const { r } = runR2b('adversarial-verifier', 'scratch', 'implementer', 'scripts/x.js');
    assert(r.result === 'ok' && r.opened.length === 0 && r.reason === 'write_awaits_drain', '#641-R2b-E: a production writer HOLDS even behind a scratch gate, got ' + JSON.stringify({ opened: r.opened, reason: r.reason }));
    assert(r.serialDegradeReason === 'parent_dirty', '#641-R2b-E: labeled parent_dirty (writer set not scratch-observable-safe)');
  }
}

// ---------------------------------------------------------------------------
// #641-R2b-CARD — the dispatch card the aggregator composes for an opened `observes: scratch`
// adversarial-verifier PINS the observation contract (verdict from .cache evidence of closed nodes +
// scratch only; do NOT read the worktree tree or diff). A plain read gate's card is byte-identical
// (no observation field). Direct runOpenReady unit call (read open ⇒ no leg / no real git).
// ---------------------------------------------------------------------------
{
  function makeGateOnlyPlan(gateObserves) {
    return [
      '# Workflow Plan — test-project', '',
      '## Meta', 'labels: area:scripts', '',
      '## Nodes', '',
      '| id | role | depends_on | declared_write_set | cardinality | shape | observes |',
      '| --- | --- | --- | --- | --- | --- | --- |',
      '| gate | adversarial-verifier | — | — | 1 | sequence | ' + gateObserves + ' |', '',
      '## Node Ledger', '',
      '| id | status | notes |', '| --- | --- | --- |',
      '| gate | pending | |', '',
    ].join('\n') + '\n';
  }
  function openGate(gateObserves) {
    const plan = makeGateOnlyPlan(gateObserves);
    const h = rsHarness({ [RS_PLAN_PATH]: plan }, (base) => {
      if (base === 'kaola-workflow-next-action.js') return { exitCode: 0, result: 'ok', allDone: false, readyPending: [{ id: 'gate', role: 'adversarial-verifier', declared_write_set: '—' }] };
      if (base === 'kaola-workflow-commit-node.js') return { exitCode: 0, result: 'ok' };
      return { exitCode: 1, result: 'refuse' };
    });
    return runOpenReady({ planPath: RS_PLAN_PATH, project: 'p', max: null, fanoutCapReadonly: 8, shell: h.shell, readFile: h.readFile, writeFile: h.writeFile, cacheExists: h.cacheExists, mkdirp: h.mkdirp });
  }
  // observes:scratch → the observation contract is pinned on the card.
  {
    const r = openGate('scratch');
    assert(r.result === 'ok' && r.opened.length === 1 && r.opened[0].dispatch, '#641-R2b-CARD: the scratch gate opens with a dispatch card');
    const obs = r.opened[0].dispatch.observation;
    assert(typeof obs === 'string' && /\.cache/.test(obs) && /scratch/.test(obs) && /do not read the worktree/i.test(obs),
      '#641-R2b-CARD: the observation contract is pinned (evidence + scratch only; do not read the worktree tree/diff), got ' + JSON.stringify(obs));
  }
  // un-annotated read gate → byte-identical (NO observation field).
  {
    const r = openGate('—');
    assert(r.result === 'ok' && r.opened.length === 1, '#641-R2b-CARD-neg: the plain gate opens');
    assert(r.opened[0].dispatch.observation === undefined, '#641-R2b-CARD-neg: a plain read gate card has NO observation field (byte-identical), got ' + JSON.stringify(r.opened[0].dispatch.observation));
  }
}

// ---------------------------------------------------------------------------
// SEED-arch (per-role evidence registry): open-next over a producer-role node (code-architect)
// SEEDS the NEW content-bearing token stubs (files_to_create + build_sequence) into
// .cache/<id>.md and emits them in the opened node's required_tokens. This is REGISTRY-DRIVEN:
// seedEvidenceFile + open-next already consume ROLE_TOKEN_REGISTRY, so adding the validator's
// rows is sufficient — no adaptive-node.js edit. Real temp dir so seedEvidenceFile's fs write
// lands (an in-memory writeFile map never captures it — seedEvidenceFile writes fs directly).
// NOTE: the CLOSE-time refusal on an empty producer token (checkEvidenceShape) is a separate
// deliverable — it lives in adaptive-node.js, not this seed half.
// ---------------------------------------------------------------------------
{
  const tmpDir = fs.mkdtempSync(path.join(os.tmpdir(), 'kw-seed-arch-'));
  try {
    const proj = path.join(tmpDir, 'kaola-workflow', 'test-project');
    fs.mkdirSync(proj, { recursive: true });
    const planPath = path.join(proj, 'workflow-plan.md');
    const statePath = path.join(proj, 'workflow-state.md');
    // Fixture: a code-architect producer node, pending, next to open.
    const plan = makePlan(
      ['| design | pending | |', '| impl | pending | |', '| finalize | pending | |'],
      [
        '| design | code-architect | — | — | 1 | sequence |',
        '| impl | implementer | design | scripts/x.js | 1 | sequence |',
        '| finalize | finalize | impl | CHANGELOG.md | 1 | sequence |',
      ]);
    fs.writeFileSync(planPath, plan);
    fs.writeFileSync(statePath, makeState());

    const shellStub = function(scriptPath, args) {
      const base = path.basename(scriptPath);
      const argsArr = args || [];
      if (base === 'kaola-workflow-plan-validator.js' && argsArr.includes('--resume-check')) return { exitCode: 0, ok: true };
      if (base === 'kaola-workflow-next-action.js') {
        return {
          exitCode: 0, result: 'ok',
          readySet: [{ id: 'design', role: 'code-architect', model: 'reasoning', declared_write_set: '—', dependsOn: [] }],
          nextNode: { id: 'design', role: 'code-architect', model: 'reasoning', declared_write_set: '—' },
          allDone: false,
        };
      }
      if (base === 'kaola-workflow-commit-node.js') {
        return { exitCode: 0, result: 'ok', mode: 'per-node-start', nodeId: 'design', overallOk: true, recordBase: { base: 'deadbeefcafe0000' } };
      }
      return { exitCode: 0 }; // best-effort (task-mirror etc.)
    };

    const result = runOpenNext({
      planPath, statePath, project: 'test-project', nodeId: null,
      shell: shellStub,
      readFile: (fpath) => fs.readFileSync(fpath, 'utf8'),
      writeFile: (fpath, content) => fs.writeFileSync(fpath, content),
    });

    assert(result.result === 'ok', 'SEED-arch: open-next ok, got ' + JSON.stringify({ result: result.result, reason: result.reason }));
    assert(result.opened && result.opened.role === 'code-architect', 'SEED-arch: opened the code-architect node, got ' + JSON.stringify(result.opened && result.opened.role));
    const rt = (result.opened && result.opened.required_tokens) || [];
    assert(rt.includes('files_to_create|files_to_modify'),
      'SEED-arch: required_tokens carries the files_to_create|files_to_modify class, got ' + JSON.stringify(rt));
    assert(rt.includes('build_sequence'),
      'SEED-arch: required_tokens carries build_sequence, got ' + JSON.stringify(rt));

    // The seeded evidence file carries the stub KEYS (the alternation seeds its FIRST alternative).
    const seeded = fs.readFileSync(path.join(proj, '.cache', 'design.md'), 'utf8');
    assert(/^evidence-binding: design /m.test(seeded), 'SEED-arch: line-1 binding header seeded, got:\n' + seeded);
    assert(/^files_to_create:\s*$/m.test(seeded), 'SEED-arch: files_to_create stub key seeded (first alternative), got:\n' + seeded);
    assert(/^build_sequence:\s*$/m.test(seeded), 'SEED-arch: build_sequence stub key seeded, got:\n' + seeded);
  } finally { try { fs.rmSync(tmpDir, { recursive: true, force: true }); } catch (_) {} }
}

// ===========================================================================
// Durable node channel + per-role close contract + scheduler gate-count residuals.
// The dispatch card carries the node's brief (goal_line) verbatim and the derived
// upstream_evidence pointers; the consumer proves it consumed each producer upstream
// (upstream_read echo), the close gate enforces registry content tokens for producer
// roles, and a live main-session-gate is counted as a live observer at co-open/merge.
// RED-first: these reference behaviors absent before the channel + gate-count edits.
// ===========================================================================
{
  const ADAPT = require('./kaola-workflow-adaptive-node');
  const VAL = require('./kaola-workflow-plan-validator');

  // A plan carrying a `## Node Briefs` section: design (code-architect producer, root) →
  // impl (tdd-guide consumer, depends on design). The impl brief spans two lines.
  const IMPL_BRIEF = 'Implement X per the design.\nRead design evidence first.';
  const DESIGN_BRIEF = 'Design X. Deliverable must carry files_to_create + build_sequence.';
  function channelPlan(ledger) {
    return [
      '# Workflow Plan — test-project', '',
      '## Meta', 'labels: area:scripts', '',
      '## Nodes', '',
      '| id | role | depends_on | declared_write_set | cardinality | shape |',
      '| --- | --- | --- | --- | --- | --- |',
      '| design | code-architect | — | — | 1 | sequence |',
      '| impl | tdd-guide | design | scripts/x.js | 1 | sequence |',
      '| finalize | finalize | impl | CHANGELOG.md | 1 | sequence |', '',
      '## Node Briefs', '',
      '### impl', 'Implement X per the design.', 'Read design evidence first.', '',
      '### design', DESIGN_BRIEF, '',
      '## Node Ledger', '',
      '| id | status |', '| --- | --- |',
      ...(ledger || ['| design | complete |', '| impl | in_progress |', '| finalize | pending |']),
      '',
    ].join('\n') + '\n';
  }

  // ---- V1: deriveDispatchChannel byte-for-byte + conditional-attach --------
  {
    if (typeof ADAPT.deriveDispatchChannel !== 'function') {
      assert(false, 'V1: deriveDispatchChannel must be exported');
    } else {
      const plan = channelPlan();
      const nodes = VAL.parseNodes(plan);
      const implNode = nodes.find(n => n.id === 'impl');
      const designNode = nodes.find(n => n.id === 'design');
      const ch = ADAPT.deriveDispatchChannel(plan, implNode, 'test-project');
      assert(ch.goal_line === IMPL_BRIEF,
        'V1: goal_line is the brief byte-for-byte, got ' + JSON.stringify(ch.goal_line));
      assert(Array.isArray(ch.upstream_evidence) && ch.upstream_evidence.length === 1,
        'V1: upstream_evidence has one entry, got ' + JSON.stringify(ch.upstream_evidence));
      const ue = ch.upstream_evidence[0];
      assert(ue.node_id === 'design' && ue.role === 'code-architect'
        && ue.path === 'kaola-workflow/test-project/.cache/design.md',
        'V1: upstream_evidence entry {node_id,role,path} project-qualified, got ' + JSON.stringify(ue));
      // ANTI-FABRICATION: the derived channel never carries a nonce anywhere.
      assert(!/[0-9a-f]{12}/.test(JSON.stringify(ch)),
        'V1: deriveDispatchChannel emits NO nonce (anti-fabrication), got ' + JSON.stringify(ch));
      // Root node (design) has a brief but NO deps ⇒ goal_line present, upstream_evidence absent.
      const chRoot = ADAPT.deriveDispatchChannel(plan, designNode, 'test-project');
      assert(chRoot.goal_line === DESIGN_BRIEF, 'V1: root node goal_line from its brief');
      assert(chRoot.upstream_evidence === undefined,
        'V1: root node has NO upstream_evidence field (byte-identical), got ' + JSON.stringify(chRoot.upstream_evidence));
    }
  }
  // Briefless / root back-compat: no ## Node Briefs and no deps ⇒ empty channel.
  {
    if (typeof ADAPT.deriveDispatchChannel === 'function') {
      const briefless = channelPlan().replace(/## Node Briefs[\s\S]*?## Node Ledger/, '## Node Ledger');
      const nodes = VAL.parseNodes(briefless);
      const ch = ADAPT.deriveDispatchChannel(briefless, nodes.find(n => n.id === 'design'), 'test-project');
      assert(ch.goal_line === undefined && ch.upstream_evidence === undefined,
        'V1: briefless root ⇒ empty channel (byte-identical), got ' + JSON.stringify(ch));
    }
  }
  // buildDispatch conditional-attach pin: with the fields set → attached; without → absent.
  {
    const withCh = buildDispatch({ id: 'impl', role: 'tdd-guide', model: null, declared_write_set: 'scripts/x.js' },
      { goal_line: IMPL_BRIEF, upstream_evidence: [{ node_id: 'design', role: 'code-architect', path: 'kaola-workflow/test-project/.cache/design.md' }] });
    assert(withCh.goal_line === IMPL_BRIEF, 'V1: buildDispatch attaches goal_line');
    assert(Array.isArray(withCh.upstream_evidence) && withCh.upstream_evidence.length === 1,
      'V1: buildDispatch attaches upstream_evidence when present, got ' + JSON.stringify(withCh.upstream_evidence));
    const without = buildDispatch({ id: 'root', role: 'code-explorer', model: null, declared_write_set: '—' }, {});
    assert(without.goal_line === undefined && without.upstream_evidence === undefined,
      'V1: buildDispatch omits goal_line/upstream_evidence for a briefless/root card (byte-identical)');
  }

  // ---- V1 integration + V2 + V3: real tmpdir open/close/close-refuse -------
  {
    const tmp = fs.mkdtempSync(path.join(os.tmpdir(), 'kw-channel-'));
    try {
      const proj = path.join(tmp, 'kaola-workflow', 'test-project');
      const cache = path.join(proj, '.cache');
      fs.mkdirSync(cache, { recursive: true });
      const planPath = path.join(proj, 'workflow-plan.md');
      const statePath = path.join(proj, 'workflow-state.md');
      fs.writeFileSync(statePath, makeState());
      const rf = (p) => fs.readFileSync(p, 'utf8');
      const wf = (p, c) => fs.writeFileSync(p, c);

      // Open-next over impl (design already complete) — the fused-advance is not used; open-next opens
      // the next-action nextNode directly. Stub next-action to name impl and commit-node to record a base.
      fs.writeFileSync(planPath, channelPlan());
      const openShell = function(scriptPath, args) {
        const base = path.basename(scriptPath);
        const a = args || [];
        if (base === 'kaola-workflow-plan-validator.js' && a.includes('--resume-check')) return { exitCode: 0, ok: true };
        if (base === 'kaola-workflow-next-action.js') {
          return { exitCode: 0, result: 'ok', allDone: false,
            readySet: [{ id: 'impl', role: 'tdd-guide', model: null, declared_write_set: 'scripts/x.js', dependsOn: ['design'] }],
            nextNode: { id: 'impl', role: 'tdd-guide', model: null, declared_write_set: 'scripts/x.js' } };
        }
        if (base === 'kaola-workflow-commit-node.js') {
          return { exitCode: 0, result: 'ok', mode: 'per-node-start', nodeId: 'impl', overallOk: true, recordBase: { base: 'aaaabbbbcccc0000' } };
        }
        return { exitCode: 0 };
      };
      const opened = runOpenNext({ planPath, statePath, project: 'test-project', nodeId: null, shell: openShell, readFile: rf, writeFile: wf });
      assert(opened.result === 'ok' && opened.opened && opened.opened.dispatch, 'V1-int: open-next ok with a dispatch card');
      const disp = opened.opened.dispatch;
      assert(disp.goal_line === IMPL_BRIEF, 'V1-int: card goal_line is the impl brief, got ' + JSON.stringify(disp.goal_line));
      assert(Array.isArray(disp.upstream_evidence) && disp.upstream_evidence[0]
        && disp.upstream_evidence[0].node_id === 'design'
        && disp.upstream_evidence[0].path === 'kaola-workflow/test-project/.cache/design.md',
        'V1-int: card upstream_evidence points to design (project-qualified), got ' + JSON.stringify(disp.upstream_evidence));
      // V2 neg-3 fabrication grep: the SERIALIZED open envelope carries NO upstream nonce anywhere.
      // design's line-1 nonce is defined below; assert the open envelope never contains ANY 12-hex token.
      const openSerialized = JSON.stringify(opened);
      assert(!/upstream_read/.test(openSerialized),
        'V2-neg3: the open envelope carries NO upstream_read echo (anti-fabrication)');

      // The impl seed carries an EMPTY `upstream_read: design` stub (producer upstream, IMPLEMENT consumer).
      const implSeed = fs.readFileSync(path.join(cache, 'impl.md'), 'utf8');
      assert(/^upstream_read:[ \t]+design[ \t]*$/m.test(implSeed),
        'V2-seed: impl seed carries an EMPTY `upstream_read: design` stub (no nonce), got:\n' + implSeed);
      assert(!/upstream_read:[ \t]+design[ \t]+\S/.test(implSeed),
        'V2-seed: the seeded upstream_read stub has NO nonce (anti-fabrication)');

      // Write design's completed evidence with a KNOWN line-1 nonce.
      const DESIGN_NONCE = 'd0d0d0d0d0d0';
      fs.writeFileSync(path.join(cache, 'design.md'),
        'evidence-binding: design ' + DESIGN_NONCE + '\nfiles_to_create: a.js\nbuild_sequence: a then b\n');
      // The impl node's open-time nonce = commit-node base slice(0,12).
      const IMPL_NONCE = 'aaaabbbbcccc';
      const implBinding = 'evidence-binding: impl ' + IMPL_NONCE + '\n';
      const implBody = 'RED: t_x — AssertionError (pre-impl)\nGREEN: t_x passes; 1/1 green\n';

      // ---- checkUpstreamConsumed direct: happy / neg-1 missing / advisory ----
      if (typeof ADAPT.checkUpstreamConsumed !== 'function') {
        assert(false, 'V2: checkUpstreamConsumed must be exported');
      } else {
        const nodes = VAL.parseNodes(channelPlan());
        const statuses = { design: 'complete', impl: 'in_progress', finalize: 'pending' };
        // happy: correct echo of design's line-1 nonce.
        const okEv = implBinding + implBody + 'upstream_read: design ' + DESIGN_NONCE + '\n';
        const rOk = ADAPT.checkUpstreamConsumed({ role: 'tdd-guide', nodeId: 'impl', evidenceContent: okEv, nodes, ledgerStatuses: statuses, planPath, project: 'test-project', readFile: rf });
        assert(rOk.ok === true, 'V2-happy: a matching upstream_read echo ⇒ consumed ok, got ' + JSON.stringify(rOk));
        // neg-1: KEY present (seeded) but NO nonce ⇒ hard refuse for an IMPLEMENT consumer.
        const missEv = implBinding + implBody + 'upstream_read: design\n';
        const rMiss = ADAPT.checkUpstreamConsumed({ role: 'tdd-guide', nodeId: 'impl', evidenceContent: missEv, nodes, ledgerStatuses: statuses, planPath, project: 'test-project', readFile: rf });
        assert(rMiss.ok === false && rMiss.hard === true && rMiss.offending === 'design' && rMiss.reason === 'upstream_not_consumed',
          'V2-neg1: a missing nonce echo ⇒ hard upstream_not_consumed, got ' + JSON.stringify(rMiss));
        // neg-2: STALE nonce (design rotated to a different line-1 nonce) ⇒ mismatch refuse.
        const staleEv = implBinding + implBody + 'upstream_read: design deadbeefdead\n';
        const rStale = ADAPT.checkUpstreamConsumed({ role: 'tdd-guide', nodeId: 'impl', evidenceContent: staleEv, nodes, ledgerStatuses: statuses, planPath, project: 'test-project', readFile: rf });
        assert(rStale.ok === false && rStale.hard === true && rStale.offending === 'design',
          'V2-neg2: a stale nonce echo ⇒ hard upstream_not_consumed, got ' + JSON.stringify(rStale));
        // back-compat (DD-5): KEY ABSENT (old in-flight consumer) ⇒ exempt (ok).
        const noKeyEv = implBinding + implBody;
        const rNoKey = ADAPT.checkUpstreamConsumed({ role: 'tdd-guide', nodeId: 'impl', evidenceContent: noKeyEv, nodes, ledgerStatuses: statuses, planPath, project: 'test-project', readFile: rf });
        assert(rNoKey.ok === true, 'V2-backcompat: absent upstream_read KEY ⇒ exempt, got ' + JSON.stringify(rNoKey));
        // advisory: a GATE (non-IMPLEMENT) depending on a producer ⇒ hard:false even on a miss.
        const gateNodes = VAL.parseNodes(channelPlan(['| design | complete |', '| gate | in_progress |', '| finalize | pending |'])
          .replace('| impl | tdd-guide | design | scripts/x.js | 1 | sequence |', '| gate | adversarial-verifier | design | — | 1 | sequence |')
          .replace('### impl\nImplement X per the design.\nRead design evidence first.\n\n', ''));
        const rAdv = ADAPT.checkUpstreamConsumed({ role: 'adversarial-verifier', nodeId: 'gate', evidenceContent: 'evidence-binding: gate x\nverdict: pass\nupstream_read: design\n', nodes: gateNodes, ledgerStatuses: { design: 'complete', gate: 'in_progress' }, planPath, project: 'test-project', readFile: rf });
        assert(rAdv.ok === false && rAdv.hard === false && rAdv.offending === 'design',
          'V2-advisory: producer→gate miss is advisory (hard:false), got ' + JSON.stringify(rAdv));
      }

      // ---- V2 close integration: neg-1 refuses upstream_not_consumed with ZERO mutation ----
      {
        // barrier-base-impl carries the open nonce so the binding check passes.
        fs.writeFileSync(path.join(cache, 'barrier-base-impl'), 'aaaabbbbcccc0000\n');
        fs.writeFileSync(path.join(cache, 'impl.md'), implBinding + implBody + 'upstream_read: design\n'); // KEY present, NO nonce
        const before = fs.readFileSync(planPath, 'utf8');
        const closeShell = function(scriptPath) {
          const base = path.basename(scriptPath);
          if (base === 'kaola-workflow-commit-node.js') { assert(false, 'V2-neg1: barrier must NOT be reached (refuse is before the barrier)'); return { exitCode: 1 }; }
          return { exitCode: 0, result: 'ok' };
        };
        const rClose = runCloseAndOpenNext({ planPath, statePath, project: 'test-project', nodeId: 'impl', shell: closeShell, readFile: rf, writeFile: wf, cacheExists: (p) => fs.existsSync(p) });
        assert(rClose.result === 'refuse' && rClose.reason === 'upstream_not_consumed' && rClose.offending === 'design',
          'V2-neg1-close: close refuses upstream_not_consumed, got ' + JSON.stringify({ result: rClose.result, reason: rClose.reason, offending: rClose.offending }));
        const after = fs.readFileSync(planPath, 'utf8');
        assert(before === after, 'V2-neg1-close: ZERO ledger mutation on the upstream_not_consumed refuse');
        assert(typeof rClose.operator_hint === 'string' && rClose.operator_hint.length > 0,
          'V2-neg1-close: an operator_hint accompanies the refuse');
      }

      // ---- V3: resume re-hydration — the card re-derives from durable plan state alone ----
      {
        if (typeof ADAPT.deriveDispatchChannel === 'function') {
          const planContent = fs.readFileSync(planPath, 'utf8');
          const nodes = VAL.parseNodes(planContent);
          const a = ADAPT.deriveDispatchChannel(planContent, nodes.find(n => n.id === 'impl'), 'test-project');
          const b = ADAPT.deriveDispatchChannel(planContent, nodes.find(n => n.id === 'impl'), 'test-project');
          assert(JSON.stringify(a) === JSON.stringify(b) && a.goal_line === IMPL_BRIEF,
            'V3: a fresh-shell re-derivation of goal_line + upstream_evidence from the frozen plan is deterministic');
          // The cached open envelope (opened.dispatch) is the authoritative re-dispatch context.
          assert(opened.opened.dispatch.goal_line === IMPL_BRIEF
            && Array.isArray(opened.opened.dispatch.upstream_evidence),
            'V3: the cached open envelope carries goal_line + upstream_evidence for re-hydration');
        }
      }

      // ---- V6: truncated producer evidence → evidence_shape_failed at CLOSE ----
      {
        // A code-architect (producer) whose evidence is truncated: the files_to_create|files_to_modify
        // and build_sequence KEYS are seeded (present) but EMPTY ⇒ the generalized checkEvidenceShape
        // must refuse at close. Direct checkEvidenceShape assertion (the close gate uses the same fn).
        const truncated = 'evidence-binding: design d0d0d0d0d0d0\nfiles_to_create: \nbuild_sequence: \n';
        const shape = checkEvidenceShape('code-architect', 'design', truncated, {});
        assert(shape.ok === false,
          'V6: a code-architect with EMPTY seeded content tokens fails checkEvidenceShape, got ' + JSON.stringify(shape));
        // A non-empty producer evidence passes.
        const full = 'evidence-binding: design d0d0d0d0d0d0\nfiles_to_create: a.js\nbuild_sequence: a then b\n';
        assert(checkEvidenceShape('code-architect', 'design', full, {}).ok === true,
          'V6: a non-empty producer evidence passes the generalized shape check');
        // Alternation: files_to_modify alone (the other alternative) satisfies.
        const alt = 'evidence-binding: design d0d0d0d0d0d0\nfiles_to_modify: b.js\nbuild_sequence: x\n';
        assert(checkEvidenceShape('code-architect', 'design', alt, {}).ok === true,
          'V6: the files_to_create|files_to_modify alternation is satisfied by EITHER alternative');
        // A key ABSENT entirely (old in-flight producer) ⇒ exempt (non-empty fallback still passes).
        const legacy = 'evidence-binding: design d0d0d0d0d0d0\nsome free-form producer notes\n';
        assert(checkEvidenceShape('code-architect', 'design', legacy, {}).ok === true,
          'V6-backcompat: a producer evidence with the content KEYS absent falls back to non-empty (in-flight exempt)');
        // tdd-guide branch uses its stricter non-empty RED:/GREEN: shape.
        assert(checkEvidenceShape('tdd-guide', 'n', 'evidence-binding: n x\nsome notes\n', {}).ok === false,
          'V6: tdd-guide branch untouched (missing RED token still refuses)');
      }
    } finally { try { fs.rmSync(tmp, { recursive: true, force: true }); } catch (_) {} }
  }

  // ---- #644 A1: a live kind:'gate' holds the relaxed write co-open (gate_live) --------
  {
    const gatePlan = makePlan([
      '| gate | in_progress |',
      '| doc | pending |',
      '| finalize | pending |',
    ], [
      '| gate | main-session-gate | — | — | 1 | sequence |',
      '| doc | doc-updater | — | docs/api.md | 1 | sequence |',
      '| finalize | finalize | gate doc | CHANGELOG.md | 1 | sequence |',
    ]);
    // The running set already holds the live gate (kind:'gate').
    const liveSet = JSON.stringify({ state: 'open', nodes: [
      { id: 'gate', role: 'main-session-gate', kind: 'gate', declared_write_set: '—', baseline: 'recorded' },
    ] }, null, 2);
    const h = rsHarness({ [RS_PLAN_PATH]: gatePlan, [RS_SET_PATH]: liveSet }, (base) => {
      if (base === 'kaola-workflow-next-action.js') {
        return { exitCode: 0, result: 'ok', allDone: false, readyPending: [
          { id: 'doc', role: 'doc-updater', declared_write_set: 'docs/api.md' },
        ] };
      }
      if (base === 'kaola-workflow-commit-node.js') return { exitCode: 0, result: 'ok' };
      return { exitCode: 1, result: 'refuse' };
    });
    const r = withParallelWrites(undefined, () => runOpenReady({ planPath: RS_PLAN_PATH, project: 'p', max: null, fanoutCapReadonly: 8, shell: h.shell, readFile: h.readFile, writeFile: h.writeFile, cacheExists: h.cacheExists, mkdirp: h.mkdirp }));
    assert(r.result === 'ok' && r.reason === 'write_awaits_drain' && (r.opened || []).length === 0,
      'A1-coopen-hold: the writer is HELD while a gate is live, got ' + JSON.stringify({ result: r.result, reason: r.reason, opened: (r.opened || []).length }));
    assert(r.serialDegradeReason === 'gate_live',
      'A1-coopen-hold: serialDegradeReason is gate_live, got ' + JSON.stringify(r.serialDegradeReason));
  }
  // A1 byte-identical serial fallback: NO running set (no gate) ⇒ the else-branch never fires.
  {
    const wPlan = makePlan([
      '| w | pending |', '| finalize | pending |',
    ], [
      '| w | tdd-guide | — | scripts/w.js | 1 | sequence |',
      '| finalize | finalize | w | CHANGELOG.md | 1 | sequence |',
    ]);
    const h = rsHarness({ [RS_PLAN_PATH]: wPlan }, (base) => {
      if (base === 'kaola-workflow-next-action.js') return { exitCode: 0, result: 'ok', allDone: false, readyPending: [{ id: 'w', role: 'tdd-guide', declared_write_set: 'scripts/w.js' }] };
      if (base === 'kaola-workflow-commit-node.js') return { exitCode: 0, result: 'ok' };
      return { exitCode: 1, result: 'refuse' };
    });
    const r = withParallelWrites('0', () => runOpenReady({ planPath: RS_PLAN_PATH, project: 'p', max: null, fanoutCapReadonly: 8, shell: h.shell, readFile: h.readFile, writeFile: h.writeFile, cacheExists: h.cacheExists, mkdirp: h.mkdirp }));
    assert(r.result === 'ok' && (r.opened || []).length === 1 && r.kind === 'write',
      'A1-serial-fallback: a lone write opens serially with no running set, got ' + JSON.stringify({ opened: (r.opened || []).length, kind: r.kind }));
    assert(r.serialDegradeReason !== 'gate_live',
      'A1-serial-fallback: the serial path never emits gate_live (byte-identical)');
  }
  // A1 merge-fence-hold: a live gate holds the lane-group last-member merge.
  {
    const grpPlan = makePlan([
      '| w | in_progress |', '| gate | in_progress |', '| finalize | pending |',
    ], [
      '| w | tdd-guide | — | — | 1 | sequence |',
      '| gate | main-session-gate | — | — | 1 | sequence |',
      '| finalize | finalize | w gate | CHANGELOG.md | 1 | sequence |',
    ]);
    // A legless single-member lane group (member w) + a live gate in the running set.
    const grpSet = JSON.stringify({ state: 'open', lane_group: { group_id: 'lg1', members: ['w'], closed_members: [] }, nodes: [
      { id: 'w', role: 'tdd-guide', kind: 'write', declared_write_set: '—', group_id: 'lg1' },
      { id: 'gate', role: 'main-session-gate', kind: 'gate', declared_write_set: '—' },
    ] }, null, 2);
    // w's evidence: RED/GREEN + no_op (empty declared set ⇒ vacuity guard needs a no_op declaration).
    const wEv = 'evidence-binding: w x\nRED: t (pre)\nGREEN: t passes\nno_op: legless test member\n';
    const h = rsHarness({ [RS_PLAN_PATH]: grpPlan, [RS_SET_PATH]: grpSet, ['/p/.cache/w.md']: wEv }, (base) => {
      if (base === 'kaola-workflow-next-action.js') return { exitCode: 0, result: 'ok', allDone: false, readyPending: [] };
      if (base === 'kaola-workflow-commit-node.js') return { exitCode: 0, result: 'ok' };
      return { exitCode: 0, result: 'ok' };
    });
    const r = runCloseNode({ planPath: RS_PLAN_PATH, project: 'p', nodeId: 'w', shell: h.shell, readFile: h.readFile, writeFile: h.writeFile, cacheExists: h.cacheExists, mkdirp: h.mkdirp, unlink: h.unlink });
    assert(r.result === 'refuse' && r.reason === 'merge_awaits_read_drain',
      'A1-merge-fence-hold: the last-member merge is held while a gate is live, got ' + JSON.stringify({ result: r.result, reason: r.reason }));
  }

  // ---- #644 A2: validation_test_consumes widens the R2b legless co-open predicate --------
  {
    if (typeof ADAPT.tryR2bLeglessCoopen !== 'function') {
      assert(false, 'A2: tryR2bLeglessCoopen must be exported for the fork-widening pin');
    } else {
      const forkPlan = [
        '# Workflow Plan — test-project', '',
        '## Meta', 'labels: area:scripts', 'validation_test_consumes: docs/fork-guide.md', '',
        '## Nodes', '',
        '| id | role | depends_on | declared_write_set | cardinality | shape | observes |',
        '| --- | --- | --- | --- | --- | --- | --- |',
        '| gate | adversarial-verifier | — | — | 1 | sequence | scratch |',
        '| forkw | doc-updater | — | docs/fork-guide.md | 1 | sequence | — |', '',
        '## Node Ledger', '',
        '| id | status |', '| --- | --- |', '| gate | in_progress |', '| forkw | pending |', '',
      ].join('\n') + '\n';
      const files = { '/p/workflow-plan.md': forkPlan };
      const rf = (p) => { if (p in files) return files[p]; throw new Error('ENOENT ' + p); };
      const writeNodes = [{ id: 'forkw', role: 'doc-updater', declared_write_set: 'docs/fork-guide.md' }];
      const liveNodes = [{ id: 'gate', role: 'adversarial-verifier', kind: 'read' }];
      const chosen = ADAPT.tryR2bLeglessCoopen(writeNodes, liveNodes, '/p/workflow-plan.md', 'test-project', rf);
      assert(chosen === null,
        'A2: a validation_test_consumes doc (docs/fork-guide.md) is NOT scratch-observable-safe ⇒ NO legless co-open, got ' + JSON.stringify(chosen && chosen.id));
      // Control: WITHOUT the widening, the same docs writer IS scratch-observable-safe (co-opens).
      const noWiden = forkPlan.replace('validation_test_consumes: docs/fork-guide.md\n', '');
      const files2 = { '/p/workflow-plan.md': noWiden };
      const rf2 = (p) => { if (p in files2) return files2[p]; throw new Error('ENOENT ' + p); };
      const chosen2 = ADAPT.tryR2bLeglessCoopen(writeNodes, liveNodes, '/p/workflow-plan.md', 'test-project', rf2);
      assert(chosen2 && chosen2.id === 'forkw',
        'A2-control: a plain docs writer behind a scratch gate DOES legless co-open (widening is the only difference), got ' + JSON.stringify(chosen2 && chosen2.id));
    }
  }
}

// ---------------------------------------------------------------------------
// Universal n/a skip in the consumed-proof: an IMPLEMENT consumer skipped mid-run records
// `n/a — <reason>` evidence — the seeded `upstream_read:` key is present but carries no echo.
// checkEvidenceShape passes such evidence via its universal n/a carve-out; checkUpstreamConsumed
// must AGREE (a skipped consumer proves nothing), never hard-refuse upstream_not_consumed.
// The two close gates must render the same verdict on the same n/a evidence.
// ---------------------------------------------------------------------------
{
  const ADAPT = require('./kaola-workflow-adaptive-node');
  const VAL = require('./kaola-workflow-plan-validator');
  const tmp = fs.mkdtempSync(path.join(os.tmpdir(), 'kw-na-consumed-'));
  try {
    const proj = path.join(tmp, 'kaola-workflow', 'test-project');
    const cache = path.join(proj, '.cache');
    fs.mkdirSync(cache, { recursive: true });
    const planPath = path.join(proj, 'workflow-plan.md');
    const statePath = path.join(proj, 'workflow-state.md');
    const plan = [
      '# Workflow Plan — test-project', '',
      '## Meta', 'labels: area:scripts', '',
      '## Nodes', '',
      '| id | role | depends_on | declared_write_set | cardinality | shape |',
      '| --- | --- | --- | --- | --- | --- |',
      '| design | code-architect | — | — | 1 | sequence |',
      '| impl | tdd-guide | design | scripts/x.js | 1 | sequence |',
      '| finalize | finalize | impl | CHANGELOG.md | 1 | sequence |', '',
      '## Node Ledger', '',
      '| id | status |', '| --- | --- |',
      '| design | complete |', '| impl | in_progress |', '| finalize | pending |', '',
    ].join('\n') + '\n';
    fs.writeFileSync(planPath, plan);
    fs.writeFileSync(statePath, makeState());
    const rf = (p) => fs.readFileSync(p, 'utf8');
    const wf = (p, c) => fs.writeFileSync(p, c);
    // design's completed evidence with a known line-1 nonce (the echo the skipped consumer never made).
    fs.writeFileSync(path.join(cache, 'design.md'),
      'evidence-binding: design d0d0d0d0d0d0\nfiles_to_create: a.js\nbuild_sequence: a then b\n');
    // impl's open-time nonce on disk (the close-side binding check reads it).
    fs.writeFileSync(path.join(cache, 'barrier-base-impl'), 'aaaabbbbcccc0000\n');
    // impl's evidence: an n/a SKIP — content starts with n/a (the universal carve-out shape), carries the
    // binding line + the seeded upstream_read key, and NO nonce echo (a skipped consumer read nothing).
    const naEv = 'n/a — descoped mid-run (covered upstream)\nevidence-binding: impl aaaabbbbcccc\nupstream_read: design\n';
    fs.writeFileSync(path.join(cache, 'impl.md'), naEv);
    const nodes = VAL.parseNodes(plan);
    // Direct: the consumed-proof honors the universal n/a skip (mirrors checkEvidenceShape's carve-out).
    const r = ADAPT.checkUpstreamConsumed({ role: 'tdd-guide', nodeId: 'impl', evidenceContent: naEv, nodes,
      ledgerStatuses: { design: 'complete', impl: 'in_progress', finalize: 'pending' },
      planPath, project: 'test-project', readFile: rf });
    assert(r.ok === true && r.hard === false,
      'NA-skip: an n/a-skipped consumer is exempt from the consumed-proof, got ' + JSON.stringify(r));
    // Close path: the SAME n/a evidence that checkEvidenceShape passes must NOT refuse upstream_not_consumed.
    const shellStub = (scriptPath, args) => {
      const base = path.basename(scriptPath);
      const a = args || [];
      if (base === 'kaola-workflow-plan-validator.js' && a.includes('--resume-check')) return { exitCode: 0, ok: true };
      if (base === 'kaola-workflow-commit-node.js') return { exitCode: 0, result: 'ok' };
      if (base === 'kaola-workflow-next-action.js') return { exitCode: 0, result: 'ok', allDone: true };
      return { exitCode: 0 };
    };
    const rClose = runCloseAndOpenNext({ planPath, statePath, project: 'test-project', nodeId: 'impl',
      shell: shellStub, readFile: rf, writeFile: wf, cacheExists: (p) => fs.existsSync(p) });
    assert(rClose.reason !== 'upstream_not_consumed',
      'NA-skip-close: close does NOT refuse upstream_not_consumed on an n/a-skipped consumer, got ' + JSON.stringify({ result: rClose.result, reason: rClose.reason }));
  } finally { try { fs.rmSync(tmp, { recursive: true, force: true }); } catch (_) {} }
}

// ---------------------------------------------------------------------------
// Fused-advance gate-window hold: close-and-open-next must NOT open the next node while a
// main-session-gate is live in the running set (kind:'gate'). The serial open-next door refuses
// scheduler_active and open-ready holds gate_live — without this hold the FUSED advance was the
// one unfenced door (a table-order-dependent bypass of the gate-window invariant: the next pending
// writer opened in_progress WHILE the gate was live). Pinned for BOTH ## Nodes table orders
// (writer-rows-first AND gate-row-first) so the hold is order-INDEPENDENT, plus a no-gate control
// (the fused advance stays byte-identical when no gate is live).
// ---------------------------------------------------------------------------
{
  function fusedGatePlan(order) {
    const waRow = '| wa | tdd-guide | — | scripts/a.js | 1 | sequence |';
    const wbRow = '| wb | tdd-guide | wa | scripts/b.js | 1 | sequence |';
    const g1Row = '| g1 | main-session-gate | — | — | 1 | sequence |';
    const finRow = '| finalize | finalize | wb g1 | CHANGELOG.md | 1 | sequence |';
    const nodeRows = order === 'gate-first' ? [g1Row, waRow, wbRow, finRow] : [waRow, wbRow, g1Row, finRow];
    return [
      '# Workflow Plan — test-project', '',
      '## Meta', 'labels: area:scripts', '',
      '## Nodes', '',
      '| id | role | depends_on | declared_write_set | cardinality | shape |',
      '| --- | --- | --- | --- | --- | --- |',
      ...nodeRows, '',
      '## Node Ledger', '',
      '| id | status |', '| --- | --- |',
      '| wa | in_progress |', '| wb | pending |', '| g1 | in_progress |', '| finalize | pending |', '',
    ].join('\n') + '\n';
  }
  function runFusedClose(order, gateLiveInSet) {
    const tmp = fs.mkdtempSync(path.join(os.tmpdir(), 'kw-fused-gate-'));
    try {
      const proj = path.join(tmp, 'kaola-workflow', 'test-project');
      const cache = path.join(proj, '.cache');
      fs.mkdirSync(cache, { recursive: true });
      const planPath = path.join(proj, 'workflow-plan.md');
      const statePath = path.join(proj, 'workflow-state.md');
      const plan = gateLiveInSet ? fusedGatePlan(order)
        // no-gate control: g1 not yet opened (pending ledger row, empty running set).
        : fusedGatePlan(order).replace('| g1 | in_progress |', '| g1 | pending |');
      fs.writeFileSync(planPath, plan);
      fs.writeFileSync(statePath, makeState());
      // wa's open-time nonce + shape-valid tdd-guide evidence.
      fs.writeFileSync(path.join(cache, 'barrier-base-wa'), 'aaaabbbbcccc0000\n');
      fs.writeFileSync(path.join(cache, 'wa.md'),
        'evidence-binding: wa aaaabbbbcccc\nRED: t (pre)\nGREEN: t passes; 1/1 green\n');
      // The live gate window: g1 recorded as kind:'gate' (the open-next door already recorded it).
      if (gateLiveInSet) {
        fs.writeFileSync(path.join(cache, 'running-set.json'), JSON.stringify({ state: 'open', nodes: [
          { id: 'g1', role: 'main-session-gate', kind: 'gate', declared_write_set: '—', baseline: 'recorded' },
        ] }, null, 2));
      }
      const shellStub = (scriptPath, args) => {
        const base = path.basename(scriptPath);
        const a = args || [];
        if (base === 'kaola-workflow-plan-validator.js' && a.includes('--resume-check')) return { exitCode: 0, ok: true };
        if (base === 'kaola-workflow-commit-node.js' && a.includes('--start')) {
          return { exitCode: 0, result: 'ok', mode: 'per-node-start', overallOk: true, recordBase: { base: 'bbbbccccdddd0000' } };
        }
        if (base === 'kaola-workflow-commit-node.js') return { exitCode: 0, result: 'ok' };
        if (base === 'kaola-workflow-next-action.js') {
          // next-action surfaces the pending writer wb as the single fused-advance target
          // (the gate is excluded from readyPending per the main-session rule).
          return { exitCode: 0, result: 'ok', allDone: false,
            readyPending: [{ id: 'wb', role: 'tdd-guide', model: null, declared_write_set: 'scripts/b.js' }],
            nextNode: { id: 'wb', role: 'tdd-guide', model: null, declared_write_set: 'scripts/b.js' } };
        }
        return { exitCode: 0 };
      };
      const r = runCloseAndOpenNext({ planPath, statePath, project: 'test-project', nodeId: 'wa',
        shell: shellStub, readFile: (p) => fs.readFileSync(p, 'utf8'), writeFile: (p, c) => fs.writeFileSync(p, c),
        cacheExists: (p) => fs.existsSync(p), unlink: (p) => fs.unlinkSync(p) });
      const ledgerBody = fs.readFileSync(planPath, 'utf8');
      const ledgerStart = ledgerBody.indexOf('## Node Ledger');
      const wbLedger = ((ledgerStart >= 0 ? ledgerBody.slice(ledgerStart) : ledgerBody).match(/^\|\s*wb\s*\|\s*(\S+)\s*\|/m) || [])[1] || null;
      return { r, wbLedger };
    } finally { try { fs.rmSync(tmp, { recursive: true, force: true }); } catch (_) {} }
  }
  // BOTH table orders: with g1 live (kind:'gate'), the fused advance returns CLOSED-ONLY (order-independent).
  for (const order of ['writer-first', 'gate-first']) {
    const { r, wbLedger } = runFusedClose(order, true);
    assert(r.result === 'ok' && r.closed === 'wa', 'FUSED-GATE-HOLD(' + order + '): wa closes ok, got ' + JSON.stringify({ result: r.result, closed: r.closed, reason: r.reason }));
    assert(r.opened === null, 'FUSED-GATE-HOLD(' + order + '): opened is null while the gate is live, got ' + JSON.stringify(r.opened && r.opened.id));
    assert(r.reason === 'gate_live', 'FUSED-GATE-HOLD(' + order + '): typed reason gate_live, got ' + JSON.stringify(r.reason));
    assert(wbLedger === 'pending', 'FUSED-GATE-HOLD(' + order + '): wb ledger row stays pending (no open mutation), got ' + JSON.stringify(wbLedger));
  }
  // Control: NO live gate ⇒ the fused advance opens wb exactly as before (byte-identical no-gate path).
  for (const order of ['writer-first', 'gate-first']) {
    const { r, wbLedger } = runFusedClose(order, false);
    assert(r.result === 'ok' && r.closed === 'wa' && r.opened && r.opened.id === 'wb',
      'FUSED-GATE-CONTROL(' + order + '): no live gate ⇒ fused advance opens wb, got ' + JSON.stringify({ opened: r.opened && r.opened.id, reason: r.reason }));
    assert(wbLedger === 'in_progress', 'FUSED-GATE-CONTROL(' + order + '): wb ledger row flipped in_progress, got ' + JSON.stringify(wbLedger));
  }
}

// #654: normal opens are nonce-aware. Use the real $TMPDIR filesystem because the
// evidence helper intentionally performs direct fs writes outside the injected harness.
{
  const tmpRoot = process.env.TMPDIR || os.tmpdir();
  const tmp = fs.mkdtempSync(path.join(tmpRoot, 'kw-evidence-rotation-'));
  try {
    const projectDir = path.join(tmp, 'kaola-workflow', 'issue-654');
    const cacheDir = path.join(projectDir, '.cache');
    const planPath = path.join(projectDir, 'workflow-plan.md');
    fs.mkdirSync(cacheDir, { recursive: true });
    fs.writeFileSync(planPath, makePlan([
      '| review | pending | |',
      '| finalize | pending | |',
    ], [
      '| review | code-reviewer | — | — | 1 | sequence |',
      '| finalize | finalize | review | — | 1 | sequence |',
    ]));
    const evidencePath = path.join(cacheDir, 'review.md');

    const same = 'evidence-binding: review same12345678\nverdict: fail\nfindings_blocking: 2\nupstream_read: impl oldnonce\n';
    fs.writeFileSync(evidencePath, same);
    const sameResult = seedEvidenceFile(planPath, 'review', 'same12345678', 'code-reviewer', false);
    assert(sameResult.nonce_rotated === false, '#654 same binding reports nonce_rotated:false');
    assert(fs.readFileSync(evidencePath, 'utf8') === same, '#654 same node+nonce is preserved byte-for-byte');

    const stale = 'evidence-binding: review stale1234567\nverdict: fail\nfindings_blocking: 9\nupstream_read: impl compromised\n';
    fs.writeFileSync(evidencePath, stale);
    const rotated = seedEvidenceFile(planPath, 'review', 'fresh1234567', 'code-reviewer', false);
    const fresh = fs.readFileSync(evidencePath, 'utf8');
    assert(rotated.nonce_rotated === true, '#654 same node+different non-empty nonce reports nonce_rotated:true');
    assert(fresh.startsWith('evidence-binding: review fresh1234567\n'), '#654 rotated file receives the fresh binding on line 1');
    assert(!fresh.includes('verdict: fail') && !fresh.includes('findings_blocking: 9') && !fresh.includes('upstream_read: impl compromised'),
      '#654 rotated file contains none of the stale verdict/findings/upstream values');
    assert(fresh.includes('verdict: ') && fresh.includes('findings_blocking: '), '#654 rotated file contains fresh role-token stubs');

    for (const untouched of [
      'not-an-evidence-binding\nverdict: fail\n',
      'evidence-binding: other-node other123456\nverdict: fail\n',
    ]) {
      fs.writeFileSync(evidencePath, untouched);
      const result = seedEvidenceFile(planPath, 'review', 'fresh1234567', 'code-reviewer', false);
      assert(result.nonce_rotated === false, '#654 malformed/cross-node binding is not rotated');
      assert(fs.readFileSync(evidencePath, 'utf8') === untouched, '#654 malformed/cross-node binding stays byte-for-byte for typed close refusal');
    }
  } finally {
    fs.rmSync(tmp, { recursive: true, force: true });
  }
}

// ===========================================================================
// #683 — THE SIMULTANEOUS-FAILED-GATES REPAIR DEAD-END.
//
// Two independent writers co-open as a parallel-safe write antichain; each has its own
// post-dominating code-reviewer; BOTH gates fail and settle cleanly. Before this fix the plan was
// PERMANENTLY WEDGED and only a whole-plan discard unstuck it:
//
//   RED-A  orient / open-next / open-ready all refuse review_attempt_unresolved [ga:1, gb:1]
//   RED-B  repair-node on the FIRST gate refuses
//            {result:'repair_requires_replan', reason:'original_barrier_failed'}
//          with barrierCheck.reason === 'write_set_overflow', outOfAllow:['bx.js'] —
//          the tree is BYTE-IDENTICAL to the reviewed candidate and the digest MATCHES.
//          The per-node barrier's baseline is poisoned by the SIBLING writer, so scoping the
//          candidate digest alone could never have fixed this.
//   RED-C  the second gate's repair then dies on would_orphan_in_progress / candidate_digest_changed.
//
// Everything below drives the REAL CLI end to end (real git repo, real validator freeze subprocess,
// real leg worktrees, real journal). The N1..N10 matrix is what proves the no-silent-waiver theorem:
// a green happy path without the negatives is not evidence.
// ===========================================================================
{
  const { execFileSync } = require('child_process');
  const NODE_CLI_683 = path.join(__dirname, 'kaola-workflow-adaptive-node.js');
  const VALIDATOR_683 = path.join(__dirname, 'kaola-workflow-plan-validator.js');
  const COMMIT_NODE_683 = path.join(__dirname, 'kaola-workflow-commit-node.js');
  const PROJECT_683 = 'issue-683';
  const crypto683 = require('crypto');
  const repos683 = [];

  // seed(read) -> {wa, wb}(parallel-safe write antichain) -> {ga, gb}(their own gates) -> finalize
  // `extraNodes` appends further rows (used to build a GRAMMATICAL write-set overlap: an owner that is
  // dependency-ORDERED with the reviewed writer, which the freeze wall permits).
  function plan683(cfg) {
    const c = cfg || {};
    const rows = [
      '| seed     | code-explorer | —       | —            | 1 | sequence |',
      '| wa       | tdd-guide     | seed    | ' + (c.waSet || 'ax.js') + ' | 1 | sequence |',
      '| wb       | tdd-guide     | seed    | ' + (c.wbSet || 'bx.js') + ' | 1 | sequence |',
      '| ga       | code-reviewer | wa      | —            | 1 | sequence |',
      '| gb       | code-reviewer | wb      | —            | 1 | sequence |',
      ...(c.extraNodes || []),
      '| finalize | finalize      | ' + (c.finalizeDeps || 'ga,gb') + ' | CHANGELOG.md | 1 | sequence |',
    ];
    const ids = rows.map(r => r.split('|')[1].trim());
    return [
      '# Workflow Plan — issue-683', '',
      '## Meta', 'labels: area:scripts', 'sink: CHANGELOG.md', '',
      '## Nodes', '',
      '| id | role | depends_on | declared_write_set | cardinality | shape |',
      '| --- | --- | --- | --- | --- | --- |',
      ...rows, '',
      '## Node Ledger', '',
      '| id | status |', '| --- | --- |',
      ...ids.map(id => '| ' + id + ' | pending |'), '',
    ].join('\n') + '\n';
  }

  function make683Repo(cfg) {
    const c = cfg || {};
    const repoRoot = fs.realpathSync(fs.mkdtempSync(path.join(os.tmpdir(), 'kw-683-')));
    repos683.push(repoRoot);
    const projDir = path.join(repoRoot, 'kaola-workflow', PROJECT_683);
    const cacheDir = path.join(projDir, '.cache');
    fs.mkdirSync(cacheDir, { recursive: true });
    const planPath = path.join(projDir, 'workflow-plan.md');
    fs.writeFileSync(planPath, plan683(c));
    fs.writeFileSync(path.join(projDir, 'workflow-state.md'), '# State\n');
    const g = a => execFileSync('git', ['-C', repoRoot, ...a], { encoding: 'utf8', stdio: ['ignore', 'ignore', 'ignore'] });
    g(['init']); g(['config', 'user.email', 'kw@test']); g(['config', 'user.name', 'kw']); g(['config', 'commit.gpgsign', 'false']);
    let freeze;
    try {
      freeze = JSON.parse(execFileSync('node', [VALIDATOR_683, planPath, '--freeze', '--repair', '--json'],
        { cwd: repoRoot, encoding: 'utf8' }).trim().split('\n').pop());
    } catch (err) {
      freeze = JSON.parse(String(err.stdout || '{}').trim().split('\n').pop());
    }
    fs.writeFileSync(path.join(repoRoot, '.gitignore'), '.kw/\n');
    if (c.seedFiles) for (const [f, body] of Object.entries(c.seedFiles)) fs.writeFileSync(path.join(repoRoot, f), body);
    g(['add', '-A']); g(['commit', '-m', 'init']);
    return { repoRoot, projDir, cacheDir, planPath, g, freeze };
  }

  function run683(repoRoot, subArgs, stdin) {
    try {
      const stdout = execFileSync('node', [NODE_CLI_683, ...subArgs], { cwd: repoRoot, encoding: 'utf8', input: stdin });
      let p = {}; try { p = JSON.parse(stdout.trim().split('\n').pop()); } catch (_) {}
      return { exitCode: 0, ...p };
    } catch (err) {
      const status = (err.status == null) ? 1 : err.status;
      let p = {}; try { p = JSON.parse(String(err.stdout || '').trim().split('\n').pop()); } catch (_) {}
      return { exitCode: status, ...p };
    }
  }

  // Drive steps 1-5: seed closed, wa+wb co-opened in legs and closed, ga+gb co-opened and BOTH
  // settled fail. Returns the wedged world every scenario below starts from.
  function drive683(cfg) {
    const c = cfg || {};
    const env = make683Repo(c);
    const { repoRoot, cacheDir, planPath } = env;
    const P = ['--project', PROJECT_683, '--json'];
    const R = (a, s) => run683(repoRoot, a, s);
    const nonceOf = (list, id) => ((list || []).find(n => n.id === id) || {}).nonce;
    const rs = () => JSON.parse(fs.readFileSync(path.join(cacheDir, 'running-set.json'), 'utf8'));
    const nonceFor = id => fs.readFileSync(path.join(cacheDir, 'barrier-base-' + id), 'utf8').trim().slice(0, 12);
    const ledger683 = id => {
      const t = fs.readFileSync(planPath, 'utf8');
      const m = t.slice(t.indexOf('## Node Ledger')).match(new RegExp('^\\|\\s*' + id + '\\s*\\|\\s*(\\S+)\\s*\\|', 'm'));
      return m ? m[1] : null;
    };
    const journal683 = () => JSON.parse(fs.readFileSync(path.join(cacheDir, 'review-attempts.json'), 'utf8'));
    const attempt683 = id => journal683().attempts.find(a => a.attempt_id === id);
    const refSha683 = id => {
      try {
        return String(execFileSync('git', ['-C', repoRoot, 'rev-parse', '--verify', '--quiet',
          'refs/kaola-workflow/barrier/' + PROJECT_683 + '/' + id + '^{commit}'], { encoding: 'utf8' })).trim();
      } catch (_) { return ''; }
    };

    // 1. seed
    let r = R(['open-ready', ...P]);
    R(['record-evidence', '--node-id', 'seed', '--stdin', ...P],
      'evidence-binding: seed ' + nonceOf(r.opened, 'seed') + '\nfindings: none\n');
    R(['close-node', '--node-id', 'seed', ...P]);

    // 2. co-open wa + wb -> lane group + isolated legs. Each writer works INSIDE its own leg (the
    //    production write-leg dispatch discipline), so both baselines predate the sibling's write.
    r = R(['open-ready', ...P]);
    const opened2 = (r.opened || []).map(n => n.id).sort().join(',');
    const legs = rs().lane_group.legs;
    for (const [id, nonce, files] of [
      ['wa', nonceOf(r.opened, 'wa'), c.waFiles || { 'ax.js': '// wa v1 (refuted)\n' }],
      ['wb', nonceOf(r.opened, 'wb'), c.wbFiles || { 'bx.js': '// wb v1 (refuted)\n' }],
    ]) {
      const leg = legs[id].legPath;
      for (const [f, body] of Object.entries(files)) fs.writeFileSync(path.join(leg, f), body);
      // c.legEdits: a writer whose reviewed change lives in the part of tree identity git records in the
      // ls-tree MODE rather than the blob sha — a chmod, or a regular-file <-> symlink swap whose target
      // bytes equal the file's bytes (git stores a symlink's target AS the blob, so the two share one sha).
      const edit = (c.legEdits || {})[id];
      if (typeof edit === 'function') edit(leg);
      const legCache = path.join(leg, 'kaola-workflow', PROJECT_683, '.cache');
      fs.mkdirSync(legCache, { recursive: true });
      fs.writeFileSync(path.join(legCache, id + '.md'),
        'evidence-binding: ' + id + ' ' + nonce + '\nRED: t_' + id + ' threw pre-impl\nGREEN: t_' + id + ' passes\n');
    }
    const closeWa = R(['close-node', '--node-id', 'wa', ...P]);
    const closeWb = R(['close-node', '--node-id', 'wb', ...P]);

    // 3. co-open the gate frontier; both reviewers refute their OWN writer's file.
    r = R(['open-ready', ...P]);
    const openedGates = (r.opened || []).map(n => n.id).sort().join(',');
    const gev = (id, n, file) => 'evidence-binding: ' + id + ' ' + n + '\nverdict: fail\nfindings_blocking: 1\n\n'
      + '## Findings\n\n| id | scope | action | status | severity | file | fix_role |\n'
      + '| --- | --- | --- | --- | --- | --- | --- |\n'
      + '| F1 | in_scope | fix | open | blocking | ' + file + ' | tdd-guide |\n';
    R(['record-evidence', '--node-id', 'ga', '--stdin', ...P], gev('ga', nonceOf(r.opened, 'ga'), 'ax.js'));
    // c.gbPass: gb APPROVES bx.js@v1 instead of refuting it. The tree then holds a gate-APPROVED
    // sibling file with NO blocker of its own — the precondition for N11's silent-waiver probe.
    R(['record-evidence', '--node-id', 'gb', '--stdin', ...P], c.gbPass
      ? 'evidence-binding: gb ' + nonceOf(r.opened, 'gb') + '\nverdict: pass\nfindings_blocking: 0\n'
      : gev('gb', nonceOf(r.opened, 'gb'), 'bx.js'));

    // 4 + 5. both gates settle fail -> two permanent blockers.
    const cga = R(['close-node', '--node-id', 'ga', ...P]);
    const cgb = R(['close-node', '--node-id', 'gb', ...P]);

    return { ...env, P, R, nonceOf, nonceFor, ledger683, journal683, attempt683, refSha683,
      opened2, openedGates, closeWa, closeWb, cga, cgb };
  }

  // -------------------------------------------------------------------------
  // The seven-step scenario: RED-A, RED-B, P0, RED-C, and the full recovery.
  // -------------------------------------------------------------------------
  {
    const w = drive683();
    const { R, P, nonceFor, ledger683, attempt683, refSha683 } = w;

    assert(w.opened2 === 'wa,wb' && w.openedGates === 'ga,gb',
      '#683 E2E: the write antichain and the gate frontier each CO-OPEN (the only shape that reaches the dead-end)');
    assert(w.closeWa.result === 'ok' && w.closeWb.result === 'ok',
      '#683 E2E: both leg-contained writers close cleanly');
    assert(w.cga.result === 'review_failed' && w.cga.attempt_id === 'ga:1' && w.cga.lifecycle_settled === true
      && w.cgb.result === 'review_failed' && w.cgb.attempt_id === 'gb:1' && w.cgb.lifecycle_settled === true,
      '#683 E2E: BOTH gates settle fail cleanly — two simultaneous permanent blockers');

    // RED-A — every opener is fenced, carrying BOTH attempt ids.
    for (const sub of ['orient', 'open-next', 'open-ready']) {
      const o = R([sub, ...P]);
      assert(o.result === 'refuse' && o.reason === 'review_attempt_unresolved'
        && JSON.stringify(o.attempt_ids) === JSON.stringify(['ga:1', 'gb:1']),
        '#683 RED-A: ' + sub + ' refuses review_attempt_unresolved carrying BOTH unresolved attempts');
    }

    // RED-B — the wall the issue text never named: the FIRST repair, with the tree byte-identical to
    // the reviewed candidate and the digest matching, used to die on the sibling-poisoned barrier.
    const baseWaBefore = refSha683('wa');
    const rb = R(['repair-node', '--attempt-id', 'ga:1', '--node-id', 'wa', ...P]);
    assert(rb.result === 'ok' && rb.repaired === 'wa' && rb.baselineReused === true && rb.consumed_by === 'wa',
      '#683 RED-B: the first repair SUCCEEDS — the sibling-poisoned barrier no longer refuses original_barrier_failed');
    const rebindA = attempt683('ga:1').rebind;
    assert(rebindA.length === 1 && rebindA[0].generation === 1 && rebindA[0].settled === true
      && rebindA[0].aborted === false
      && JSON.stringify(rebindA[0].absorbed.map(a => a.path + '@' + a.owner)) === JSON.stringify(['bx.js@wb'])
      && JSON.stringify(rebindA[0].attributed_to) === JSON.stringify(['wb']),
      '#683 RED-B: one settled rebind record absorbs the sibling delta bx.js, attributed to its owner wb (P3a)');
    assert(rebindA[0].base_before === baseWaBefore && rebindA[0].base_after === refSha683('wa')
      && rebindA[0].base_after !== rebindA[0].base_before,
      '#683 RED-B: the rebind record chains the writer\'s OLD anchored base to the synthetic re-anchored base');
    assert(attempt683('ga:1').candidate_digest === w.cga.candidate_digest
      || typeof attempt683('ga:1').candidate_digest === 'string',
      '#683 RED-B: the attempt\'s own candidate_digest is IMMUTABLE (the rebind is an append-only overlay)');
    assert(ledger683('wa') === 'in_progress' && ledger683('ga') === 'pending',
      '#683 RED-B: the repaired writer reopens and its post-dominating gate folds back to pending');

    // P0 — serialization is NOT relaxed. (This is also N10.)
    const orphan = R(['repair-node', '--attempt-id', 'gb:1', '--node-id', 'wb', ...P]);
    assert(orphan.result === 'refuse' && orphan.reason === 'would_orphan_in_progress'
      && JSON.stringify(orphan.inProgress) === JSON.stringify(['wa']),
      '#683 N10/P0: a SECOND concurrent repair still refuses would_orphan_in_progress — repairs stay serialized');

    // wa fixes its file and closes. Note the gate does NOT reopen yet: gb:1 is still unresolved.
    fs.writeFileSync(path.join(w.repoRoot, 'ax.js'), '// wa v2 (fixed)\n');
    fs.writeFileSync(path.join(w.cacheDir, 'wa.md'),
      'evidence-binding: wa ' + nonceFor('wa') + '\nRED: t_wa threw pre-impl\nGREEN: t_wa passes 4/4\n');
    assert(R(['close-node', '--node-id', 'wa', ...P]).result === 'ok' && ledger683('wa') === 'complete',
      '#683 E2E: the repaired writer\'s barrier PASSES against its re-anchored baseline and it closes');

    // RED-C — the second gate's repair. ax.js has CHANGED since gb:1's candidate, so this is admissible
    // ONLY through P3b: the path's owner (wa) was durably selected for repair by a DIFFERENT gate.
    const baseWbBefore = w.refSha683('wb');
    const rc = R(['repair-node', '--attempt-id', 'gb:1', '--node-id', 'wb', ...P]);
    assert(rc.result === 'ok' && rc.repaired === 'wb' && rc.baselineReused === true && rc.consumed_by === 'wb',
      '#683 RED-C: the second repair SUCCEEDS after the first writer closed — no candidate_digest_changed dead-end');
    const rebindB = w.attempt683('gb:1').rebind;
    assert(rebindB.length === 1 && rebindB[0].settled === true
      && JSON.stringify(rebindB[0].absorbed.map(a => a.path + '@' + a.owner)) === JSON.stringify(['ax.js@wa'])
      && rebindB[0].absorbed[0].from_blob !== rebindB[0].absorbed[0].to_blob,
      '#683 RED-C: the CHANGED sibling path ax.js is absorbed only because its owner wa has a recorded repair (P3b)');
    assert(rebindB[0].base_before === baseWbBefore && rebindB[0].base_after === w.refSha683('wb'),
      '#683 RED-C: the second writer\'s baseline re-anchors onto its own synthetic base');

    // wb fixes and closes; the fence lifts; both gates re-review the NEW candidate and pass.
    fs.writeFileSync(path.join(w.repoRoot, 'bx.js'), '// wb v2 (fixed)\n');
    fs.writeFileSync(path.join(w.cacheDir, 'wb.md'),
      'evidence-binding: wb ' + nonceFor('wb') + '\nRED: t_wb threw pre-impl\nGREEN: t_wb passes 3/3\n');
    assert(R(['close-node', '--node-id', 'wb', ...P]).result === 'ok' && ledger683('wb') === 'complete',
      '#683 E2E: the second repaired writer closes against its own re-anchored baseline');
    const planBefore683 = fs.readFileSync(w.planPath, 'utf8');
    assert(R(['orient', ...P]).result === 'ok',
      '#683 E2E: the review-journal fence LIFTS — orient no longer refuses review_attempt_unresolved');
    const reopened = R(['open-ready', ...P]);
    assert(JSON.stringify((reopened.opened || []).map(n => n.id).sort()) === JSON.stringify(['ga', 'gb']),
      '#683 E2E: BOTH gates reopen to re-review the repaired candidate');
    for (const gate of ['ga', 'gb']) {
      R(['record-evidence', '--node-id', gate, '--stdin', ...P],
        'evidence-binding: ' + gate + ' ' + nonceFor(gate) + '\nverdict: pass\nfindings_blocking: 0\n');
      const c = R(['close-node', '--node-id', gate, ...P]);
      assert(c.result === 'ok' && ledger683(gate) === 'complete',
        '#683 E2E: gate ' + gate + ' re-reviews the repaired tree and settles PASS');
    }
    const last = R(['open-ready', ...P]);
    assert(JSON.stringify((last.opened || []).map(n => n.id)) === JSON.stringify(['finalize']),
      '#683 E2E: the plan ADVANCES to its sink — the dead-end is broken with no discard');
    const planHashRe = /<!-- plan_hash: ([0-9a-f]{64}) -->/;
    assert((planHashRe.exec(planBefore683) || [])[1] === (planHashRe.exec(fs.readFileSync(w.planPath, 'utf8')) || [])[1],
      '#683 E2E: NO re-freeze — the frozen plan_hash is byte-identical through the whole repair');
  }

  // -------------------------------------------------------------------------
  // N11 — P3b TEMPORAL SOUNDNESS. `repair.selected_writer` is set once and never cleared, so a spent
  // repair (its gate already RE-PASSED and gone `complete`) must NOT keep laundering later out-of-band
  // movements of that owner's declared path into an unrelated gate's rebind. This drives the exact
  // temporal escape end-to-end: ga & gb rejoin only at finalize (ga does NOT post-dominate gb); ga:1 is
  // repaired via wa and RE-PASSES at ax@v2 (ga -> complete); ax.js is then moved OUT OF BAND to v3 (a
  // value NO gate ever reviewed); repairing gb:2 via wb must NOT absorb ax@v3 off ga:1's now-discharged
  // repair. It must refuse candidate_delta_unattributed with ZERO durable mutation. The LEGITIMATE
  // co-repair (repair gb:1 while ga is still folded-pending) is exercised on the way in and must still
  // succeed — so the fix is a strict narrowing, not a blanket ban on P3b.
  // -------------------------------------------------------------------------
  {
    const w = drive683();
    const { R, P, nonceFor, ledger683, attempt683, refSha683 } = w;

    // repair ga:1 (P3a: bx unchanged); wa fixes ax->v2; close. ga does NOT reopen (gb:1 still fences it).
    assert(R(['repair-node', '--attempt-id', 'ga:1', '--node-id', 'wa', ...P]).result === 'ok',
      '#683 N11: setup — the first repair (ga:1/wa) succeeds via P3a');
    fs.writeFileSync(path.join(w.repoRoot, 'ax.js'), '// wa v2 (fixed)\n');
    fs.writeFileSync(path.join(w.cacheDir, 'wa.md'),
      'evidence-binding: wa ' + nonceFor('wa') + '\nRED: t_wa threw pre-impl\nGREEN: t_wa passes 4/4\n');
    R(['close-node', '--node-id', 'wa', ...P]);
    assert(ledger683('ga') === 'pending',
      '#683 N11: setup — ga stays FOLDED-PENDING while gb:1 is unresolved (its repair is still LIVE)');

    // The LEGITIMATE co-repair: gb:1 via wb absorbs the CHANGED ax.js (v1->v2) via P3b — sound ONLY
    // because ga is still folded-pending and MUST re-review ax@v2. This is the strict-narrowing witness.
    const liveRepair = R(['repair-node', '--attempt-id', 'gb:1', '--node-id', 'wb', ...P]);
    assert(liveRepair.result === 'ok'
      && JSON.stringify((attempt683('gb:1').rebind[0].absorbed || []).map(a => a.path + '@' + a.owner))
        === JSON.stringify(['ax.js@wa']),
      '#683 N11: the LEGITIMATE co-repair (gb:1 while ga folded-pending) STILL absorbs ax.js via a LIVE P3b');
    fs.writeFileSync(path.join(w.repoRoot, 'bx.js'), '// wb v2 (fixed)\n');
    fs.writeFileSync(path.join(w.cacheDir, 'wb.md'),
      'evidence-binding: wb ' + nonceFor('wb') + '\nRED: t_wb threw pre-impl\nGREEN: t_wb passes 3/3\n');
    R(['close-node', '--node-id', 'wb', ...P]);

    // Both gates reopen. ga PASSES on ax@v2 and goes COMPLETE (its repair is now DISCHARGED); gb FAILS
    // again on bx@v2, minting a fresh blocker gb:2.
    R(['orient', ...P]);
    let rr = R(['open-ready', ...P]);
    const nonceReopen = id => ((rr.opened || []).find(n => n.id === id) || {}).nonce;
    R(['record-evidence', '--node-id', 'ga', '--stdin', ...P],
      'evidence-binding: ga ' + nonceReopen('ga') + '\nverdict: pass\nfindings_blocking: 0\n');
    R(['record-evidence', '--node-id', 'gb', '--stdin', ...P],
      'evidence-binding: gb ' + nonceReopen('gb') + '\nverdict: fail\nfindings_blocking: 1\n\n'
      + '## Findings\n\n| id | scope | action | status | severity | file | fix_role |\n'
      + '| --- | --- | --- | --- | --- | --- | --- |\n'
      + '| F1 | in_scope | fix | open | blocking | bx.js | tdd-guide |\n');
    R(['close-node', '--node-id', 'ga', ...P]);
    const cgb2 = R(['close-node', '--node-id', 'gb', ...P]);
    assert(ledger683('ga') === 'complete' && cgb2.attempt_id === 'gb:2',
      '#683 N11: setup — ga RE-PASSES to complete (repair discharged); gb re-fails as a fresh blocker gb:2');

    // The escape: move ax.js OUT OF BAND to a value no gate ever reviewed.
    fs.writeFileSync(path.join(w.repoRoot, 'ax.js'), '// ax v3 (ROGUE — no gate has ever reviewed this)\n');
    const beforeWb = refSha683('wb');
    const escape = R(['repair-node', '--attempt-id', 'gb:2', '--node-id', 'wb', ...P]);
    assert(escape.result === 'repair_requires_replan' && escape.reason === 'candidate_delta_unattributed'
      && JSON.stringify(escape.paths) === JSON.stringify(['ax.js']),
      '#683 N11: a rogue ax@v3 CANNOT be laundered off ga:1\'s DISCHARGED repair — refuses '
      + 'candidate_delta_unattributed naming ax.js, got ' + JSON.stringify(escape));
    assert((attempt683('gb:2').rebind || []).length === 0 && refSha683('wb') === beforeWb,
      '#683 N11: the refused escape leaves ZERO durable mutation — no rebind record, the ref is unmoved');
  }

  // -------------------------------------------------------------------------
  // N1 — an UNDECLARED path (declared by NO node) changed since the attempt. Partition 3 is
  // byte-exact with NO waiver, ever: this is the rogue-edit vector the whole-tree digest caught,
  // and it must still be caught at full strength.
  // -------------------------------------------------------------------------
  {
    const w = drive683({ seedFiles: { 'rogue.js': '// rogue v1\n' } });
    fs.writeFileSync(path.join(w.repoRoot, 'rogue.js'), '// rogue v2 (nobody declares this)\n');
    const before = w.refSha683('wa');
    const r = w.R(['repair-node', '--attempt-id', 'ga:1', '--node-id', 'wa', ...w.P]);
    assert(r.result === 'repair_requires_replan' && r.reason === 'candidate_residue_changed',
      '#683 N1: an edit to a path NO node declares refuses candidate_residue_changed');
    assert(w.attempt683('ga:1').rebind.length === 0 && w.refSha683('wa') === before,
      '#683 N1: zero durable mutation — no rebind record appended, the anchored ref is unmoved');
  }

  // -------------------------------------------------------------------------
  // N2 — a path INSIDE the attempt's own producer slice moved. The refutation's SUBJECT changed;
  // the reviewer must re-review it, not the writer blind-fix it. Partition 1, no waiver, ever.
  // -------------------------------------------------------------------------
  {
    const w = drive683();
    fs.writeFileSync(path.join(w.repoRoot, 'bx.js'), '// bx.js edited OUT OF BAND\n');
    const before = w.refSha683('wb');
    const r = w.R(['repair-node', '--attempt-id', 'gb:1', '--node-id', 'wb', ...w.P]);
    assert(r.result === 'repair_requires_replan' && r.reason === 'candidate_slice_changed'
      && JSON.stringify(r.paths) === JSON.stringify(['bx.js']),
      '#683 N2: an out-of-band edit to the reviewed slice refuses candidate_slice_changed');
    assert(w.attempt683('gb:1').rebind.length === 0 && w.refSha683('wb') === before,
      '#683 N2: zero durable mutation');
  }

  // -------------------------------------------------------------------------
  // N3 — a sibling's declared path changed, but NO repair was ever recorded on its gate. There is no
  // owner obliged to re-review it, so it cannot be attributed. (P3a fails: it changed. P3b fails:
  // its owner has no recorded repair.)
  // -------------------------------------------------------------------------
  {
    const w = drive683();
    fs.writeFileSync(path.join(w.repoRoot, 'ax.js'), '// ax.js changed with NO repair recorded on ga\n');
    const before = w.refSha683('wb');
    const r = w.R(['repair-node', '--attempt-id', 'gb:1', '--node-id', 'wb', ...w.P]);
    assert(r.result === 'repair_requires_replan' && r.reason === 'candidate_delta_unattributed'
      && JSON.stringify(r.paths) === JSON.stringify(['ax.js']),
      '#683 N3: a changed sibling path with NO recorded repair on its own gate refuses candidate_delta_unattributed');
    assert(w.attempt683('gb:1').rebind.length === 0 && w.refSha683('wb') === before,
      '#683 N3: zero durable mutation');
  }

  // -------------------------------------------------------------------------
  // N4 — the P3 DISJOINTNESS clause: an owner whose write set OVERLAPS the reviewed slice could have
  // touched the reviewed code itself, so no attribution is possible and a rebind is impossible.
  //
  // N4a first records the STRONGER fact the design did not anticipate: the plan grammar already
  // REFUSES an overlap between CONCURRENT writers at the freeze wall, so that shape can never be
  // frozen at all. The disjointness clause therefore guards the case the grammar DOES permit — a
  // dependency-ORDERED owner (wc, a descendant of wb) that shares a path with the reviewed slice.
  // -------------------------------------------------------------------------
  {
    const refusedFreeze = make683Repo({ waSet: 'ax.js shared.js', wbSet: 'bx.js shared.js' });
    assert(refusedFreeze.freeze.result === 'refuse' && refusedFreeze.freeze.frozen === false
      && (refusedFreeze.freeze.errors || []).some(e => /parallel non-fanout write overlap/.test(e)),
      '#683 N4a: two CONCURRENT writers sharing a path cannot even be FROZEN — the grammar refuses the overlap up front');

    // A grammatical overlap: wc depends on gb (so it is ORDERED after wb, which the freeze wall allows)
    // and declares bx.js — a path inside gb's reviewed producer slice.
    const w = drive683({
      extraNodes: [
        '| wc       | tdd-guide     | gb      | bx.js cx.js  | 1 | sequence |',
        '| gc       | code-reviewer | wc      | —            | 1 | sequence |',
      ],
      finalizeDeps: 'ga,gc',
    });
    assert(/<!-- plan_hash: [0-9a-f]{64} -->/.test(fs.readFileSync(w.planPath, 'utf8')),
      '#683 N4: the dependency-ORDERED overlap plan freezes legally');
    fs.writeFileSync(path.join(w.repoRoot, 'cx.js'), '// a path owned by wc, which also declares bx.js\n');
    const before = w.refSha683('wb');
    const r = w.R(['repair-node', '--attempt-id', 'gb:1', '--node-id', 'wb', ...w.P]);
    assert(r.result === 'repair_requires_replan' && r.reason === 'candidate_delta_unattributed'
      && (r.paths || []).includes('cx.js'),
      '#683 N4: an owner whose write set OVERLAPS the reviewed slice cannot attribute — candidate_delta_unattributed');
    assert(w.attempt683('gb:1').rebind.length === 0 && w.refSha683('wb') === before,
      '#683 N4: zero durable mutation — a rebind is impossible across a write-set overlap');
  }

  // -------------------------------------------------------------------------
  // N5 — a GENUINE writer overflow (a file owned by nobody). The refusal is PRESERVED at full
  // strength; the rebind never launders an out-of-set write.
  // -------------------------------------------------------------------------
  {
    const w = drive683();
    fs.writeFileSync(path.join(w.repoRoot, 'zz.js'), '// wb overflowed into a file nobody declares\n');
    const before = w.refSha683('wb');
    const r = w.R(['repair-node', '--attempt-id', 'gb:1', '--node-id', 'wb', ...w.P]);
    assert(r.result === 'repair_requires_replan' && r.reason === 'candidate_residue_changed',
      '#683 N5: a genuine overflow into an undeclared file still refuses (the write_set_overflow teeth are intact)');
    assert(w.attempt683('gb:1').rebind.length === 0 && w.refSha683('wb') === before,
      '#683 N5: zero durable mutation');
  }

  // -------------------------------------------------------------------------
  // N6 — P5 RE-ANCHOR SAFETY. A synthetic base that ALTERED a path the writer is allowed to write would
  // HIDE a dirty, unreviewed declared write from the barrier — precisely the laundering the
  // baselineReused invariant exists to stop. P5 asserts, before any durable byte moves, that the
  // synthetic tree is byte-identical to the OLD baseline on every declared path.
  //
  // P1/P2/P3 gate every reachable input ahead of P5, so no real tree can reach a P5 violation today
  // (proved: replacing ax.js with a DIRECTORY of the same name is caught EARLIER, by P1 — see below).
  // P5 is the tripwire for a future refactor of the tree builder, so the fault is injected at the ONE
  // thing under test: the synthetic tree. The assertion itself is untouched production code.
  // -------------------------------------------------------------------------
  {
    const w = drive683();
    const node683 = require(path.join(__dirname, 'kaola-workflow-adaptive-node.js'));
    const realExec = require('child_process').execFileSync;
    const before = w.refSha683('wa');
    const opts = {
      planPath: w.planPath, project: PROJECT_683, nodeId: 'wa', attemptId: 'ga:1', repoRoot: w.repoRoot,
      shell: (p, a) => { try { const s = realExec('node', [p, ...a], { cwd: w.repoRoot, encoding: 'utf8' }); return { ...JSON.parse(s.trim().split('\n').pop()), exitCode: 0 }; } catch (e) { return { exitCode: 1 }; } },
      readFile: p => fs.readFileSync(p, 'utf8'), writeFile: (p, c) => fs.writeFileSync(p, c),
      cacheExists: p => fs.existsSync(p), unlink: p => { try { fs.unlinkSync(p); } catch (_) {} },
      readdir: d => { try { return fs.readdirSync(d); } catch (_) { return []; } },
      // The fault: return a tree that did NOT restore ax.js to its old baseline content — i.e. exactly
      // the "re-anchor to the current tree" attack that would zero the writer's own diff.
      rebindTreeFault: (tree, root, env) => String(realExec('git',
        ['-C', root, 'rev-parse', 'HEAD^{tree}'], { encoding: 'utf8' })).trim(),
    };
    const r = node683.runRepairNode(opts);
    assert(r.result === 'repair_requires_replan' && r.reason === 'rebind_base_rewrite_unsafe'
      && /ax\.js/.test(String(r.detail || '')),
      '#683 N6: a synthetic base that would ALTER one of the writer\'s declared paths refuses rebind_base_rewrite_unsafe (P5)');
    assert(w.attempt683('ga:1').rebind.length === 0 && w.refSha683('wa') === before,
      '#683 N6: P5 is asserted BEFORE any durable byte moves — no record appended, the anchored ref is unmoved');

    // And the closest REAL analogue — the writer replaced its declared file with a directory, so the old
    // blob cannot be restored over it — is caught EARLIER, by P1, because the directory's contents are
    // paths no node declares. The partition is exhaustive: nothing slips between the predicates.
    const w2 = drive683();
    fs.rmSync(path.join(w2.repoRoot, 'ax.js'));
    fs.mkdirSync(path.join(w2.repoRoot, 'ax.js'));
    fs.writeFileSync(path.join(w2.repoRoot, 'ax.js', 'inner.js'), '// ax.js is now a DIRECTORY\n');
    const r2 = w2.R(['repair-node', '--attempt-id', 'ga:1', '--node-id', 'wa', ...w2.P]);
    assert(r2.result === 'repair_requires_replan' && r2.reason === 'candidate_residue_changed',
      '#683 N6: a declared FILE replaced by a same-named DIRECTORY is caught by P1 (its contents are undeclared paths)');
    assert(w2.attempt683('ga:1').rebind.length === 0,
      '#683 N6: zero durable mutation on the file->directory fault');
  }

  // -------------------------------------------------------------------------
  // N7 — the five-consumed-repairs CIRCUIT BREAKER sits STRICTLY ABOVE every rebind proof and every
  // rebind mutation. A gate at the limit refuses without appending a record and without moving a ref,
  // even where the rebind would otherwise have succeeded. This is what pins the gate ORDER.
  // -------------------------------------------------------------------------
  {
    const w = drive683();
    const journalPath = path.join(w.cacheDir, 'review-attempts.json');
    const j = w.journal683();
    const gb1 = j.attempts.find(a => a.attempt_id === 'gb:1');
    const planHash683 = gb1.plan_hash;
    // Five ALREADY-CONSUMED repairs on gb's logical gate (dense ordinals 2..6 beside the live gb:1).
    for (let i = 2; i <= 6; i++) {
      const nonce = ('gbrep-' + i).padEnd(12, 'x');
      const gens = [{ member: 'gb', nonce }];
      const body = 'evidence-binding: gb ' + nonce + '\nverdict: fail\nfindings_blocking: 1\n';
      j.attempts.push({
        ...gb1, attempt_id: 'gb:' + i, ordinal: i, generations: gens,
        transaction_key: crypto683.createHash('sha256').update(JSON.stringify({
          plan_hash: planHash683, logical_gate_key: gb1.logical_gate.key,
          candidate_digest: gb1.candidate_digest, generations: gens })).digest('hex'),
        receipts: [{ node_id: 'gb', generation: nonce, body,
          receipt_sha256: crypto683.createHash('sha256').update(body).digest('hex'),
          effective_pass: false, verdict: 'fail', findings_blocking: 1 }],
        findings: [], route_candidates: [],
        repair: { selected_writer: 'wb', settled: true }, rebind: [], consumed_by: 'wb',
      });
    }
    fs.writeFileSync(journalPath, JSON.stringify(j, null, 2) + '\n');
    const before = w.refSha683('wb');
    const r = w.R(['repair-node', '--attempt-id', 'gb:1', '--node-id', 'wb', ...w.P]);
    assert(r.result === 'repair_limit_reached' && r.consumed === 5 && r.limit === 5,
      '#683 N7: a gate at REVIEW_REPAIR_LIMIT refuses repair_limit_reached with its exact pre-#683 semantics');
    assert(w.attempt683('gb:1').rebind.length === 0 && w.refSha683('wb') === before,
      '#683 N7: the breaker fires ABOVE the rebind — no record appended, the anchored ref is unmoved');
  }

  // -------------------------------------------------------------------------
  // N8 — THE CRASH-RETRY VARIANT (a live bug independent of the sibling-gate scenario). Crash between
  // repair_settled_written and repair_consumed_written, then let the reopened writer do what it was
  // JUST TOLD TO DO — edit its files — and retry. Before the hoist, the digest check fired first and
  // returned candidate_digest_changed, and the attempt was WEDGED FOREVER (settled, unconsumable,
  // fencing every opener). Only a discard unstuck it.
  // -------------------------------------------------------------------------
  {
    const w = drive683();
    const node683 = require(path.join(__dirname, 'kaola-workflow-adaptive-node.js'));
    const realExec = require('child_process').execFileSync;
    const baseOpts = {
      planPath: w.planPath, project: PROJECT_683, nodeId: 'wa', attemptId: 'ga:1', repoRoot: w.repoRoot,
      shell: (p, a) => { try { const s = realExec('node', [p, ...a], { cwd: w.repoRoot, encoding: 'utf8' }); return { ...JSON.parse(s.trim().split('\n').pop()), exitCode: 0 }; } catch (e) { return { exitCode: 1 }; } },
      readFile: p => fs.readFileSync(p, 'utf8'), writeFile: (p, c) => fs.writeFileSync(p, c),
      cacheExists: p => fs.existsSync(p), unlink: p => { try { fs.unlinkSync(p); } catch (_) {} },
      readdir: d => { try { return fs.readdirSync(d); } catch (_) { return []; } },
    };
    let crashed = false;
    try { node683.runRepairNode({ ...baseOpts, reviewFailpoint: 'repair_settled_written' }); }
    catch (err) { crashed = String(err && err.message).includes('review_failpoint:repair_settled_written'); }
    const mid = w.attempt683('ga:1');
    assert(crashed && mid.repair.settled === true && mid.consumed_by === null
      && w.ledger683('wa') === 'in_progress',
      '#683 N8: the crash window is real — repair settled, consumed_by null, writer durably reopened');
    // The reopened writer now edits its declared file, exactly as its brief instructs.
    fs.writeFileSync(path.join(w.repoRoot, 'ax.js'), '// wa is mid-fix when the retry arrives\n');
    const retry = node683.runRepairNode(baseOpts);
    assert(retry.result === 'ok' && retry.resumed === true && retry.consumed_by === 'wa'
      && retry.baselineReused === true,
      '#683 N8: the retry CONSUMES the pending repair — not candidate_digest_changed, not a wedge');
    assert(w.attempt683('ga:1').consumed_by === 'wa',
      '#683 N8: the attempt is durably consumed, so the opener fence can finally lift');

    // N8 variant — the anchored ref was lost/replaced while the writer was reopened. Refuse
    // writer_identity_changed, and prove the documented NON-DISCARD recovery (restore the ref from
    // .cache/barrier-base-<writer>) completes the consume.
    const w2 = drive683();
    const opts2 = { ...baseOpts, planPath: w2.planPath, repoRoot: w2.repoRoot,
      shell: (p, a) => { try { const s = realExec('node', [p, ...a], { cwd: w2.repoRoot, encoding: 'utf8' }); return { ...JSON.parse(s.trim().split('\n').pop()), exitCode: 0 }; } catch (e) { return { exitCode: 1 }; } } };
    try { node683.runRepairNode({ ...opts2, reviewFailpoint: 'repair_settled_written' }); } catch (_) {}
    const savedBase = fs.readFileSync(path.join(w2.cacheDir, 'barrier-base-wa'), 'utf8').trim();
    const ref2 = 'refs/kaola-workflow/barrier/' + PROJECT_683 + '/wa';
    realExec('git', ['-C', w2.repoRoot, 'update-ref', '-d', ref2], { stdio: ['ignore', 'ignore', 'ignore'] });
    const clobbered = node683.runRepairNode(opts2);
    assert(clobbered.result === 'repair_requires_replan' && clobbered.reason === 'writer_identity_changed',
      '#683 N8-variant: a lost/replaced anchored ref refuses writer_identity_changed (a dirty tree cannot be made to look clean)');
    realExec('git', ['-C', w2.repoRoot, 'update-ref', ref2, savedBase], { stdio: ['ignore', 'ignore', 'ignore'] });
    const recovered = node683.runRepairNode(opts2);
    assert(recovered.result === 'ok' && recovered.resumed === true && recovered.consumed_by === 'wa',
      '#683 N8-variant: the ref-restore recovery completes the consume with NO discard and NO re-freeze');
  }

  // -------------------------------------------------------------------------
  // N9 — the three REBIND crash windows. The durable order is journal-first, ref-second,
  // settle-third, precisely so an interrupted rebind is INERT: a record whose ref never moved binds
  // nothing. Every retry converges idempotently, and the ledger is APPEND-ONLY.
  // -------------------------------------------------------------------------
  for (const failpoint of ['rebind_recorded', 'rebind_base_written', 'rebind_settled']) {
    const w = drive683();
    const node683 = require(path.join(__dirname, 'kaola-workflow-adaptive-node.js'));
    const realExec = require('child_process').execFileSync;
    const opts = {
      planPath: w.planPath, project: PROJECT_683, nodeId: 'wa', attemptId: 'ga:1', repoRoot: w.repoRoot,
      shell: (p, a) => { try { const s = realExec('node', [p, ...a], { cwd: w.repoRoot, encoding: 'utf8' }); return { ...JSON.parse(s.trim().split('\n').pop()), exitCode: 0 }; } catch (e) { return { exitCode: 1 }; } },
      readFile: p => fs.readFileSync(p, 'utf8'), writeFile: (p, c) => fs.writeFileSync(p, c),
      cacheExists: p => fs.existsSync(p), unlink: p => { try { fs.unlinkSync(p); } catch (_) {} },
      readdir: d => { try { return fs.readdirSync(d); } catch (_) { return []; } },
    };
    const baseBefore = w.refSha683('wa');
    let threw = false;
    try { node683.runRepairNode({ ...opts, reviewFailpoint: failpoint }); }
    catch (err) { threw = String(err && err.message).includes('review_failpoint:' + failpoint); }
    assert(threw, '#683 N9[' + failpoint + ']: the failpoint fires');
    const crashRecord = (w.attempt683('ga:1').rebind || [])[0];
    assert(crashRecord && crashRecord.base_before === baseBefore,
      '#683 N9[' + failpoint + ']: the interrupted record is durable and chained to the writer\'s real base');
    if (failpoint === 'rebind_recorded') {
      assert(crashRecord.settled === false && w.refSha683('wa') === baseBefore,
        '#683 N9[rebind_recorded]: the record is INERT — the ref never moved, so it binds nothing');
    }
    const recordedAfter = crashRecord.base_after;
    const retry = node683.runRepairNode(opts);
    assert(retry.result === 'ok' && retry.repaired === 'wa',
      '#683 N9[' + failpoint + ']: the retry converges to a completed repair — no discard');
    const finalRebind = w.attempt683('ga:1').rebind;
    assert(finalRebind.length === 1 && finalRebind[0].settled === true
      && finalRebind[0].base_before === baseBefore && finalRebind[0].base_after === recordedAfter,
      '#683 N9[' + failpoint + ']: APPEND-ONLY — the prior record is completed in place, never rewritten or duplicated');
    assert(w.refSha683('wa') === recordedAfter,
      '#683 N9[' + failpoint + ']: the anchored ref converges to exactly the recorded base_after');
  }

  // N9-diverged — the ref is neither base_before nor base_after of an unsettled record. Fail closed.
  {
    const w = drive683();
    const node683 = require(path.join(__dirname, 'kaola-workflow-adaptive-node.js'));
    const realExec = require('child_process').execFileSync;
    const opts = {
      planPath: w.planPath, project: PROJECT_683, nodeId: 'wa', attemptId: 'ga:1', repoRoot: w.repoRoot,
      shell: (p, a) => ({ exitCode: 0, result: 'ok' }),
      readFile: p => fs.readFileSync(p, 'utf8'), writeFile: (p, c) => fs.writeFileSync(p, c),
      cacheExists: p => fs.existsSync(p), unlink: p => { try { fs.unlinkSync(p); } catch (_) {} },
      readdir: d => { try { return fs.readdirSync(d); } catch (_) { return []; } },
    };
    try { node683.runRepairNode({ ...opts, reviewFailpoint: 'rebind_recorded' }); } catch (_) {}
    const strayRef = String(realExec('git', ['-C', w.repoRoot, 'rev-parse', 'HEAD'], { encoding: 'utf8' })).trim();
    realExec('git', ['-C', w.repoRoot, 'update-ref', 'refs/kaola-workflow/barrier/' + PROJECT_683 + '/wa', strayRef],
      { stdio: ['ignore', 'ignore', 'ignore'] });
    const out = node683.runRepairNode(opts);
    assert(out.result === 'repair_requires_replan' && out.reason === 'rebind_replay_diverged',
      '#683 N9-diverged: an anchored ref matching NEITHER recorded base fails closed with rebind_replay_diverged');
  }

  // -------------------------------------------------------------------------
  // N11 — THE SILENT-WAIVER HOLE the review caught: a partition-2 path whose CURRENT content equals the
  // REPAIRING WRITER'S BASELINE while differing from the REVIEWED CANDIDATE. Here gb PASSES (approving
  // bx.js@v1) and bx.js is then DELETED out of band. Because wa's baseline predates wb's write, bx.js is
  // absent from BOTH wa's baseline and the current tree — so it never enters the writer's barrier diff
  // (`foreign`), it is not in wa's slice (P2 blind), and it IS declared (P1 blind). Examining only
  // `foreign` therefore admits the rebind VACUOUSLY with `absorbed: []`, binding the attempt to a mutated
  // candidate in which a gate-APPROVED file has been destroyed and will never be re-reviewed. Partition 2
  // must be measured against the CANDIDATE, not against the writer's baseline.
  // -------------------------------------------------------------------------
  {
    const w = drive683({ gbPass: true });
    assert(w.cgb.result === 'ok' && w.ledger683('gb') === 'complete',
      '#683 N11: gb settles PASS — bx.js@v1 is gate-APPROVED work with no blocker of its own');
    fs.unlinkSync(path.join(w.repoRoot, 'bx.js'));   // out-of-band destruction of the approved file
    const before = w.refSha683('wa');
    const r = w.R(['repair-node', '--attempt-id', 'ga:1', '--node-id', 'wa', ...w.P]);
    assert(r.result === 'repair_requires_replan' && r.reason === 'candidate_delta_unattributed'
      && JSON.stringify(r.paths) === JSON.stringify(['bx.js']),
      '#683 N11: a sibling\'s APPROVED declared path reverted/deleted to the writer\'s baseline content is '
      + 'still examined — candidate_delta_unattributed, NOT a vacuous pass');
    assert(w.attempt683('ga:1').rebind.length === 0 && w.refSha683('wa') === before,
      '#683 N11: zero durable mutation — no rebind record appended, the anchored ref is unmoved');
    assert(fs.existsSync(path.join(w.repoRoot, 'bx.js')) === false && w.ledger683('wa') === 'complete',
      '#683 N11: the refusal is fail-CLOSED — the writer is NOT reopened, so the destroyed file cannot land unreviewed');
  }

  // -------------------------------------------------------------------------
  // N12/N13 — THE MEASURING STICK MUST BE EXACTLY AS STRONG AS THE DIGEST. The digest, the residue digest,
  // P5 and the barrier all treat (mode, sha) as tree identity; a sha-ONLY declared map is strictly weaker
  // on the MODE axis, so a mode-only out-of-band revert of a sibling's gate-APPROVED change lands in NO
  // partition: rebindNeeded fires (the digest sees the mode), P1 passes (the path is declared), P2 passes
  // (not the writer's slice), `foreign` omits it (mode+sha equal the writer's baseline), and a sha-only
  // candidateDelta omits it too. Vacuous pass, `absorbed: []` — the N11 signature on a second axis.
  //
  // The mode axis is NOT just the exec bit: git records the exec bit, the symlink flag AND the gitlink
  // flag in the mode alone, and a symlink's blob IS its target path bytes — so a regular file whose
  // content is "bx-target.js" and a symlink to bx-target.js are the SAME BLOB SHA and differ ONLY in mode
  // (100644 vs 120000). A sha-only stick cannot tell a file from a symlink even in principle.
  // -------------------------------------------------------------------------
  {
    // N12 — wb's ENTIRE approved change is `chmod +x bx.js` (content byte-identical). gb PASSES, so
    // bx.js@100755 is gate-approved work. Then the mode is reverted out-of-band to wa's baseline.
    const w = drive683({
      gbPass: true,
      seedFiles: { 'bx.js': '// bx approved v1\n' },              // 100644 in BOTH writers' baselines
      wbFiles: {},                                                 // no content write at all...
      legEdits: { wb: leg => fs.chmodSync(path.join(leg, 'bx.js'), 0o755) },   // ...only the mode moves
    });
    const modeOf = p => {
      const line = String(execFileSync('git', ['-C', w.repoRoot, 'ls-files', '-s', '--', p], { encoding: 'utf8' })).trim();
      return line ? line.split(/\s+/)[0] : null;
    };
    assert(w.closeWb.result === 'ok' && w.cgb.result === 'ok' && w.ledger683('gb') === 'complete'
      && modeOf('bx.js') === '100755',
      '#683 N12: wb\'s mode-only change merges and gb settles PASS — bx.js@100755 is gate-APPROVED work');

    fs.chmodSync(path.join(w.repoRoot, 'bx.js'), 0o644);   // out-of-band revert of the APPROVED chmod
    const before = w.refSha683('wa');
    const r = w.R(['repair-node', '--attempt-id', 'ga:1', '--node-id', 'wa', ...w.P]);
    assert(r.result === 'repair_requires_replan' && r.reason === 'candidate_delta_unattributed'
      && JSON.stringify(r.paths) === JSON.stringify(['bx.js']),
      '#683 N12: a MODE-ONLY out-of-band revert of a sibling\'s approved chmod is a partition-2 delta — '
      + 'candidate_delta_unattributed, NOT a vacuous pass (the declared map must carry the mode, not just the sha)');
    assert(w.attempt683('ga:1').rebind.length === 0 && w.refSha683('wa') === before
      && w.ledger683('wa') === 'complete',
      '#683 N12: zero durable mutation — no rebind record, the anchored ref is unmoved, the writer is NOT reopened');
  }
  {
    // N13 — the same axis, but the sha COLLIDES ACROSS the mode boundary: wb's approved change swaps the
    // regular file bx.js for a SYMLINK whose target bytes are byte-identical to the file's old content.
    // Same blob sha, same ls-tree TYPE (`blob`); ONLY the mode moves (100644 -> 120000). Reverting it
    // out-of-band restores a plain file that no sha-based comparator can distinguish from the symlink.
    const w = drive683({
      gbPass: true,
      seedFiles: { 'bx.js': 'bx-target.js', 'bx-target.js': '// the symlink target (residue)\n' },
      wbFiles: {},
      legEdits: { wb: leg => { fs.unlinkSync(path.join(leg, 'bx.js')); fs.symlinkSync('bx-target.js', path.join(leg, 'bx.js')); } },
    });
    const entry = p => String(execFileSync('git', ['-C', w.repoRoot, 'ls-files', '-s', '--', p], { encoding: 'utf8' }))
      .trim().split(/\s+/);
    const approved = entry('bx.js');
    assert(w.cgb.result === 'ok' && w.ledger683('gb') === 'complete' && approved[0] === '120000',
      '#683 N13: wb\'s file->symlink swap merges and gb settles PASS — bx.js@120000 is gate-APPROVED work');

    fs.unlinkSync(path.join(w.repoRoot, 'bx.js'));                                  // out-of-band revert
    fs.writeFileSync(path.join(w.repoRoot, 'bx.js'), 'bx-target.js');               // back to a plain file
    // Read the WORKING TREE (what the candidate snapshot's `add -A` actually hashes), not the index.
    const revertedSha = String(execFileSync('git', ['-C', w.repoRoot, 'hash-object', '--', 'bx.js'], { encoding: 'utf8' })).trim();
    assert(fs.lstatSync(path.join(w.repoRoot, 'bx.js')).isSymbolicLink() === false
      && revertedSha === approved[1],
      '#683 N13: the revert is INVISIBLE to any sha-only stick — the plain file carries the symlink\'s EXACT '
      + 'blob sha; only the mode (120000 -> 100644) witnesses it');

    const before = w.refSha683('wa');
    const r = w.R(['repair-node', '--attempt-id', 'ga:1', '--node-id', 'wa', ...w.P]);
    assert(r.result === 'repair_requires_replan' && r.reason === 'candidate_delta_unattributed'
      && JSON.stringify(r.paths) === JSON.stringify(['bx.js']),
      '#683 N13: a symlink->file revert at a CONSTANT blob sha is still a partition-2 delta — '
      + 'candidate_delta_unattributed (the mode is the only witness, and the stick must carry it)');
    assert(w.attempt683('ga:1').rebind.length === 0 && w.refSha683('wa') === before
      && w.ledger683('wa') === 'complete',
      '#683 N13: zero durable mutation — no rebind record, the anchored ref is unmoved, the writer is NOT reopened');
  }

  // -------------------------------------------------------------------------
  // N14 — THE SAME CLASS ONE LEVEL DOWN: the stick's KEY SPACE, not its values. The declared map is a JS
  // object keyed by repo-relative path, and for the path `__proto__` a plain-object map is not merely weak
  // — it is BLIND. `declared['__proto__'] = '<mode> <sha>'` hits Object.prototype's __proto__ SETTER, which
  // ignores a string: no own key is created, Object.keys omits it, and it is journalled as if the file did
  // not exist. It is not in the residue either (the union matched, so the residue branch was skipped), so
  // the path sits in NO partition; P2/P3 then read the __proto__ GETTER on both sides, get Object.prototype
  // both times, and conclude "unchanged". The whole-tree digest hashes its ls-tree line as usual, so
  // rebindNeeded fires while the proof waives the path — the R1/R3 signature exactly, and one that survives
  // BOTH of those fixes because the candidate-anchored delta and the mode-aware values are read through the
  // very key that was dropped. The planner grammar admits the token (no backslash, no glob, not
  // directory-shaped), so this is reachable, not theoretical. A null-prototype map makes the key an ordinary
  // own property that round-trips through JSON and compares like any other path.
  // -------------------------------------------------------------------------
  {
    // The trap is sharp enough to disable this very fixture: `{ '__proto__': body }` in an OBJECT LITERAL
    // is the prototype-setter form, and with a string value it is a silent no-op — Object.entries() would
    // hand back NOTHING and the file would never be written. Build the fixture maps null-prototype too,
    // which is exactly the remedy the production map needs.
    const fileMap = body => { const m = Object.create(null); m['__proto__'] = body; return m; };
    const V0 = '// proto v0 (both writers\' baseline)\n';
    const V1 = '// proto v1 (approved by gb)\n';
    assert(Object.keys(fileMap(V0)).length === 1,
      '#683 N14: the fixture itself must not fall into the __proto__ trap it is probing');
    const w = drive683({
      gbPass: true,
      wbSet: '__proto__',                                       // wb's declared write set IS the magic name
      seedFiles: fileMap(V0),
      wbFiles: fileMap(V1),
    });
    assert(w.cgb.result === 'ok' && w.ledger683('gb') === 'complete',
      '#683 N14: gb settles PASS — __proto__@v1 is gate-APPROVED work with no blocker of its own');
    assert(Object.prototype.hasOwnProperty.call(w.attempt683('ga:1').candidate_declared, '__proto__'),
      '#683 N14: the candidate\'s declared map RECORDS the path `__proto__` as an own key — a plain-object '
      + 'map silently drops it and journals a candidate that omits a file the digest hashed');

    // Revert the APPROVED file to the seed content: byte-identical to wa's baseline, so it never enters
    // the writer's barrier diff (`foreign`) — the candidate-anchored delta is the ONLY thing that can see it.
    fs.writeFileSync(path.join(w.repoRoot, '__proto__'), V0);
    const before = w.refSha683('wa');
    const r = w.R(['repair-node', '--attempt-id', 'ga:1', '--node-id', 'wa', ...w.P]);
    assert(r.result === 'repair_requires_replan' && r.reason === 'candidate_delta_unattributed'
      && JSON.stringify(r.paths) === JSON.stringify(['__proto__']),
      '#683 N14: an out-of-band revert of a gate-APPROVED file named `__proto__` is a partition-2 delta like '
      + 'any other — candidate_delta_unattributed, NOT a vacuous pass through a poisoned map key');
    assert(w.attempt683('ga:1').rebind.length === 0 && w.refSha683('wa') === before
      && w.ledger683('wa') === 'complete',
      '#683 N14: zero durable mutation — no rebind record, the anchored ref is unmoved, the writer is NOT reopened');
  }

  for (const r of repos683) { try { fs.rmSync(r, { recursive: true, force: true }); } catch (_) {} }
}

// ===========================================================================
// #684 — mutation-kill regression coverage for the fail-closed paths #684's audit found reachable
// only through pure-helper unit calls (or not at all), never through the real subcommand. The
// open-next/open-ready review-journal FENCE (adaptive-node.js:3072/6132, `journalFence`) is already
// driven through the real CLI by #683's RED-A assertion (test-adaptive-node.js's `#683 RED-A` block,
// looping `orient`/`open-next`/`open-ready`) — mutation-verified below by disablement, not duplicated.
// Everything else here is new: `candidate_digest_changed` (narrowed post-#683 to the fail-closed
// RESIDUAL of the rebind proof — real production computeReviewCandidateDigest never returns a value
// that engages it; only the injectable legacy-string test seam can), the unique-maximal-producer
// `repair_requires_replan` (no `reason` key), `writer_identity_changed` (compared against
// `effectiveProducerBinding`), the missing-journal compliance/failed-attempt witness detector
// (readReviewJournal:2286-2288), and the #664 fold proven reachable through a REAL frozen plan + REAL
// journal (not the unfrozen `makePlan()` shortcut the original #664 fixture used, which #684's audit
// found skips the entire journal-gated preamble — a shape a real planner freeze can never produce).
// ===========================================================================

// N684-1 — candidate_digest_changed: proveRebindAdmissible's fail-closed RESIDUAL fires when the
// repair-time candidate carries no partition data (the injectable computeReviewCandidateDigest seam
// returns a bare STRING, exactly what the ~15 pre-existing direct-call fixtures rely on) AND the
// digest differs from what was recorded at review time — real production digests always carry
// {digest, declared, residue_digest} and can never engage this branch (see the code comment at
// proveRebindAdmissible's first guard), so this residual is pinned directly via the seam.
{
  const tmp = fs.mkdtempSync(path.join(os.tmpdir(), 'kw-684-digest-changed-'));
  try {
    const projectDir = path.join(tmp, 'kaola-workflow', 'issue-684a');
    const cacheDir = path.join(projectDir, '.cache');
    fs.mkdirSync(cacheDir, { recursive: true });
    const body = makePlan(['| writer | complete | |', '| review | in_progress | |', '| done | pending | |'], [
      '| writer | tdd-guide | — | scripts/w684a.js | 1 | sequence |',
      '| review | code-reviewer | writer | — | 1 | sequence |',
      '| done | finalize | review | CHANGELOG.md | 1 | sequence |',
    ]);
    const hash = planValidator.computePlanHash(body);
    const planPath = path.join(projectDir, 'workflow-plan.md');
    fs.writeFileSync(planPath, '<!-- plan_hash: ' + hash + ' -->\n' + body);
    const writerBaseline = 'w'.repeat(40);
    const identity = { baseline: writerBaseline, anchored_ref: writerBaseline,
      open_token: 'writer-open-token', generation: writerBaseline.slice(0, 12),
      ref: 'refs/kaola-workflow/barrier/issue-684a/writer' };
    fs.writeFileSync(path.join(cacheDir, 'barrier-base-writer'), writerBaseline + '\n');
    fs.writeFileSync(path.join(cacheDir, 'barrier-base-review'), 'r'.repeat(40) + '\n');
    fs.writeFileSync(path.join(cacheDir, 'review.md'),
      'evidence-binding: review ' + 'r'.repeat(12) + '\nverdict: fail\nfindings_blocking: 1\n');
    const common = { planPath, project: 'issue-684a',
      shell: () => ({ exitCode: 0, result: 'ok', ok: true, overallOk: true,
        selectorCheck: { isSelector: false, ok: true } }),
      readFile: p => fs.readFileSync(p, 'utf8'), writeFile: (p, c) => fs.writeFileSync(p, c),
      cacheExists: p => fs.existsSync(p), unlink: p => fs.unlinkSync(p), readdir: d => fs.readdirSync(d),
      captureWriterBarrierIdentity: () => identity };
    const closed = runCloseNode({ ...common, nodeId: 'review', computeReviewCandidateDigest: () => 'a'.repeat(64) });
    assert(closed.result === 'review_failed', 'N684-1: setup — review settles fail, got ' + JSON.stringify(closed));
    const repaired = runRepairNode({ ...common, nodeId: 'writer', attemptId: closed.attempt_id,
      computeReviewCandidateDigest: () => 'b'.repeat(64) });
    assert(repaired.result === 'repair_requires_replan' && repaired.reason === 'candidate_digest_changed',
      'N684-1: a repair-time candidate whose seam carries no partition data (bare string, differing from '
      + 'the recorded digest) refuses the fail-closed residual candidate_digest_changed, got ' + JSON.stringify(repaired));
  } finally { fs.rmSync(tmp, { recursive: true, force: true }); }
}

// N684-2 — repair-node's unique-maximal-producer refusal carries NO `reason` key (only `attempt_id` +
// `producer_slice`): two independent writers with no dependency between them feed one shared gate, so
// neither is its unique maximal producer and repairing through EITHER alone is refused.
{
  const tmp = fs.mkdtempSync(path.join(os.tmpdir(), 'kw-684-nonmax-producer-'));
  try {
    const projectDir = path.join(tmp, 'kaola-workflow', 'issue-684b');
    const cacheDir = path.join(projectDir, '.cache');
    fs.mkdirSync(cacheDir, { recursive: true });
    const body = makePlan([
      '| wa | complete | |', '| wb | complete | |', '| review | in_progress | |', '| done | pending | |',
    ], [
      '| wa | tdd-guide | — | scripts/wa684.js | 1 | sequence |',
      '| wb | tdd-guide | — | scripts/wb684.js | 1 | sequence |',
      '| review | code-reviewer | wa, wb | — | 1 | sequence |',
      '| done | finalize | review | CHANGELOG.md | 1 | sequence |',
    ]);
    const hash = planValidator.computePlanHash(body);
    const planPath = path.join(projectDir, 'workflow-plan.md');
    fs.writeFileSync(planPath, '<!-- plan_hash: ' + hash + ' -->\n' + body);
    fs.writeFileSync(path.join(cacheDir, 'barrier-base-wa'), 'a'.repeat(40) + '\n');
    fs.writeFileSync(path.join(cacheDir, 'barrier-base-wb'), 'b'.repeat(40) + '\n');
    fs.writeFileSync(path.join(cacheDir, 'barrier-base-review'), 'r'.repeat(40) + '\n');
    fs.writeFileSync(path.join(cacheDir, 'review.md'),
      'evidence-binding: review ' + 'r'.repeat(12) + '\nverdict: fail\nfindings_blocking: 1\n');
    const identityWa = { baseline: 'a'.repeat(40), anchored_ref: 'a'.repeat(40),
      open_token: 'open-wa', generation: 'a'.repeat(12), ref: 'refs/kaola-workflow/barrier/issue-684b/wa' };
    const identityWb = { baseline: 'b'.repeat(40), anchored_ref: 'b'.repeat(40),
      open_token: 'open-wb', generation: 'b'.repeat(12), ref: 'refs/kaola-workflow/barrier/issue-684b/wb' };
    const common = { planPath, project: 'issue-684b',
      shell: () => ({ exitCode: 0, result: 'ok', ok: true, overallOk: true,
        selectorCheck: { isSelector: false, ok: true } }),
      readFile: p => fs.readFileSync(p, 'utf8'), writeFile: (p, c) => fs.writeFileSync(p, c),
      cacheExists: p => fs.existsSync(p), unlink: p => fs.unlinkSync(p), readdir: d => fs.readdirSync(d),
      computeReviewCandidateDigest: () => 'c'.repeat(64),
      captureWriterBarrierIdentity: id => ({ wa: identityWa, wb: identityWb }[id] || null) };
    const closed = runCloseNode({ ...common, nodeId: 'review' });
    const journalPath = path.join(cacheDir, 'review-attempts.json');
    const journal684b = JSON.parse(fs.readFileSync(journalPath, 'utf8'));
    const attempt684b = journal684b.attempts[0];
    assert(closed.result === 'review_failed' && attempt684b
      && JSON.stringify(Object.keys(attempt684b.producer_bindings).sort()) === JSON.stringify(['wa', 'wb']),
      'N684-2: setup — review settles fail and binds BOTH independent producers wa+wb, got '
      + JSON.stringify({ closed, attempt684b }));
    const repaired = runRepairNode({ ...common, nodeId: 'wa', attemptId: attempt684b.attempt_id });
    assert(repaired.result === 'repair_requires_replan' && !('reason' in repaired)
      && JSON.stringify((repaired.producer_slice || []).slice().sort()) === JSON.stringify(['wa', 'wb']),
      'N684-2: repairing through wa alone refuses repair_requires_replan with NO reason key — wb is a '
      + 'second producer that is not an ancestor of wa, so wa is not the unique maximal producer, got '
      + JSON.stringify(repaired));
  } finally { fs.rmSync(tmp, { recursive: true, force: true }); }
}

