// ===========================================================================
// N684-5 — the #664 fold END-TO-END through a REAL frozen plan + REAL review journal, not the
// unfrozen makePlan() shortcut the ORIGINAL #664 fixture above uses (which reaches runRepairNode with
// hasReviewJournal===false and skips the ENTIRE journal-gated preamble — a shape a real planner
// freeze can never produce, per #684's audit). Drives close-node for a REAL adversarial-verifier
// fanout(red-team) PASS group, then a REAL code-reviewer FAIL, then repair-node with the settled
// failed attempt's real attempt_id — --attempt-id/the unique-maximal proof/the digest check/the
// writer-identity check/the commit-node barrier re-verify shell-out ALL engage — asserting the exact
// #664 fold outcome (post-dominating gates folded, receipts purged with dedupe honored, singleton
// reviewer evidence retained, the attempt durably consumed).
// ===========================================================================
{
  const tmp = fs.mkdtempSync(path.join(os.tmpdir(), 'kw-684-fold-e2e-'));
  try {
    const projectDir = path.join(tmp, 'kaola-workflow', 'issue-684f');
    const cacheDir = path.join(projectDir, '.cache');
    fs.mkdirSync(cacheDir, { recursive: true });
    const body = makePlan([
      '| impl | complete | |', '| av-a | in_progress | |', '| av-b | in_progress | |',
      '| review | pending | |', '| finalize | pending | |',
    ], [
      '| impl | tdd-guide | — | scripts/impl684f.js | 1 | sequence |',
      '| av-a | adversarial-verifier | impl | — | 1 | fanout(red-team) |',
      '| av-b | adversarial-verifier | impl | — | 1 | fanout(red-team) |',
      '| review | code-reviewer | av-a, av-b | — | 1 | sequence |',
      '| finalize | finalize | review | CHANGELOG.md | 1 | sequence |',
    ]);
    const hash = planValidator.computePlanHash(body);
    const planPath = path.join(projectDir, 'workflow-plan.md');
    fs.writeFileSync(planPath, '<!-- plan_hash: ' + hash + ' -->\n' + body);
    const writerIdentity = { baseline: 'i'.repeat(40), anchored_ref: 'i'.repeat(40),
      open_token: 'open-impl684f', generation: 'i'.repeat(12),
      ref: 'refs/kaola-workflow/barrier/issue-684f/impl' };
    fs.writeFileSync(path.join(cacheDir, 'barrier-base-impl'), 'i'.repeat(40) + '\n');
    fs.writeFileSync(path.join(cacheDir, 'barrier-base-av-a'), 'a'.repeat(40) + '\n');
    fs.writeFileSync(path.join(cacheDir, 'barrier-base-av-b'), 'b'.repeat(40) + '\n');
    fs.writeFileSync(path.join(cacheDir, 'av-a.md'),
      'evidence-binding: av-a ' + 'a'.repeat(12) + '\nverdict: pass\nfindings_blocking: 0\n');
    fs.writeFileSync(path.join(cacheDir, 'av-b.md'),
      'evidence-binding: av-b ' + 'b'.repeat(12) + '\nverdict: pass\nfindings_blocking: 0\n');
    fs.writeFileSync(path.join(cacheDir, 'running-set.json'), JSON.stringify({ state: 'open', nodes: [
      { id: 'av-a', role: 'adversarial-verifier', kind: 'read' },
      { id: 'av-b', role: 'adversarial-verifier', kind: 'read' },
    ] }, null, 2));
    const common = { planPath, project: 'issue-684f',
      shell: () => ({ exitCode: 0, result: 'ok', ok: true, overallOk: true,
        selectorCheck: { isSelector: false, ok: true } }),
      readFile: p => fs.readFileSync(p, 'utf8'), writeFile: (p, c) => fs.writeFileSync(p, c),
      cacheExists: p => fs.existsSync(p), unlink: p => fs.unlinkSync(p), readdir: d => fs.readdirSync(d),
      computeReviewCandidateDigest: () => 'f'.repeat(64),
      captureWriterBarrierIdentity: id => id === 'impl' ? writerIdentity : null };

    // The fanout group PASSES on round 1 — av-a votes provisionally, av-b (last) certifies the group.
    const closeA = runCloseNode({ ...common, nodeId: 'av-a' });
    assert(closeA.result === 'ok' && closeA.provisional === true,
      'N684-5: setup — av-a (non-last fanout member) closes provisionally, got ' + JSON.stringify(closeA));
    const closeB = runCloseNode({ ...common, nodeId: 'av-b' });
    assert(closeB.result === 'ok' && !closeB.provisional,
      'N684-5: setup — av-b (last fanout member) certifies the group PASS, got ' + JSON.stringify(closeB));
    let plan = fs.readFileSync(planPath, 'utf8');
    const statusesAfterFanout = readLedgerStatuses(plan);
    assert(statusesAfterFanout['av-a'] === 'complete' && statusesAfterFanout['av-b'] === 'complete',
      'N684-5: setup — BOTH fanout members are complete after the group settles PASS, got '
      + JSON.stringify(statusesAfterFanout));

    // review opens (hand-advanced — the fold under test is repair-node's, not the scheduler's) and
    // settles FAIL.
    const opened = spliceLedgerNode(plan, 'review', 'in_progress', { allowFrom: ['pending'] });
    assert(opened.changed, 'N684-5: setup — review transitions to in_progress');
    fs.writeFileSync(planPath, opened.content);
    fs.writeFileSync(path.join(cacheDir, 'barrier-base-review'), 'r'.repeat(40) + '\n');
    fs.writeFileSync(path.join(cacheDir, 'review.md'),
      'evidence-binding: review ' + 'r'.repeat(12) + '\nverdict: fail\nfindings_blocking: 1\n');
    fs.writeFileSync(path.join(cacheDir, 'running-set.json'), JSON.stringify({ state: 'open', nodes: [
      { id: 'review', role: 'code-reviewer', kind: 'read' },
    ] }, null, 2));
    const closeReview = runCloseNode({ ...common, nodeId: 'review' });
    assert(closeReview.result === 'review_failed' && closeReview.lifecycle_settled === true,
      'N684-5: setup — the singleton reviewer settles FAIL with a durable attempt, got ' + JSON.stringify(closeReview));
    plan = fs.readFileSync(planPath, 'utf8');
    assert(readLedgerStatuses(plan).review === 'pending',
      'N684-5: setup — the failed reviewer folds itself back to pending');

    // The real journal-gated repair-node path: --attempt-id required, readReviewJournal, the
    // unique-maximal producer proof, verifyWriterBarrierIdentity, computeReviewCandidateDigest, and
    // the commit-node barrier re-verify shell-out ALL engage (hasReviewJournal === true throughout).
    const repaired = runRepairNode({ ...common, nodeId: 'impl', attemptId: closeReview.attempt_id });
    assert(repaired.result === 'ok' && repaired.baselineReused === true,
      '#664 (real journal): repair-node folds the mixed-shape group through the REAL journal-gated path, '
      + 'got ' + JSON.stringify(repaired));
    assert(repaired.gatesReset.includes('av-a') && repaired.gatesReset.includes('av-b')
      && repaired.gatesReset.includes('review'),
      '#664 (real journal): repair-node folds BOTH the completed fanout group AND the singleton downstream '
      + 'gate, got gatesReset=' + JSON.stringify(repaired.gatesReset));
    assert(JSON.stringify(repaired.evidenceRemoved.slice().sort()) === JSON.stringify(['av-a.md', 'av-b.md']),
      '#664 (real journal): BOTH stale skeptic receipts are purged with dedupe honored (each name exactly '
      + 'once even though the fold loop visits the group via both av-a and av-b), got '
      + JSON.stringify(repaired.evidenceRemoved));
    assert(fs.existsSync(path.join(cacheDir, 'review.md')),
      '#664 (real journal): the singleton reviewer\'s evidence is RETAINED as the repair brief, not purged');
    plan = fs.readFileSync(planPath, 'utf8');
    const finalStatuses = readLedgerStatuses(plan);
    assert(finalStatuses['av-a'] === 'pending' && finalStatuses['av-b'] === 'pending'
      && finalStatuses.review === 'pending' && finalStatuses.impl === 'in_progress',
      '#664 (real journal): av-a/av-b/review reset to pending and impl reopens to in_progress, got '
      + JSON.stringify(finalStatuses));
    const journalAfter = JSON.parse(fs.readFileSync(path.join(cacheDir, 'review-attempts.json'), 'utf8'));
    const settledAttempt = journalAfter.attempts.find(a => a.attempt_id === closeReview.attempt_id);
    assert(settledAttempt && settledAttempt.consumed_by === 'impl' && settledAttempt.repair.settled === true,
      '#664 (real journal): the repaired attempt is durably consumed by the selected writer');
  } finally { fs.rmSync(tmp, { recursive: true, force: true }); }
}

// ===========================================================================
// N684-6 — the PAIRED fixture that gives the JOURNAL-DRIVEN fold site (adaptive-node.js ~:5031-5052)
// its OWN single-mutation killer. In N684-5 that site is MUTUALLY REDUNDANT with the legacy #664
// ledger-fanout site (~:5073-5090): both fold the SAME av-a/av-b group and both purge the SAME two
// receipts, so disabling either alone leaves every N684-5 assertion green. The two sites are NOT
// equivalent, though: only the journal-driven site can attribute a COMPLETED **singleton** gate (a
// code-reviewer, not a fan-out) to this exact candidate+writer via its recorded PASS attempt, and only
// it therefore purges that singleton's stale pass receipt (the `completedJournalGates` purge at :5195,
// whose input set is computed EXCLUSIVELY by :5031-5052). The ledger-fanout site touches only
// adversarial-verifier fan-out receipts, so it can never cover this purge. A sequence-only shape
// isolates it: impl -> g_pass (PASSES, complete) -> g_fail (FAILS, folds) -> finalize. Structural
// post-domination (:5071-5072) still folds BOTH gates back to pending regardless of the journal site,
// so the KILLER lives on the receipt purge, not on gatesReset. Disabling ONLY :5031-5052 empties
// completedJournalGates and g_pass.md survives -> the evidenceRemoved assertion goes RED, with the #664
// fanout fixture and N684-5 untouched (proving the killer is single-site).
// ===========================================================================
{
  const tmp = fs.mkdtempSync(path.join(os.tmpdir(), 'kw-684-6-singleton-'));
  try {
    const projectDir = path.join(tmp, 'kaola-workflow', 'issue-684g');
    const cacheDir = path.join(projectDir, '.cache');
    fs.mkdirSync(cacheDir, { recursive: true });
    const body = makePlan([
      '| impl | complete | |', '| g_pass | in_progress | |',
      '| g_fail | pending | |', '| finalize | pending | |',
    ], [
      '| impl | tdd-guide | — | scripts/impl684g.js | 1 | sequence |',
      '| g_pass | code-reviewer | impl | — | 1 | sequence |',
      '| g_fail | code-reviewer | g_pass | — | 1 | sequence |',
      '| finalize | finalize | g_fail | CHANGELOG.md | 1 | sequence |',
    ]);
    const hash = planValidator.computePlanHash(body);
    const planPath = path.join(projectDir, 'workflow-plan.md');
    fs.writeFileSync(planPath, '<!-- plan_hash: ' + hash + ' -->\n' + body);
    const writerIdentity = { baseline: 'i'.repeat(40), anchored_ref: 'i'.repeat(40),
      open_token: 'open-impl684g', generation: 'i'.repeat(12),
      ref: 'refs/kaola-workflow/barrier/issue-684g/impl' };
    fs.writeFileSync(path.join(cacheDir, 'barrier-base-impl'), 'i'.repeat(40) + '\n');
    fs.writeFileSync(path.join(cacheDir, 'barrier-base-g_pass'), 'p'.repeat(40) + '\n');
    fs.writeFileSync(path.join(cacheDir, 'g_pass.md'),
      'evidence-binding: g_pass ' + 'p'.repeat(12) + '\nverdict: pass\nfindings_blocking: 0\n');
    fs.writeFileSync(path.join(cacheDir, 'running-set.json'), JSON.stringify({ state: 'open', nodes: [
      { id: 'g_pass', role: 'code-reviewer', kind: 'read' },
    ] }, null, 2));
    const common = { planPath, project: 'issue-684g',
      shell: () => ({ exitCode: 0, result: 'ok', ok: true, overallOk: true,
        selectorCheck: { isSelector: false, ok: true } }),
      readFile: p => fs.readFileSync(p, 'utf8'), writeFile: (p, c) => fs.writeFileSync(p, c),
      cacheExists: p => fs.existsSync(p), unlink: p => fs.unlinkSync(p), readdir: d => fs.readdirSync(d),
      computeReviewCandidateDigest: () => 'f'.repeat(64),
      captureWriterBarrierIdentity: id => id === 'impl' ? writerIdentity : null };

    // g_pass — a SINGLETON code-reviewer — PASSES on this candidate, recording a durable PASS attempt
    // bound to impl. This is the receipt only the journal-driven site can attribute + purge.
    const closePass = runCloseNode({ ...common, nodeId: 'g_pass' });
    assert(closePass.result === 'ok' && !closePass.provisional && readLedgerStatuses(fs.readFileSync(planPath, 'utf8')).g_pass === 'complete',
      'N684-6: setup — the singleton g_pass certifies PASS and goes complete, got ' + JSON.stringify(closePass));

    // g_fail opens (hand-advanced) and settles FAIL — the blocker the repair consumes.
    let plan = fs.readFileSync(planPath, 'utf8');
    const opened = spliceLedgerNode(plan, 'g_fail', 'in_progress', { allowFrom: ['pending'] });
    assert(opened.changed, 'N684-6: setup — g_fail transitions to in_progress');
    fs.writeFileSync(planPath, opened.content);
    fs.writeFileSync(path.join(cacheDir, 'barrier-base-g_fail'), 'q'.repeat(40) + '\n');
    fs.writeFileSync(path.join(cacheDir, 'g_fail.md'),
      'evidence-binding: g_fail ' + 'q'.repeat(12) + '\nverdict: fail\nfindings_blocking: 1\n');
    fs.writeFileSync(path.join(cacheDir, 'running-set.json'), JSON.stringify({ state: 'open', nodes: [
      { id: 'g_fail', role: 'code-reviewer', kind: 'read' },
    ] }, null, 2));
    const closeFail = runCloseNode({ ...common, nodeId: 'g_fail' });
    assert(closeFail.result === 'review_failed' && closeFail.lifecycle_settled === true,
      'N684-6: setup — g_fail settles FAIL with a durable attempt, got ' + JSON.stringify(closeFail));

    const repaired = runRepairNode({ ...common, nodeId: 'impl', attemptId: closeFail.attempt_id });
    assert(repaired.result === 'ok' && repaired.baselineReused === true,
      'N684-6: repair-node folds the sequence chain through the REAL journal-gated path, got ' + JSON.stringify(repaired));
    // Structural post-domination folds BOTH gates regardless of the journal site — NOT the killer.
    assert(repaired.gatesReset.includes('g_pass') && repaired.gatesReset.includes('g_fail'),
      'N684-6: both post-dominating gates fold back to pending, got gatesReset=' + JSON.stringify(repaired.gatesReset));
    // THE SINGLE-SITE KILLER: g_pass's stale PASS receipt is purged ONLY via completedJournalGates,
    // whose membership is computed EXCLUSIVELY by the journal-driven fold site (:5031-5052). The
    // ledger-fanout site (:5073-5090) touches no singleton receipt, so this assertion goes RED iff the
    // journal-driven site is disabled — a killer no other fixture supplies.
    assert(repaired.evidenceRemoved.includes('g_pass.md'),
      'N684-6: the stale singleton PASS receipt g_pass.md is purged (journal-driven completedJournalGates '
      + 'site is load-bearing), got evidenceRemoved=' + JSON.stringify(repaired.evidenceRemoved));
    assert(!repaired.evidenceRemoved.includes('g_fail.md') && fs.existsSync(path.join(cacheDir, 'g_fail.md')),
      'N684-6: the failed singleton\'s evidence is RETAINED as the repair brief, not purged');
  } finally { fs.rmSync(tmp, { recursive: true, force: true }); }
}

// ===========================================================================
// #688 — fail-closed hardening of proveRebindAdmissible's ledger-status inputs (items 1+2, low,
// unreachable-today edges surfaced by the #683 adversarial campaign). Direct-call unit assertions,
// exactly as the issue's own acceptance criteria sanction (a synthetic absent-ledger call; an n/a-arm
// construction) — neither shape is reachable through the real repair-node CLI today.
//
// Fixture: one slice node `writer` (the current attempt's own producer, declares a.js) and one
// disjoint owner `other` (declares b.js) whose OWN gate is a DIFFERENT, already-repaired attempt
// (`repair.selected_writer: 'other'`). The candidate delta moves b.js (owned solely by `other`,
// disjoint from the slice) since cand and now disagree on its blob — the ONLY path P3b can ever
// attribute, and exactly the seam #688.1/2 hardens (repairWriters' ledger-status quantifier).
// ===========================================================================
{
  const makeProveCtx = () => ({
    nodes: [
      { id: 'writer', writeSetRaw: 'a.js' },
      { id: 'other', writeSetRaw: 'b.js' },
    ],
    attempt: {
      candidate_residue_digest: 'RESIDUE688',
      producer_bindings: { writer: {} },
      logical_gate: { key: 'gate-writer-688', members: ['writer'] },
      rebind: [],
    },
    attempts: [{
      logical_gate: { key: 'gate-other-688', members: ['other'] },
      repair: { selected_writer: 'other', settled: false },
    }],
    now: { residue_digest: 'RESIDUE688',
      declared: { 'a.js': '100644 ' + 'a'.repeat(40), 'b.js': '100644 ' + 'b'.repeat(40) } },
    cand: { digest: 'X688',
      declared: { 'a.js': '100644 ' + 'a'.repeat(40), 'b.js': '100644 ' + 'c'.repeat(40) } },
    declaredUnion: new Set(['a.js', 'b.js']),
    foreign: [],
    nodeId: 'writer',
    // NOTE: `ledgerStatuses` is deliberately OMITTED here — the synthetic absent-ledger call.
  });

  // #688.1 — a synthetic ABSENT ledger (ctx carries no `ledgerStatuses` key at all): the pre-fix
  // `(ledgerStatuses || {})[m]` fallback degrades every lookup to undefined !== 'complete' -> true,
  // i.e. admit-ALL. Fail-closed posture: an absent ledger must refuse attribution instead.
  {
    const out = proveRebindAdmissible(makeProveCtx());
    assert(out.ok === false && out.reason === 'candidate_delta_unattributed'
      && JSON.stringify(out.paths) === JSON.stringify(['b.js']),
      '#688.1: a synthetic absent ledger (ctx.ledgerStatuses omitted) fails CLOSED — refuses '
      + 'candidate_delta_unattributed on b.js instead of admit-all, got ' + JSON.stringify(out));
  }

  // #688.2 — an n/a-ARM construction: the owner gate's sole member sits at status n/a (a
  // selector-pruned arm that never re-reviews). The pre-fix quantifier `!== 'complete'` treats n/a as
  // "still live", wrongly attributing through it. Restrict to {pending, in_progress}.
  {
    const ctx = makeProveCtx();
    ctx.ledgerStatuses = { other: 'n/a' };
    const out = proveRebindAdmissible(ctx);
    assert(out.ok === false && out.reason === 'candidate_delta_unattributed'
      && JSON.stringify(out.paths) === JSON.stringify(['b.js']),
      '#688.2: an n/a owner-gate member is excluded from the liveness quantifier — refuses '
      + 'candidate_delta_unattributed on b.js, got ' + JSON.stringify(out));
  }

  // Regression controls — a genuinely LIVE owner gate (pending or in_progress) must still attribute
  // the delta via P3b exactly as before (the fix narrows the quantifier, it must not empty it).
  {
    const ctxPending = makeProveCtx();
    ctxPending.ledgerStatuses = { other: 'pending' };
    const outPending = proveRebindAdmissible(ctxPending);
    assert(outPending.ok === true
      && JSON.stringify(outPending.absorbed.map(a => a.path)) === JSON.stringify(['b.js'])
      && JSON.stringify(outPending.attributed_to) === JSON.stringify(['other']),
      '#688: (control) a genuinely pending owner gate still attributes the delta via P3b, got ' + JSON.stringify(outPending));

    const ctxInProgress = makeProveCtx();
    ctxInProgress.ledgerStatuses = { other: 'in_progress' };
    const outInProgress = proveRebindAdmissible(ctxInProgress);
    assert(outInProgress.ok === true && JSON.stringify(outInProgress.attributed_to) === JSON.stringify(['other']),
      '#688: (control) a genuinely in_progress owner gate still attributes the delta via P3b, got ' + JSON.stringify(outInProgress));
  }
}

// ===========================================================================
// #688.4 — isCanonicalBlobMap's enumeration-order check made ORDER-INSENSITIVE. JS forces
// canonical-integer object keys (e.g. "10", "2024") to enumerate FIRST, in numeric order, ahead of
// EVERY string key regardless of insertion order — so a correctly-built declared-path map containing
// a repo-root file literally named a canonical integer can fail the pre-fix native-enumeration-vs-
// lexicographic-sort comparison purely as an artifact of that forced reordering, not a real disorder.
// ===========================================================================
{
  const mode = '100644 ';
  // A string key that sorts (lexicographically, character-by-character) BEFORE the canonical-integer
  // key "10" (".env" starts with '.' = 0x2E, less than '1' = 0x31) — the exact shape the issue names:
  // "a repo-root file named a canonical integer (10, 2024) alongside a string-earlier path".
  const declared = { '.env': mode + 'a'.repeat(40), '10': mode + 'b'.repeat(40) };
  // Sanity: this is precisely the native-order-vs-sorted mismatch the pre-fix check choked on (JS
  // enumerates the integer-like key '10' before the string key '.env' regardless of insertion order).
  assert(JSON.stringify(Object.keys(declared)) !== JSON.stringify(Object.keys(declared).slice().sort()),
    '#688.4 fixture sanity: native enumeration order for {.env, 10} really does diverge from lexicographic sort');
  assert(isCanonicalBlobMap(declared) === true,
    '#688.4: an integer-keyed candidate_declared map ({.env, 10}) must pass isCanonicalBlobMap after the '
    + 'order-insensitive fix, got false');

  // Regression control: a genuinely malformed map (a value that is not a canonical tree-entry string)
  // must still be rejected — the fix removes the enumeration-order dependency, not the shape check.
  assert(isCanonicalBlobMap({ '.env': 'not-a-tree-entry' }) === false,
    '#688.4: (control) a non-canonical value shape is still rejected');
  assert(isCanonicalBlobMap(null) === false && isCanonicalBlobMap([]) === false && isCanonicalBlobMap('x') === false,
    '#688.4: (control) non-object/array/string inputs are still rejected');
}

// ===========================================================================
// #688.3 — a reserved node id (a literal Object.prototype key, e.g. `__proto__`) must REFUSE at
// freeze, not silently poison readLedgerStatuses' plain-object status map (a `{}` literal's
// `out['__proto__'] = status` is a silent setter no-op, never an own property — the row vanishes and
// the run wedges fail-closed). Direct-call against validatePlan (the freeze-time grammar).
// ===========================================================================
{
  const body688c = makePlan(
    ['| impl | pending | |', '| __proto__ | pending | |', '| finalize | pending | |'],
    [
      '| impl | tdd-guide | — | scripts/impl688c.js | 1 | sequence |',
      '| __proto__ | code-reviewer | impl | — | 1 | sequence |',
      '| finalize | finalize | __proto__ | CHANGELOG.md | 1 | sequence |',
    ]);
  const v688c = planValidator.validatePlan(body688c, {});
  assert(v688c.result === 'refuse' && v688c.reason === 'plan_invalid'
    && Array.isArray(v688c.errors) && v688c.errors.some(e => e.includes('__proto__') && e.includes('reserved')),
    '#688.3: a node id literally named `__proto__` refuses in-grammar at freeze (plan_invalid, a '
    + 'reserved-Object.prototype-key error), got ' + JSON.stringify({ result: v688c.result, reason: v688c.reason, errors: v688c.errors }));

  // Regression control: a legitimate node id (not a reserved key) still freezes clean — the fix must
  // not reject ordinary plans.
  const cleanBody688c = makePlan(
    ['| impl | pending | |', '| review | pending | |', '| finalize | pending | |'],
    [
      '| impl | tdd-guide | — | scripts/impl688c-clean.js | 1 | sequence |',
      '| review | code-reviewer | impl | — | 1 | sequence |',
      '| finalize | finalize | review | CHANGELOG.md | 1 | sequence |',
    ]);
  const vClean688c = planValidator.validatePlan(cleanBody688c, {});
  assert(vClean688c.result === 'in-grammar',
    '#688.3: (control) an ordinary node id set still freezes clean, got ' + JSON.stringify({ result: vClean688c.result, errors: vClean688c.errors }));
}

if (failed > 0) {
  console.error('adaptive-node tests FAILED (' + failed + ' failures, ' + passed + ' passed)');
  process.exitCode = 1;
} else {
  console.log('adaptive-node tests passed (' + passed + ' assertions)');
}
